-- Poems batch 383
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('67a1ed1f-0ac2-4b42-adec-634e9c3b4bc7','再和鄧志宏二首  其一','陳淵','宋','宋诗','song-poetry','','[]','石馬祠門餘隻耳，夢魂先過瞿塘水。',96,'全唐诗/poet.song.93000.json','["石馬祠門餘隻耳，夢魂先過瞿塘水。", "人間得喪豈偶然，可笑紛紛夸奪子。", "文章自古多窮人，妙奪造化天應瞋。", "謾言勤苦得富貴，見彈求鴞何日真。", "張羅門巷行人絕，歲晏誰憐生事拙。", "窮通有數勿復言，已辦此心堅似鐵。"]'),
('0e82ecdb-1c79-4783-b72f-e3a2578020d1','再和鄧志宏二首  其二','陳淵','宋','宋诗','song-poetry','','[]','先友遺書猶在耳，念之清淚如鉛水。',96,'全唐诗/poet.song.93000.json','["先友遺書猶在耳，念之清淚如鉛水。", "可憐萬事已忘情，獨嘗託我芝蘭子。", "阿戎文采映前人，脱略不顧妻孥瞋。", "却能飲我瞑眩藥，知我老大言尤真。", "利欲昏人須猛絕，妙年母謂吾謀拙。", "古來解使玉如泥，劍鋩除是錕鋙鐵。"]'),
('26665876-79a1-46a8-b9d3-a72b287e1feb','廖成伯奉議生辰','陳淵','宋','宋诗','song-poetry','','[]','曾聽尊前世綵歌，喜聞烟袖舞婆娑。',64,'全唐诗/poet.song.93000.json','["曾聽尊前世綵歌，喜聞烟袖舞婆娑。", "名駒汗血得夷路，老柏凌霜只舊柯。", "桃李盛時隨地有，芝蘭生處近人多。", "春風二月年年事，莫問靈椿歲幾何。"]'),
('0a3628ea-0f29-4315-ba4b-4fa8ee69dc69','交溪靜安院見許尉題壁次韻','陳淵','宋','宋诗','song-poetry','','[]','柱頤脩劍上凌煙，自古功名亦偶然。',32,'全唐诗/poet.song.93000.json','["柱頤脩劍上凌煙，自古功名亦偶然。", "鐘鼎山林俱不惡，一瓢吾欲盡餘年。"]'),
('1c1803b1-22a4-4b6a-9b46-6e5c06101009','用中示以字瑞既書其事又賦詩一首','陳淵','宋','宋诗','song-poetry','','[]','河圖布畫非人力，鳥跡成文豈偶然。',64,'全唐诗/poet.song.93000.json','["河圖布畫非人力，鳥跡成文豈偶然。", "自昔秘藏神所護，至今陳露墨猶鮮。", "胸襟有道推先覺，斤斧無情肯自全。", "但欲剖心彰景命，爨桐何意擬薰絃。"]'),
('82b7b120-2295-437a-a8a1-bcc77adbccbb','字瑞奇特再用前韻','陳淵','宋','宋诗','song-poetry','','[]','春來無物不爭妍，爨木呈祥孰使然。',64,'全唐诗/poet.song.93000.json','["春來無物不爭妍，爨木呈祥孰使然。", "應爲奇文開奧穾，不隨凢卉競蕃鮮。", "窪隆密向暌中合，點畫仍從毁處全。", "御史說符直可騐，從来謀國直如絃。"]'),
('941c7b5a-75b9-4016-9f38-c463b3ecbdaf','提舉生辰','陳淵','宋','宋诗','song-poetry','','[]','東井遥觀盾日升，南風猶入舜絃鳴。',64,'全唐诗/poet.song.93000.json','["東井遥觀盾日升，南風猶入舜絃鳴。", "鵬程九萬豈終息，椿歲八千方再榮。", "平世功名期鳳鳥，一時文采應長庚。", "浮瓜沉李年年事，稽首弧南一點明。"]'),
('6815b444-1d8d-4088-809b-e5e9dd5d449a','俞憲生辰  其一','陳淵','宋','宋诗','song-poetry','','[]','北固樓前萬頃秋，月明風定大江流。',64,'全唐诗/poet.song.93000.json','["北固樓前萬頃秋，月明風定大江流。", "從来此地多英傑，果有奇才副簡求。", "秀氣一天開夜色，威名千里駕潮頭。", "山川長在人難老，應抱文章入相周。"]'),
('fe653831-735e-46c7-82fc-fad0b7f0aa3e','俞憲生辰  其二','陳淵','宋','宋诗','song-poetry','','[]','淮南持斧功成後，甌粵乘軺喜蹔臨。',64,'全唐诗/poet.song.93000.json','["淮南持斧功成後，甌粵乘軺喜蹔臨。", "使者英標衣蹙繡，近臣新渥帯横金。", "三山氣入中秋好，八郡香焚曉霧深。", "已爲黎元開壽域，可無椿歲慰人心。"]'),
('e0385cbf-61ef-4859-b496-489787726612','耿憲生辰','陳淵','宋','宋诗','song-poetry','','[]','象緯祥光動，門弧瑞氣纒。',72,'全唐诗/poet.song.93000.json','["象緯祥光動，門弧瑞氣纒。", "秋来孤鶴徤，霜近古松堅。", "鄰境豺狼盡，新恩雨露偏。", "軺車猶問俗，寶带獨優賢。", "投筆男兒志，封侯烈士年。", "老成端可恃，終冀勒燕然。"]'),
('e1610873-be18-4cd4-ba1a-e84192965199','鄭漕生辰二首  其一','陳淵','宋','宋诗','song-poetry','','[]','至公無轍迹，萬變歸諸正。',144,'全唐诗/poet.song.93000.json','["至公無轍迹，萬變歸諸正。", "誰云學則然，要在成以性。", "我公鍾間氣，異禀剛且勁。", "一毫不容私，心境自澄映。", "超然是非表，燭物眼常淨。", "還將溟渤量，一了百川競。", "由来仁者壽，茲理天所命。", "欲知椿齡永，視此寛平政。", "桂花弄小春，晚香適再盛。", "年年幾望月，影泛杯中聖。", "尚書心如水，遠裔有餘慶。", "何以繼清風，家聲南北鄭。"]'),
('275ee924-e550-46b3-9f4e-3c4f696fe928','鄭漕生辰二首  其二','陳淵','宋','宋诗','song-poetry','','[]','象緯祥光動，門弧瑞氣盈。',120,'全唐诗/poet.song.93000.json','["象緯祥光動，門弧瑞氣盈。", "小陽春在序，幾望月偏明。", "他日三千牘，清時九萬程。", "名因使粵重，功自滿吳成。", "偉量溟波闊，奇詞錦段呈。", "褒揚看唾玉，輕重倚提衡。", "松柏真難老，芝蘭足後生。", "筍班行趣召，金带已先横。", "內史言何美，尚書心自清。", "祇應南北相，重振舊家聲。"]'),
('0d22c64b-c867-494f-91a9-04f8c4b0bb19','唐大夫生辰','陳淵','宋','宋诗','song-poetry','','[]','氣轉初寒候，祥開既望辰。',96,'全唐诗/poet.song.93000.json','["氣轉初寒候，祥開既望辰。", "應時来鸑鷟，占夢獲麒麟。", "盛德圭無玷，高才竹有筠。", "胸襟藏巨壑，人物妙洪鈞。", "使者光華遠，朝廷寵數新。", "鵬程九萬里，椿幹八千春。", "鼎鼐虚前席，風雲即要津。", "黒頭紆袞繡，天意在斯民。"]'),
('10258924-fe5e-4666-8449-0fb9e54156b0','次韻運使龍圖寵示道中夜行之什','陳淵','宋','宋诗','song-poetry','','[]','畏途千里可宵行，正是鄰邦道路平。',64,'全唐诗/poet.song.93000.json','["畏途千里可宵行，正是鄰邦道路平。", "諭蜀昔傳司馬檄，備吳今罷亞夫營。", "陰雲掃地千林出，曉月凌空萬騎迎。", "緩带驛亭留險語，春雷端使蟄蟲驚。"]'),
('7104c0d5-f3bd-4c49-b9a4-bc24803fec48','次韻子靜','陳淵','宋','宋诗','song-poetry','','[]','淵明束带向督郵，已覺歸思不可留。',64,'全唐诗/poet.song.93000.json','["淵明束带向督郵，已覺歸思不可留。", "紛紛朱墨何時休，豈得置錐無一丘。", "平生涉世如虚舟，明月從人驚暗投。", "胸次已無涇渭流，不應在我緣春秋。"]'),
('2b8b9a57-5854-4cf8-b375-4219429d90ae','黄兵部生辰四首  其一','陳淵','宋','宋诗','song-poetry','','[]','中朝人物競推先，富貴前途看永年。',32,'全唐诗/poet.song.93000.json','["中朝人物競推先，富貴前途看永年。", "九萬里程飛正遠，八千春幹久彌堅。"]'),
('26cb4ff6-c23d-45f7-ae66-f5bf7ba740c9','黄兵部生辰四首  其二','陳淵','宋','宋诗','song-poetry','','[]','南國初持使節回，斑衣仍把錦新裁。',32,'全唐诗/poet.song.93000.json','["南國初持使節回，斑衣仍把錦新裁。", "大椿更向萱堂祝，長到春来共壽杯。"]'),
('313c6d2d-f51b-4090-9d7b-e495a7ab3b5c','黄兵部生辰四首  其三','陳淵','宋','宋诗','song-poetry','','[]','蚤歲飛榮應宿郎，至今鷄舌尚含香。',32,'全唐诗/poet.song.93000.json','["蚤歲飛榮應宿郎，至今鷄舌尚含香。", "未應駟馬誇流俗，只爲慈親樂故鄉。"]'),
('61a21b10-2fc8-4640-a1fd-1eda025d5ce6','黄兵部生辰四首  其四','陳淵','宋','宋诗','song-poetry','','[]','地上泉流府庫充，艱難天與歲時豐。',32,'全唐诗/poet.song.93000.json','["地上泉流府庫充，艱難天與歲時豐。", "他時若論關中漕，合數蕭何第一功。"]'),
('0e485ed4-2657-44e0-bc63-342bd477a913','遯齋有感','陳淵','宋','宋诗','song-poetry','','[]','達士豈嫌祠竈請，虞人安可以旌招。',32,'全唐诗/poet.song.93000.json','["達士豈嫌祠竈請，虞人安可以旌招。", "由来不戀五斗粟，自是叩門勝折腰。"]'),
('f7adad9f-ca64-4394-bbf2-8f9c750dad8b','戲題延平閣上  其一','陳淵','宋','宋诗','song-poetry','','[]','黄昏欲去更凭欄，珍重銀蟾照膽寒。',32,'全唐诗/poet.song.93000.json','["黄昏欲去更凭欄，珍重銀蟾照膽寒。", "可是歌眉能繫别，人間無此好溪山。"]'),
('4c2ccb02-e392-4406-ada1-0397757c82e1','戲題延平閣上  其二','陳淵','宋','宋诗','song-poetry','','[]','西風吹露濕峩冠，迥立三山二水間。',32,'全唐诗/poet.song.93000.json','["西風吹露濕峩冠，迥立三山二水間。", "後夜江樓應殢酒，一鈎殘月與誰看。"]'),
('500c16bc-ffec-45f8-bac5-69da605e0699','謁羅養蒙辱示長篇次韻','陳淵','宋','宋诗','song-poetry','','[]','它時對語聞鶯遷，青秧離離初揷田。',160,'全唐诗/poet.song.93000.json','["它時對語聞鶯遷，青秧離離初揷田。", "重来刈稻歌有年，浪過日月將誰憐。", "故人落筆生雲煙，胸中端有萬斛泉。", "從来經笥謾便便，詩書何如一囊錢。", "有時玉樹臨風前，仰視落日窺層巔。", "已知萬古然不然，得處往往多忘筌。", "正須青綾護醉眠，坐使士類歸埴埏。", "不應直爲蓴鱸還，夜聽秋雨窮遺編。", "我今已辦訪戴船，日欲倚棹寒潭邊。", "要當學海如百川，未信軻死今無傳。"]'),
('657a67a4-be5d-4b55-851e-045acaf6f41a','小詩七首寄養蒙兼呈景駿  其一','陳淵','宋','宋诗','song-poetry','','[]','粥魚齋鼓網蛛窠，古寺長廊客少過。',32,'全唐诗/poet.song.93000.json','["粥魚齋鼓網蛛窠，古寺長廊客少過。", "唯有一溪明月在，夜寒偏向斷垣多。"]'),
('9f38fc9b-5c72-46b0-ad83-8987aa422dd8','小詩七首寄養蒙兼呈景駿  其二','陳淵','宋','宋诗','song-poetry','','[]','斜陽不到竹陰幽，小徑縈紆傍碧流。',32,'全唐诗/poet.song.93000.json','["斜陽不到竹陰幽，小徑縈紆傍碧流。", "行到草深橋斷處，却乘明月泛歸舟。"]'),
('c621ba90-c280-4400-82b1-b4ae9612598d','小詩七首寄養蒙兼呈景駿  其三','陳淵','宋','宋诗','song-poetry','','[]','它時樽酒對春風，夜雨霏霏扺曉鐘。',32,'全唐诗/poet.song.93000.json','["它時樽酒對春風，夜雨霏霏扺曉鐘。", "但說尋常往来地，豈知重到有丹楓。"]'),
('235af4ff-9b06-4d61-b2ae-fe4ec0dfcdc2','小詩七首寄養蒙兼呈景駿  其四','陳淵','宋','宋诗','song-poetry','','[]','太史溪頭十里間，朝陽峰下水涵天。',32,'全唐诗/poet.song.93000.json','["太史溪頭十里間，朝陽峰下水涵天。", "青鞋不踏紅塵陌，夢斷僧窗又一年。"]'),
('3e73355a-a4b0-4963-bca2-f5b98959c7c1','小詩七首寄養蒙兼呈景駿  其五','陳淵','宋','宋诗','song-poetry','','[]','才疏不下孔北海，道廣更師陳太丘。',32,'全唐诗/poet.song.93000.json','["才疏不下孔北海，道廣更師陳太丘。", "世路風波無着處，却尋真隱得清游。"]'),
('6d829add-b1cb-4315-bb08-1c648c70c310','小詩七首寄養蒙兼呈景駿  其六','陳淵','宋','宋诗','song-poetry','','[]','二妙胸中萬頃寛，詩成千字海濤飜。',32,'全唐诗/poet.song.93000.json','["二妙胸中萬頃寛，詩成千字海濤飜。", "已能共入淵騫室，自是同登李杜壇。"]'),
('3ca3895a-b0e7-4f44-af48-d56141587b90','小詩七首寄養蒙兼呈景駿  其七','陳淵','宋','宋诗','song-poetry','','[]','晚交誰似兩龔清，冰雪情懷獨老成。',32,'全唐诗/poet.song.93000.json','["晚交誰似兩龔清，冰雪情懷獨老成。", "揚粃在前容齒長，積薪居上看文鳴。"]'),
('45c2d4cb-5356-4cf6-8774-d7a3fb94cbdc','玩月','陳淵','宋','宋诗','song-poetry','','[]','據牀招佳月，月轉牀屢移。',156,'全唐诗/poet.song.93000.json','["據牀招佳月，月轉牀屢移。", "夜久風露涼，孤斟樂忘歸。", "冰輪擅空闊，是處留清輝。", "浮雲掃除盡，如與賞心期。", "我行萬物表，中空無一疵。", "光明徧十方，毫髪了無遺。", "心境互融澈，起坐迷東西。", "此生看此月，十年悼無時。", "它日客共飲，淋浪酒霑衣。", "十語久不契，此心唯自知。", "西風掃殘暑，秋色日益奇。", "憂國付鼎食，消閑屬山棲。", "恐妨此時樂，勿露囊中錐。"]'),
('b0409608-4aa4-4a10-bdc7-5cec6ee13896','三絕句寄幾先  其一','陳淵','宋','宋诗','song-poetry','','[]','陽明連絡四支中，胃氣由来處處通。',32,'全唐诗/poet.song.93000.json','["陽明連絡四支中，胃氣由来處處通。", "但使黄婆能飽飯，客邪端的不須攻。"]'),
('4052a68c-d30b-47be-8703-48f0326482e8','三絕句寄幾先  其二','陳淵','宋','宋诗','song-poetry','','[]','冷暖平生既自知，是中無病欲誰醫。',32,'全唐诗/poet.song.93000.json','["冷暖平生既自知，是中無病欲誰醫。", "但思寒熱從何得，未用長吟譴鬼詩。"]'),
('abf72416-3756-4d7d-b08b-97bcd11334bc','三絕句寄幾先  其三','陳淵','宋','宋诗','song-poetry','','[]','敵犯東南夜壘驚，却防西北有奇兵。',32,'全唐诗/poet.song.93000.json','["敵犯東南夜壘驚，却防西北有奇兵。", "將軍堅卧鼻雷吼，七國崢嶸次第平。"]'),
('022936d4-af5a-4f3c-ac46-f91a7d19ddfb','道出南浦見蕭子莊十首  其一','陳淵','宋','宋诗','song-poetry','','[]','霧壓山城石徑遥，筍輿乘月度溪橋。',32,'全唐诗/poet.song.93000.json','["霧壓山城石徑遥，筍輿乘月度溪橋。", "已投柳舍人方起，却訪鱣堂市未囂。"]'),
('a9bdf8d8-4349-4364-b2ed-364105550a3b','道出南浦見蕭子莊十首  其二','陳淵','宋','宋诗','song-poetry','','[]','牆仞未容肩可及，豹斑時許管能窺。',32,'全唐诗/poet.song.93000.json','["牆仞未容肩可及，豹斑時許管能窺。", "相逢一笑無餘事，明月滿懷心自知。"]'),
('f94e4c55-cf92-4efe-aa82-76f6439ae258','道出南浦見蕭子莊十首  其三','陳淵','宋','宋诗','song-poetry','','[]','雨絲收盡暮天涼，萬竅號風釀曉霜。',32,'全唐诗/poet.song.93000.json','["雨絲收盡暮天涼，萬竅號風釀曉霜。", "待趁新晴出閩嶺，夜談還喜漏偏長。"]'),
('8bb86939-558a-4e95-a4b0-4c76e7887724','道出南浦見蕭子莊十首  其四','陳淵','宋','宋诗','song-poetry','','[]','平生交契獨公深，歲晚那無裹飯心。',32,'全唐诗/poet.song.93000.json','["平生交契獨公深，歲晚那無裹飯心。", "白首它年林下約，此盟端的幾時尋。"]'),
('cd2ad82e-565a-4547-b2e3-6c88fe2886fe','道出南浦見蕭子莊十首  其五','陳淵','宋','宋诗','song-poetry','','[]','五年重見各蒼顔，往事紛紛醉夢間。',32,'全唐诗/poet.song.93000.json','["五年重見各蒼顔，往事紛紛醉夢間。", "不爲投閑多暇日，豈能千里謁龜山。"]'),
('8900ee5b-3d1c-49e7-8085-e7152dc760b9','道出南浦見蕭子莊十首  其六','陳淵','宋','宋诗','song-poetry','','[]','龜山涉世若虚舟，觸處忘懷得自由。',32,'全唐诗/poet.song.93000.json','["龜山涉世若虚舟，觸處忘懷得自由。", "道大不容長役役，心閑無事只休休。"]'),
('5167856e-9f53-4dfb-adbc-4113a669902e','道出南浦見蕭子莊十首  其七','陳淵','宋','宋诗','song-poetry','','[]','了齋已復歸黄壤，便恐人間此道微。',32,'全唐诗/poet.song.93000.json','["了齋已復歸黄壤，便恐人間此道微。", "後代不知誰得法，祇今無復更傳衣。"]'),
('2c4a1923-5131-4758-b257-bf8c3cc673da','道出南浦見蕭子莊十首  其八','陳淵','宋','宋诗','song-poetry','','[]','四海知心有幾人，淡然今與鬼爲鄰。',32,'全唐诗/poet.song.93000.json','["四海知心有幾人，淡然今與鬼爲鄰。", "天下共寃渠不恨，平生憂國自忘身。"]'),
('65fba4bb-590f-4786-843e-16ae5e111313','道出南浦見蕭子莊十首  其九','陳淵','宋','宋诗','song-poetry','','[]','斯文初不間衡茅，但有玄經豈患嘲。',32,'全唐诗/poet.song.93000.json','["斯文初不間衡茅，但有玄經豈患嘲。", "騏驥從他千里足，鷦鷯容我一枝巢。"]'),
('1c9b810c-7407-4b05-b346-e68628231afe','道出南浦見蕭子莊十首  其一○','陳淵','宋','宋诗','song-poetry','','[]','我在龍潭直下居，西来應不少雙魚。',32,'全唐诗/poet.song.93000.json','["我在龍潭直下居，西来應不少雙魚。", "故人南浦如相憶，爲寄平安尺素書。"]'),
('81d411a9-f484-4fc7-b76f-625f31118fd8','過江郎巖下少駐感而有作','陳淵','宋','宋诗','song-poetry','','[]','三峰卓立蒼崕表，朝夕雲煙自圍繞。',112,'全唐诗/poet.song.93000.json','["三峰卓立蒼崕表，朝夕雲煙自圍繞。", "幾年不向眼中青，忽露全身萬山曉。", "凝然不動亘今昔，陌上行人空自老。", "我生悟此其已久，夢事縈人嗟未了。", "却怪神龍依絕頂，獨以一身蟠故沼。", "風雷際會豈無時，忍視饑氓日紛擾。", "未能呵汝救凶年，明朝馬首霜風早。"]'),
('d81df9ec-11ac-49a5-88b5-d100cf052656','三衢道中感懷寄龐幾先','陳淵','宋','宋诗','song-poetry','','[]','霜風卷地號，達曉不成雨。',204,'全唐诗/poet.song.93000.json','["霜風卷地號，達曉不成雨。", "游雲乍蔽虧，朝日翳復吐。", "衢梁三日行，去往迷處所。", "茅簷得小休，蔬飯不能舉。", "所嗟兵火餘，白骨莾無主。", "鄰邦歲又惡，賈飯逐婺女。", "遏糴彼何忍，楚越視心膂。", "况欲賊取之，不救溝壑苦。", "生逢堯舜代，短袖不容舞。", "空餘衛物心，持此欲誰語。", "故人幕中傑，籌畫多所補。", "朝譽競推先，丘壑終自許。", "平生陳琳檄，解使頭風愈。", "容我七子間，泛愛果輕與。", "此生聽造物，未能狙公芧。", "牧羊或可息，抱關亦易處。", "要以一溉勤，聊潤漢陰圃。"]'),
('7df3e337-9d98-4a75-9a53-d8ad65e5b595','二月五日入都廳久坐候山甫不至廳前桃花一夜風雨落盡感事寫懷','陳淵','宋','宋诗','song-poetry','','[]','簿書堆裏只匆匆，過眼繁紅夜雨中。',32,'全唐诗/poet.song.93000.json','["簿書堆裏只匆匆，過眼繁紅夜雨中。", "可念青春看又老，一杯無計略從容。"]'),
('c05480a3-c4ca-4cec-9144-0e4b3dd97561','曉登嚴陵釣臺和安止所留詩','陳淵','宋','宋诗','song-poetry','','[]','溪山有底好，適契貧士欲。',120,'全唐诗/poet.song.93000.json','["溪山有底好，適契貧士欲。", "敢論生不侯，但喜夢非僕。", "千秋釣臺水，不濯市朝足。", "而我獨何人，得寓塵埃目。", "擕笻縱朝步，初日穿林麓。", "西風扶兩腋，一舉千里鵠。", "東窺夫差國，繁華混真俗。", "濁流駕頽波，一往不可復。", "之子居其間，嗜古追前躅。", "爲寄無絃琴，一和郢中曲。"]'),
('2e2ee0f9-d27e-44cc-9b7f-30baf6ff7a7a','再用前韻','陳淵','宋','宋诗','song-poetry','','[]','人閑得安眠，夢斷了無欲。',120,'全唐诗/poet.song.93000.json','["人閑得安眠，夢斷了無欲。", "那思趨朝士，一馬百夫僕。", "况聞稻苗盛，昨夜新雨足。", "一飽如可期，吾事豈多目。", "盆山鬱葱蒨，酌水周其麓。", "照我本來面，真白非浴鵠。", "故應此間住，却掃便違俗。", "超然寂照中，無往亦非復。", "百年只爾是，行矣毋躑躅。", "區區欲何爲，世路羊腸曲。"]'),
('ec9b0efc-2df1-4ed4-9932-0747be7df32b','過崇仁莫宿山寺書事','陳淵','宋','宋诗','song-poetry','','[]','驛路塗泥一尺深，竹輿高下歷千岑。',32,'全唐诗/poet.song.93000.json','["驛路塗泥一尺深，竹輿高下歷千岑。", "愁霖洗盡梅梢雪，把酒無人慰此心。"]'),
('734e48fe-8f08-46b8-8c80-1b412c8c4191','自梅花村回道中書壁四首  其一','陳淵','宋','宋诗','song-poetry','','[]','刺水秧針出已齊，雨餘膏澤未全犁。',32,'全唐诗/poet.song.93000.json','["刺水秧針出已齊，雨餘膏澤未全犁。", "道傍牛喘無情問，慚愧林間布穀啼。"]'),
('9eb3930e-47a0-470a-9d58-91931d86747f','自梅花村回道中書壁四首  其二','陳淵','宋','宋诗','song-poetry','','[]','綫路縈紆遶亂山，筍輿追逐棘林間。',32,'全唐诗/poet.song.93000.json','["綫路縈紆遶亂山，筍輿追逐棘林間。", "艱難那解蘇疲瘵，自笑奔馳未得閑。"]'),
('6a5220d9-67cd-4069-888d-e6aaf5664d17','自梅花村回道中書壁四首  其三','陳淵','宋','宋诗','song-poetry','','[]','野花無數不知名，映竹臨流若有情。',32,'全唐诗/poet.song.93000.json','["野花無數不知名，映竹臨流若有情。", "掃盡殘紅春去後，亂山深處眼增明。"]'),
('7825cf20-1df5-470b-bcfe-6f10be8bf532','自梅花村回道中書壁四首  其四','陳淵','宋','宋诗','song-poetry','','[]','城郭初看委地紅，川原今見綠蒙茸。',32,'全唐诗/poet.song.93000.json','["城郭初看委地紅，川原今見綠蒙茸。", "驚人節物催華髪，留滯窮山醉夢中。"]'),
('cb4202e8-a039-4c3d-ae24-1effa5847786','邑中諸公見和再用前韻  其一','陳淵','宋','宋诗','song-poetry','','[]','郭外盈疇草又齊，十年猶負带經犂。',32,'全唐诗/poet.song.93000.json','["郭外盈疇草又齊，十年猶負带經犂。", "未應五斗能留我，端爲癡兒索飯啼。"]'),
('8b385c26-8076-40cb-8355-25794f811a3f','邑中諸公見和再用前韻  其二','陳淵','宋','宋诗','song-poetry','','[]','馬上悠悠夢故山，茅齋依舊水雲間。',32,'全唐诗/poet.song.93000.json','["馬上悠悠夢故山，茅齋依舊水雲間。", "長懷竊轡塵沙外，豈願駢頭十二閑。"]'),
('9b17d602-3d6c-4f70-be96-71dc902f4b19','邑中諸公見和再用前韻  其三','陳淵','宋','宋诗','song-poetry','','[]','冷艶幽香不可名，老年春去獨關情。',32,'全唐诗/poet.song.93000.json','["冷艶幽香不可名，老年春去獨關情。", "林深霧暗何由見，賴有薰風爲證明。"]'),
('c0ff99d1-39e1-45f3-9c33-7d35941231e0','邑中諸公見和再用前韻  其四','陳淵','宋','宋诗','song-poetry','','[]','看盡愁人萬點紅，曉来雙鬂白於茸。',32,'全唐诗/poet.song.93000.json','["看盡愁人萬點紅，曉来雙鬂白於茸。", "它時儻記江南夢，畫我黄梅細雨中。"]'),
('9026b705-492a-440c-9e66-9e904f13c1ba','被檄下鄉督税作釋負','陳淵','宋','宋诗','song-poetry','','[]','詔書寛逋負，國用豈云闕。',120,'全唐诗/poet.song.93000.json','["詔書寛逋負，國用豈云闕。", "郡邑有常供，征求安敢輟。", "稽遲推蚤暮，鈎摘劇豪髪。", "饑氓困鞭箠，十室九告竭。", "連雨催早稻，雪穗迷空闊。", "要令公私辦，當復俟旬月。", "平生慮患深，獻玉每遭刖。", "憂民已無策，問俗聊省罰。", "陽城吾所慕，晚官敢求達。", "寧無撫字心，便覺催科拙。"]'),
('c1300c51-504a-4988-8530-cc4d2d464d5c','夏日雨後戲書','陳淵','宋','宋诗','song-poetry','','[]','雷霆挾雨驚殘夢，蕭艾乘風醒宿酲。',32,'全唐诗/poet.song.93000.json','["雷霆挾雨驚殘夢，蕭艾乘風醒宿酲。", "黄檗一杯清晝永，張羅誰復問交情。"]'),
('792294b8-004c-477d-a08e-1def8a821e92','與張司錄','陳淵','宋','宋诗','song-poetry','','[]','沉李浮瓜記昔游，重来氊帽映貂裘。',64,'全唐诗/poet.song.93000.json','["沉李浮瓜記昔游，重来氊帽映貂裘。", "乘風喜見經旬御，泛雪難留半夜舟。", "坐上談機通一馬，筆間詞刃失全牛。", "尊前它日論詩地，柱後微文阻獻酬。"]'),
('bbcfdc59-ef82-4e12-a319-af73d2a3c842','奉和司錄道中二首 山行','陳淵','宋','宋诗','song-poetry','','[]','浪蘂浮花逐去程，流紅應恨水無情。',64,'全唐诗/poet.song.93000.json','["浪蘂浮花逐去程，流紅應恨水無情。", "簷間頗厭催歸語，木杪空憐喚友聲。", "念遠却回鴻陣急，忘貧重到鷰巢成。", "待憑物理追風御，懷抱如今喜盡傾。"]'),
('88ddaf84-3ea7-4fba-b046-d30c032e31a7','奉和司錄道中二首 偶成','陳淵','宋','宋诗','song-poetry','','[]','雲路横翔計似疏，二原清賞更誰如。',64,'全唐诗/poet.song.93000.json','["雲路横翔計似疏，二原清賞更誰如。", "池塘草滿供詩夢，煙雨春来入畫圖。", "落莫早知貧是病，參池今悟直爲迂。", "傍人大笑公焉取，爲說忘機或類吾。"]'),
('c53b0d82-c87c-4b3c-8362-68eedffcbed0','和司錄行縣道中偶風雨有感之作六首  其一','陳淵','宋','宋诗','song-poetry','','[]','葉底鶯初囀，枝頭蝶漸稀。',48,'全唐诗/poet.song.93000.json','["葉底鶯初囀，枝頭蝶漸稀。", "雨餘憐草長，風定恐花飛。", "遲暮歌終寠，淹留嘆式微。", "更堪西去雁，聲逐晚雲歸。"]'),
('9187359a-22f0-4608-a9f1-94bea48f6a0b','和司錄行縣道中偶風雨有感之作六首  其二','陳淵','宋','宋诗','song-poetry','','[]','吏隱聲藏霧，天游更御風。',48,'全唐诗/poet.song.93000.json','["吏隱聲藏霧，天游更御風。", "分攜方舉白，轉盼復堆紅。", "北去豺狼盡，春回雨露同。", "向來相對飲，應復念鄰翁。"]'),
('4c40720b-5938-442a-87c7-012bdf08c61d','和司錄行縣道中偶風雨有感之作六首  其三','陳淵','宋','宋诗','song-poetry','','[]','非關濃艶能傾國，可是幽香解返魂。',32,'全唐诗/poet.song.93000.json','["非關濃艶能傾國，可是幽香解返魂。", "正爾彫零廢吟賞，欲留佳麗度晨昏。"]'),
('a3ac9fe0-14e6-416b-bcb8-9beb917d2efb','和司錄行縣道中偶風雨有感之作六首  其四','陳淵','宋','宋诗','song-poetry','','[]','酴醿卧雨有餘態，芍藥倚風無限情。',32,'全唐诗/poet.song.93000.json','["酴醿卧雨有餘態，芍藥倚風無限情。", "正是江南花欲盡，淡雲来往日微明。"]'),
('0ba2a226-7a89-4bf8-bce8-eded5f8e8bcd','和司錄行縣道中偶風雨有感之作六首  其五','陳淵','宋','宋诗','song-poetry','','[]','山頭漠漠煙藏樹，山下潺潺水滿溪。',32,'全唐诗/poet.song.93000.json','["山頭漠漠煙藏樹，山下潺潺水滿溪。", "全勝長安花柳陌，萬人塵裏逐輪蹄。"]'),
('925e5ff8-f62f-43d1-b618-a01188b4510f','和司錄行縣道中偶風雨有感之作六首  其六','陳淵','宋','宋诗','song-poetry','','[]','江山似爲詩人設，風雨故應春日多。',32,'全唐诗/poet.song.93000.json','["江山似爲詩人設，風雨故應春日多。", "醉裏吟哦聊自適，眼前開落莫誰何。"]'),
('01b02fe1-0abd-4a90-87ef-9cec6a7d9dcf','饒州張宏中挽詞二首  其一','陳淵','宋','宋诗','song-poetry','','[]','壯歲英標冠士林，莫年詩酒任浮沉。',64,'全唐诗/poet.song.93000.json','["壯歲英標冠士林，莫年詩酒任浮沉。", "奇姿不見臨風玉，妙語空傳擲地金。", "殘稾有誰知句眼，斷絃何處覓琴心。", "他時戲笑成陳迹，惆悵江亭十畝陰。"]'),
('8770d189-6e2a-47dd-a1a4-498a6daa582a','饒州張宏中挽詞二首  其二','陳淵','宋','宋诗','song-poetry','','[]','畫棟雕甍照水村，簮裳多在脊令原。',64,'全唐诗/poet.song.93000.json','["畫棟雕甍照水村，簮裳多在脊令原。", "百年得計南山豆，萬事忘懷北海尊。", "自昔功名何世乏，迨今文字幾人存。", "遺書儻有毫芒在，爲語韓公請備論。"]'),
('d74e01a6-a925-417d-b0a8-861e5b68e6b0','次韻李聳卿','陳淵','宋','宋诗','song-poetry','','[]','前輩風流曉露零，忽逢豪士壯心驚。',64,'全唐诗/poet.song.93000.json','["前輩風流曉露零，忽逢豪士壯心驚。", "雷霆落筆千人掃，珠玉成詩萬户輕。", "應許翰林追敏捷，肯容開府鬬新清。", "向来乞米無佳傳，端欲投瓜趣報瓊。"]'),
('44dc8331-50fe-477a-9f1c-ecc8cbf75445','次韻李聳卿賀太守禱雨有應二首  其一','陳淵','宋','宋诗','song-poetry','','[]','一寸丹誠貫上穹，坐令千里走龍工。',64,'全唐诗/poet.song.93000.json','["一寸丹誠貫上穹，坐令千里走龍工。", "驕陽彌目苗將槁，甘雨連霄澤已豐。", "便覺風霜傾意盡，豈愁荆棘致年凶。", "江南歲漕知無闕，遥想中都喜氣同。"]'),
('cb809549-dd9e-4509-be5e-a2b64c45e7a7','次韻李聳卿賀太守禱雨有應二首  其二','陳淵','宋','宋诗','song-poetry','','[]','使君憂國願年豐，肯放炎威久病農。',64,'全唐诗/poet.song.93000.json','["使君憂國願年豐，肯放炎威久病農。", "盡道胸中藏渤澥，誰知筆下起蛟龍。", "曉涼秋氣生蘄簟，夢斷簷聲带梵鐘。", "高卧已傳民訟息，秪應仁政古難逢。"]'),
('fb50b822-f0a5-4712-a873-37787a0cf3d9','歸自郡城見道中山礬盛開','陳淵','宋','宋诗','song-poetry','','[]','梅豆班班已滿枝，暗香猶未吐酴醿。',32,'全唐诗/poet.song.93000.json','["梅豆班班已滿枝，暗香猶未吐酴醿。", "和風煖日江南路，正是山礬爛漫時。"]'),
('9b1dd966-af62-4d61-adce-7aea033cc975','香嚴寺洗足','陳淵','宋','宋诗','song-poetry','','[]','肩輿苦頓撼，步入山間路。',144,'全唐诗/poet.song.93000.json','["肩輿苦頓撼，步入山間路。", "崎嶇歷荆榛，砂礫窘芒屨。", "披雲造蕭寺，弛擔日已暮。", "僧房急解襪，一洗塵泥汙。", "瓦盤深及膝，湯暖得頻注。", "須臾和氣達，凜凜毛髪豎。", "翛然入無何，醉夢寧知處。", "此生事奔走，早晏失期度。", "念茲頃刻閑，百日不一遇。", "啖蔗入佳境，鐘響忽予寤。", "蒲團赴微火，黙坐聊箕踞。", "明朝塵沙黄，莫憶少陵句。"]'),
('475feaa2-7bef-4931-a80b-a63d50f21184','山寺早梅三首  其一','陳淵','宋','宋诗','song-poetry','','[]','竹籬茅舍近前溪，煙淡風微月上遲。',32,'全唐诗/poet.song.93000.json','["竹籬茅舍近前溪，煙淡風微月上遲。", "認得暗香来去處，夜寒無路覓横枝。"]'),
('4dcc4e58-2a07-49b9-bf3c-6a6ec79a99b3','山寺早梅三首  其二','陳淵','宋','宋诗','song-poetry','','[]','冰雪情懷未遽開，芝蘭風味已先回。',32,'全唐诗/poet.song.93000.json','["冰雪情懷未遽開，芝蘭風味已先回。", "故人隔歲無因見，一夜月明何處来。"]'),
('19404ed1-1902-4f9b-9e65-d27de2ece880','山寺早梅三首  其三','陳淵','宋','宋诗','song-poetry','','["\u897f\u6e56"]','丹蕚猶含綽約肌，水邊籬落雪晴時。',32,'全唐诗/poet.song.93000.json','["丹蕚猶含綽約肌，水邊籬落雪晴時。", "此間妙得無言意，只有西湖處士詩。"]'),
('06c5979a-4373-46ba-83ec-9c9eead85247','又題山寺二首  其一','陳淵','宋','宋诗','song-poetry','','[]','雲間初日慘無光，天外歸鴻豈戀行。',32,'全唐诗/poet.song.93000.json','["雲間初日慘無光，天外歸鴻豈戀行。", "短景去人如掣電，不應留滯野梅香。"]'),
('b4ffdf9d-0371-4323-8c11-59003d77a055','又題山寺二首  其二','陳淵','宋','宋诗','song-poetry','','[]','雲母燒香不見煙，夜深齋閣閉龍涎。',32,'全唐诗/poet.song.93000.json','["雲母燒香不見煙，夜深齋閣閉龍涎。", "此生暇日真難得，蕭寺重来已四年。"]'),
('61a01a13-0201-40b2-b891-cb38a402c3f4','即席和焦貫道','陳淵','宋','宋诗','song-poetry','','[]','馬上無端骨肉消，老来功業正寥寥。',32,'全唐诗/poet.song.93000.json','["馬上無端骨肉消，老来功業正寥寥。", "便須舉白追年少，莫恨紅粧不我饒。"]'),
('e52fbb44-a202-48ec-ae40-90d7202de2fc','趙元述慶得子次韻','陳淵','宋','宋诗','song-poetry','','[]','貧家豈有石麒麟，說夢哦詩愧杜陵。',32,'全唐诗/poet.song.93000.json','["貧家豈有石麒麟，說夢哦詩愧杜陵。", "但得過庭追孔鯉，不愁傳鉢欠盧能。"]'),
('d63c157b-9caa-43b7-8266-3cdd98fe3413','和周唐獻郎中登普光寺閣','陳淵','宋','宋诗','song-poetry','','[]','官閑竟日身無事，雨過連巒氣似熏。',64,'全唐诗/poet.song.93000.json','["官閑竟日身無事，雨過連巒氣似熏。", "未暇含香朝瑣闥，且乘飛舄躡青雲。", "九天已振摶風翼，萬目難藏隱霧文。", "誰凭危欄親王唾，笑談應復許隨羣。"]'),
('7cce530c-bf48-4f09-8872-783a8c1c1ab3','寄曹載德諫議二首  其一','陳淵','宋','宋诗','song-poetry','','[]','不將塵土嘆徒勞，白首驅馳任所遭。',64,'全唐诗/poet.song.93000.json','["不將塵土嘆徒勞，白首驅馳任所遭。", "鸞鳳尚能安枳棘，鷽鳩何敢厭蓬蒿。", "論材競欲推嚢穎，備物何由數澗毛。", "末路固窮真自許，未應延頸試鳴號。"]'),
('e5e3c5b4-89a0-4db7-a5cc-5a143d33f9c1','寄曹載德諫議二首  其二','陳淵','宋','宋诗','song-poetry','','[]','晚途無復計行藏，捶楚塵埃秪自傷。',64,'全唐诗/poet.song.93000.json','["晚途無復計行藏，捶楚塵埃秪自傷。", "未即賣刀歸買犢，自憐挾策亦亡羊。", "已無竿牘勤毛穎，肯爲簞瓢念孔方。", "尤喜故人書斷絕，不將栖棘戲仇香。"]'),
('6d74ac9c-0976-42d4-92f4-a3113d2f4c25','茂實被檄權永新以詩寄之','陳淵','宋','宋诗','song-poetry','','[]','澗松那可比山苗，謾說凌寒有後彫。',64,'全唐诗/poet.song.93000.json','["澗松那可比山苗，謾說凌寒有後彫。", "更向鷄蟲論得失，何如鵬鷃各逍遥。", "三鍾幸自堪攘臂，五斗誰能更折腰。", "正使爭先任勞苦，虞人寧不愧弓招。"]'),
('3b698cf9-837d-4d29-a087-e88100a0a1b6','次韻李光祖南山四偈  其一','陳淵','宋','宋诗','song-poetry','','[]','聲外聞和豈待言，棒頭猶是老婆禪。',32,'全唐诗/poet.song.93000.json','["聲外聞和豈待言，棒頭猶是老婆禪。", "如何更被文殊惑，却道維摩但黙然。"]'),
('d35977da-faad-4a68-b37c-38a4db30395e','次韻李光祖南山四偈  其二','陳淵','宋','宋诗','song-poetry','','[]','臘窮春到不須臾，霜下陳根豈用耡。',32,'全唐诗/poet.song.93000.json','["臘窮春到不須臾，霜下陳根豈用耡。", "若信彫榮如轉轂，故應搖落有扶疏。"]'),
('ecf1d127-704e-4eaa-b27f-c1e1ed003f15','次韻李光祖南山四偈  其三','陳淵','宋','宋诗','song-poetry','','[]','窗前松竹翠連山，窗下弦歌晝掩關。',32,'全唐诗/poet.song.93000.json','["窗前松竹翠連山，窗下弦歌晝掩關。", "雪裏忍看梅欲吐，煙中遥認鳥知還。"]'),
('7a69c94a-fee1-46b5-a80b-757c68a68318','次韻李光祖南山四偈  其四','陳淵','宋','宋诗','song-poetry','','[]','未暇南山訪隱居，祇應無處不逢渠。',32,'全唐诗/poet.song.93000.json','["未暇南山訪隱居，祇應無處不逢渠。", "憑君一省從前夢，莫歎離羣歲又除。"]'),
('38a82b91-4719-4e0a-99b8-6732689fd457','次韻光祖避地眉溪十絕  其一','陳淵','宋','宋诗','song-poetry','','[]','眼在句中寧易知，意存言外一何微。',32,'全唐诗/poet.song.93000.json','["眼在句中寧易知，意存言外一何微。", "柏舟故是仁人事，豈爲淹留念奮飛。"]'),
('10ab145a-0c2f-42fa-838d-b8f9884edae5','次韻光祖避地眉溪十絕  其二','陳淵','宋','宋诗','song-poetry','','[]','浮木如何濟巨川，積薪其下火將然。',32,'全唐诗/poet.song.93000.json','["浮木如何濟巨川，積薪其下火將然。", "是中已有安身地，許爾垂紳玉几前。"]'),
('81b6bbbd-5255-4047-a4b2-c793a905004c','次韻光祖避地眉溪十絕  其三','陳淵','宋','宋诗','song-poetry','','[]','弄雲微月淡回廊，十室連甍占上方。',32,'全唐诗/poet.song.93000.json','["弄雲微月淡回廊，十室連甍占上方。", "誰道各無容足地，夜談猶欲致時康。"]'),
('f17d37eb-55c0-4410-9f16-9cfc014ce599','次韻光祖避地眉溪十絕  其四','陳淵','宋','宋诗','song-poetry','','[]','少年憑恃氣方强，膚理微邪未覺傷。',32,'全唐诗/poet.song.93000.json','["少年憑恃氣方强，膚理微邪未覺傷。", "迨得病深無治法，始知先甲是農黄。"]'),
('21e5fce8-46f9-49bb-bc1c-1b3c35878473','次韻光祖避地眉溪十絕  其五','陳淵','宋','宋诗','song-poetry','','[]','訪道尋幽歷萬山，神仙元不在山間。',32,'全唐诗/poet.song.93000.json','["訪道尋幽歷萬山，神仙元不在山間。", "須知對面長相失，莫嘆喬松去不還。"]'),
('40aef0f5-3e3c-4a75-94f0-98631f61cdcf','次韻光祖避地眉溪十絕  其六','陳淵','宋','宋诗','song-poetry','','[]','四海黔黎共一君，須知盜賊亦吾民。',32,'全唐诗/poet.song.93000.json','["四海黔黎共一君，須知盜賊亦吾民。", "由来齊梃勝秦甲，要在人如父子親。"]'),
('7d9424ed-912b-4703-9a88-9410273a387a','次韻光祖避地眉溪十絕  其七','陳淵','宋','宋诗','song-poetry','','[]','當時先主得關張，能使西川弱勝强。',32,'全唐诗/poet.song.93000.json','["當時先主得關張，能使西川弱勝强。", "今日中原豈無士，坐愁豺虎亂要荒。"]'),
('bb01533d-5ba0-47c4-b216-dbf1109424e2','次韻光祖避地眉溪十絕  其八','陳淵','宋','宋诗','song-poetry','','[]','汙莱正爾肥蚯蚓，滯穗那能飽鸒斯。',32,'全唐诗/poet.song.93000.json','["汙莱正爾肥蚯蚓，滯穗那能飽鸒斯。", "布穀似嫌新歷緩，每從清曉報農時。"]'),
('d9271ee4-1e9c-4f6d-b80d-27f87bb7b9fa','次韻光祖避地眉溪十絕  其九','陳淵','宋','宋诗','song-poetry','','[]','何人更下仲舉榻，舉世願登元禮門。',32,'全唐诗/poet.song.93000.json','["何人更下仲舉榻，舉世願登元禮門。", "千古家聲君與我，未知何以起斯文。"]'),
('950e35b8-ab30-4121-92ca-6e9cbcdc69b9','次韻光祖避地眉溪十絕  其一○','陳淵','宋','宋诗','song-poetry','','[]','了齋力欲排邪說，誰遣奇窮道不興。',32,'全唐诗/poet.song.93000.json','["了齋力欲排邪說，誰遣奇窮道不興。", "長恨人亡琴亦往，賴傳心法有盧能。"]'),
('99c67cd8-128e-4e83-a676-14d018003232','眉溪與光祖共談得四絕句  其一','陳淵','宋','宋诗','song-poetry','','[]','乾坤今古自昭然，此意何勞密處論。',32,'全唐诗/poet.song.93000.json','["乾坤今古自昭然，此意何勞密處論。", "不是逢人喜傾倒，正應公事合公言。"]'),
('fe1fec45-d981-48f7-be01-8a329a8dd645','眉溪與光祖共談得四絕句  其二','陳淵','宋','宋诗','song-poetry','','[]','青山雨後足奇態，好鳥簷間無俗音。',32,'全唐诗/poet.song.93000.json','["青山雨後足奇態，好鳥簷間無俗音。", "縱使麯生難會面，可無毛穎解傳心。"]'),
('0e34c00f-5134-42eb-8b85-ea5ac375a224','眉溪與光祖共談得四絕句  其三','陳淵','宋','宋诗','song-poetry','','[]','流泉爲演秘密藏，枕上聲從澗底来。',32,'全唐诗/poet.song.93000.json','["流泉爲演秘密藏，枕上聲從澗底来。", "半夜夢回聽說偈，似傳衣鉢向黄梅。"]'),
('e2b66928-0d90-4dfe-991c-d198f591f930','眉溪與光祖共談得四絕句  其四','陳淵','宋','宋诗','song-poetry','','[]','溪邊索共桃花笑，雨打風吹掃地空。',32,'全唐诗/poet.song.93000.json','["溪邊索共桃花笑，雨打風吹掃地空。", "待訪靈雲舊消息，急流無處覓殘紅。"]'),
('556cace2-60dc-45dc-9769-e5d59f77667a','交溪庵中因檢藥嚢偶成','陳淵','宋','宋诗','song-poetry','','[]','道人頭上經春雪，不羡少年何首烏。',32,'全唐诗/poet.song.93000.json','["道人頭上經春雪，不羡少年何首烏。", "已覺老来甘草莽，便當歸去訪田廬。"]'),
('e268c3a9-85a1-44b1-82e7-fca987700250','次韻陸時可歲暮感懷  其一','陳淵','宋','宋诗','song-poetry','','[]','小橋横截一溪雲，隔岸遥通避世人。',64,'全唐诗/poet.song.93000.json','["小橋横截一溪雲，隔岸遥通避世人。", "釣艇偶隨秋雁泊，吟窗今見臘梅新。", "煙塵已覺千山靜，雨露行看萬國春。", "詩酒暮年生處樂，一瓢歸去豈辭貧。"]'),
('8d9e6563-2236-42bf-9820-4e0b29792c90','次韻陸時可歲暮感懷  其二','陳淵','宋','宋诗','song-poetry','','[]','風御泠然幾過旬，異鄉窮臘作離人。',64,'全唐诗/poet.song.93000.json','["風御泠然幾過旬，異鄉窮臘作離人。", "淹留賴有交情重，飜覆從教俗態新。", "於世無求心似水，向人多可氣如春。", "也知已造顔原室，不恥人間賤與貧。"]'),
('10fbfa0c-4132-4e93-a20a-1e8e33b66404','再和時可二首  其一','陳淵','宋','宋诗','song-poetry','','[]','芝眉不見忽經旬，屢出新篇故惱人。',64,'全唐诗/poet.song.93000.json','["芝眉不見忽經旬，屢出新篇故惱人。", "應共翰林爭敏捷，豈如開府但清新。", "鷄豚且入他鄉社，桃李何殊故國春。", "白髪蒼髯共擕手，從来管鮑兩忘貧。"]'),
('9783f538-249f-4a64-b36f-8c5aff36e4f2','再和時可二首  其二','陳淵','宋','宋诗','song-poetry','','[]','甲子公今不記句，磻溪垂釣豈其人。',64,'全唐诗/poet.song.93000.json','["甲子公今不記句，磻溪垂釣豈其人。", "安心有道年年徤，出語無塵字字新。", "鬬智莫爭三十里，貪生何用八千春。", "直須凖備新年醉，無地容錐未是貧。"]'),
('3f357a88-607b-4995-98d5-4dbabf92668d','又用元韻呈時可','陳淵','宋','宋诗','song-poetry','','[]','古来兵出僅三旬，便欲修文格遠人。',64,'全唐诗/poet.song.93000.json','["古来兵出僅三旬，便欲修文格遠人。", "圖蔓可堪師已老，滌瑕當與俗更新。", "舞干止殺知何日，賣劍歸耕要及春。", "但得耡耰遍原野，飯藜何惜一身貧。"]'),
('bc8faeb5-b447-4a2a-8ebf-d94777b1d8fa','次韻光祖閑居感懷','陳淵','宋','宋诗','song-poetry','','[]','風義久已喪，交道何其衰。',72,'全唐诗/poet.song.93000.json','["風義久已喪，交道何其衰。", "艱窘無與俱，乃歌風及頺。", "誰言經由地，過門有犂来。", "霜雪豈不惡，松筠真奈摧。", "富貴如浮雲，於我何有哉。", "所嗟道不興，茲士猶塵埃。"]'),
('9d7b2c08-2b16-4940-b9ab-c3666e9046ff','初到臨安二首  其一','陳淵','宋','宋诗','song-poetry','','[]','風際管絃朝病酒，雲中樓閣夜聞香。',32,'全唐诗/poet.song.93000.json','["風際管絃朝病酒，雲中樓閣夜聞香。", "十年一夢沙河路，獨步春泥覺燕忙。"]'),
('cfb4c85c-6d71-4eda-9911-2714efd15c6d','初到臨安二首  其二','陳淵','宋','宋诗','song-poetry','','[]','青鞋踏雨花鋪徑，朱艦凌風柳拂堤。',32,'全唐诗/poet.song.93000.json','["青鞋踏雨花鋪徑，朱艦凌風柳拂堤。", "天竺舊游心已懶，孤山行處路應迷。"]'),
('63e9f796-af1e-4c36-baa2-1e6d84493643','錢塘江','陳淵','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','潮頭駕月衝殘夢，水色浮空送峭寒。',32,'全唐诗/poet.song.93000.json','["潮頭駕月衝殘夢，水色浮空送峭寒。", "十幅輕蒲連夜發，不知身到海門山。"]'),
('244a9f0c-7ac1-45cb-b2c1-fd7a292d40f0','次韻王長源飲垂絲海棠花下','陳淵','宋','宋诗','song-poetry','','[]','寇盜縱橫已十春，今年花下得微曛。',64,'全唐诗/poet.song.93000.json','["寇盜縱橫已十春，今年花下得微曛。", "應憐萬木灰薪槱，喜見奇葩脱斧斤。", "遣將幾人非鞅鞅，覆盟今日尚棼棼。", "憑君爲國施長策，莫戀垂絲鄙獻芹。"]'),
('06f38db9-28fd-4905-86da-956b4b9c0783','鄧季明挽詞三首  其一','陳淵','宋','宋诗','song-poetry','','[]','少年長揖出賢關，自許行藏契孔顔。',64,'全唐诗/poet.song.93000.json','["少年長揖出賢關，自許行藏契孔顔。", "雲路不求千載遇，篳門贏得一生閑。", "奇言盡掃鷄三足，妙意誰窺豹一斑。", "盡道東牀如李漢，會傳餘論落人間。"]'),
('cd899e99-393f-4979-b0ac-affd24362a36','鄧季明挽詞三首  其二','陳淵','宋','宋诗','song-poetry','','[]','它時膚使早還鄉，駐節旁連避世牆。',64,'全唐诗/poet.song.93000.json','["它時膚使早還鄉，駐節旁連避世牆。", "雁序風標蓮破蕚，鳳雛衣袂桂飄香。", "花邊對酒春難老，竹裏圍棊日自長。", "曾共國人歌友愛，傷心重到棣華堂。"]'),
('e95e89df-1286-419a-a3fd-483c4b62fc4b','鄧季明挽詞三首  其三','陳淵','宋','宋诗','song-poetry','','[]','道人於世已忘名，相府聞風眼自青。',64,'全唐诗/poet.song.93000.json','["道人於世已忘名，相府聞風眼自青。", "險韻舊聯韓子句，直詞今稱蔡邕銘。", "壁間玉唾情何厚，梁上銀鈎墨尚馨。", "只爾便知君不朽，豈緣中說載元齡。"]'),
('81f5638e-fba0-4247-b341-5916b279df24','省題筆諫詩','陳淵','宋','宋诗','song-poetry','','[]','志士憂君切，還將筆効忠。',72,'全唐诗/poet.song.93000.json','["志士憂君切，還將筆効忠。", "但於心取正，不向字求工。", "理自胸襟得，情因翰墨通。", "一言毛穎喻，千古史魚風。", "託意揮毫上，成名補袞中。", "誰知執藝事，功與諍臣同。"]'),
('a3aa1546-b898-4f74-992f-08d52325118a','和參謀至日喜雪三首  其一','陳淵','宋','宋诗','song-poetry','','[]','風鳴竹屋懼將顛，起視同雲隘萬川。',64,'全唐诗/poet.song.93000.json','["風鳴竹屋懼將顛，起視同雲隘萬川。", "共喜葭灰初應律，那知柳絮已漫天。", "傳杯莫怕山頽玉，閉户從教徑糝氊。", "幕府老成堪倚杖，故應衰病得安眠。"]'),
('6789b52d-42e9-4fc9-a6fa-46dc8a5ce42b','和參謀至日喜雪三首  其二','陳淵','宋','宋诗','song-poetry','','[]','玉花初著亂山顛，入夜俄驚月滿川。',64,'全唐诗/poet.song.93000.json','["玉花初著亂山顛，入夜俄驚月滿川。", "雖有冷光凝白晝，尚餘陰曀鎖青天。", "屬車未返瑶池駿，遠使猶餐北海氊。", "夢斷忽傳淮蔡捷，喜臨尊酒已忘眠。"]'),
('f5b5f42c-da63-42a1-8b1b-489fbef4a229','和參謀至日喜雪三首  其三','陳淵','宋','宋诗','song-poetry','','[]','恊氣方占大有年，珠璣填道璧沉川。',64,'全唐诗/poet.song.93000.json','["恊氣方占大有年，珠璣填道璧沉川。", "塵埃已洗三千界，雲霧終開尺五天。", "羔袖久慚依帥幕，牛衣端不羡蠻氈。", "求田好趁豐登候，乞與元龍榻上眠。"]'),
('ae81c3b2-5166-4798-976f-7f4e6e875209','和參謀參議尋春','陳淵','宋','宋诗','song-poetry','','[]','二老俱傳正始音，春来詩思轉精神。',64,'全唐诗/poet.song.93000.json','["二老俱傳正始音，春来詩思轉精神。", "風前未展垂天翼，筆下空聞擲地金。", "曉日若將開霽色，宿雲先已弄輕陰。", "落花流水年年事，只恐桃源不可尋。"]'),
('9f9a08a1-bf8f-407f-a1db-9543d3c86930','次韻吳參議病中懷歸因以自見','陳淵','宋','宋诗','song-poetry','','[]','柳絲垂地整如梳，春盡長懷舊隱居。',64,'全唐诗/poet.song.93000.json','["柳絲垂地整如梳，春盡長懷舊隱居。", "草暖屢眠斜照外，水香時潄落花餘。", "西山忍餓初疑隘，北海無功竟坐疏。", "同是念歸公得請，自憐濡滯一軒渠。"]'),
('83ea56e8-7eec-48da-a591-59e693c838f7','次韻安茂通同薛參議上巳日唱和','陳淵','宋','宋诗','song-poetry','','[]','扁舟衝浪去，羸馬傍城行。',48,'全唐诗/poet.song.93000.json','["扁舟衝浪去，羸馬傍城行。", "飄泊傷春緒，艱難作吏情。", "豈無賢者樂，亦有聖人清。", "莫繼蘭亭會，愁連曲水生。"]'),
('ad141f3a-ba5d-46f2-b405-9b410468dff3','三月二十日游東山參議不至有詩次韻','陳淵','宋','宋诗','song-poetry','','[]','羈懷厭朝市，逸興薄江山。',48,'全唐诗/poet.song.93000.json','["羈懷厭朝市，逸興薄江山。", "放杖囂埃外，傳觴紫翠間。", "碧雲猶未合，飛鳥已知還。", "不見高車過，重城欲上關。"]'),
('9f0db143-4030-4b7d-b9e4-70c8bcfc9e46','參謀得暫假歸留别同舍次韻','陈渊','宋','宋诗','song-poetry','','[]','青蒿何敢附蒼官，要以陳根託歲寒。',64,'全唐诗/poet.song.93000.json','["青蒿何敢附蒼官，要以陳根託歲寒。", "萬事忘情知我拙，一窗容膝許同歡。", "也知堅卧元非病，况是無心可得安。", "歸去儻餘饑溺念，豈能無意復纓冠。"]'),
('b9eed457-8603-4600-a454-2944dde4e0e3','次韻茂通喜雨','陈渊','宋','宋诗','song-poetry','','[]','師行初不犯秋毫，坐縛兇渠泚與滔。',64,'全唐诗/poet.song.93000.json','["師行初不犯秋毫，坐縛兇渠泚與滔。", "和氣自應迴歲旱，豐年當復騐秋高。", "横流是處通飛鷁，歸佩何時脱孟勞。", "要廣江南千里潤，須令天下入甄陶。"]'),
('2ff86f70-afe2-481f-a701-0bfda2af0484','送張巨山著作使閩分韻得我字','陈渊','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','道山仙者居，是中乃置我。',144,'全唐诗/poet.song.93000.json','["道山仙者居，是中乃置我。", "白前英俊前，糠粃出揚簸。", "同寮事闊略，未忍棄衰惰。", "日聞所不聞，更欲學其可。", "張侯廊廟器，文字粲藻火。", "一班見餘論，已足踐青瑣。", "欣然取使節，去我何其果。", "無乃萬斛舟，未授濟川柁。", "相攜湖上别，酒盡重城鎖。", "分離情已重，去住計誰左。", "從來洞庭野，乘雁不加夥。", "何日西江潮，送我東歸舸。"]'),
('566ecdc0-0a91-4adf-9f6b-50008c17faea','石夫人挽詞','陈渊','宋','宋诗','song-poetry','','[]','好客陶家舊，多才謝女風。',48,'全唐诗/poet.song.93000.json','["好客陶家舊，多才謝女風。", "一窺知帝輔，三徙得儒宫。", "遺子經猶在，知人鑒已空。", "里閭推達識，愛壻有乘騘。"]'),
('b89c13f4-74bb-445e-8d6b-73cc1abe880f','送黄平國倅邵武','陈渊','宋','宋诗','song-poetry','','[]','雪到蓬山尚破裘，倦聽餘子說封侯。',64,'全唐诗/poet.song.93000.json','["雪到蓬山尚破裘，倦聽餘子說封侯。", "松楸更作連宵夢，桂玉寧堪卒歲留。", "衣繡故應人所羡，題輿仍爲國分憂。", "艱難兀坐添華髪，亦欲如公可得不。"]'),
('42f221d2-b420-4cc1-a1cc-fa9de4f57c9c','答吳濟仲見寄','陈渊','宋','宋诗','song-poetry','','[]','季子觀周樂，妙意傳青簡。',180,'全唐诗/poet.song.93000.json','["季子觀周樂，妙意傳青簡。", "諸孫拾其遺，破具前人眼。", "新詩如珠璧，字字無可揀。", "故應意有餘，不但音睍睆。", "念昔我方壮，意輕三子撰。", "自聞歌白雪，欲和色先赧。", "中間各流落，念子忘寢饌。", "阻尋千里盟，未卜一笑莞。", "書来得佳句，奇字富瑟僴。", "推先情已厚，感舊涕應澘。", "周宣致中興，土宇日益昄。", "膚使盡蘇張，九合寧須轏。", "天才必有用，造物豈徒産。", "椽筆儻容揮，斗印定當綰。", "既去却須来，毋絕漢中棧。"]'),
('477c16b8-4d7f-4113-bd53-63a771f21646','次韻鄧天啓賀茅舍新成二首  其一','陈渊','宋','宋诗','song-poetry','','[]','長者一牀室，先生五柳廬。',48,'全唐诗/poet.song.93000.json','["長者一牀室，先生五柳廬。", "久貧應似我，多病或如渠。", "客少門常寂，身閑日自舒。", "窺園知鮮暇，安得摻君裾。"]'),
('65492984-27d2-436f-912c-73320baddb5c','次韻鄧天啓賀茅舍新成二首  其二','陈渊','宋','宋诗','song-poetry','','[]','艱難思健士，誰復數寒儒。',48,'全唐诗/poet.song.93000.json','["艱難思健士，誰復數寒儒。", "老去懷三徑，歸来就一區。", "春情縈夢草，晚步及栖烏。", "不愧王摩詰，新詩有畫圖。"]'),
('bede1bd3-4807-47c4-97aa-a6ac3f787fa9','次韻延年弟相慶  其一','陈渊','宋','宋诗','song-poetry','','[]','逐客身無事，乘閑葺敝廬。',48,'全唐诗/poet.song.93000.json','["逐客身無事，乘閑葺敝廬。", "堂成因有室，水到自成渠。", "地迥千巖秀，春迴一氣舒。", "幸爲時所棄，容我懶簮裾。"]'),
('20177330-0ff4-4fdb-94b2-423076e8c7be','次韻延年弟相慶  其二','陈渊','宋','宋诗','song-poetry','','[]','經年侍清宴，飽食愧侏儒。',48,'全唐诗/poet.song.93000.json','["經年侍清宴，飽食愧侏儒。", "脱迹鴛鴻路，忘懷草木區。", "朝簷看鬬雀，晚檻引饑烏。", "已覺蓬蒿適，誰能九萬圖。"]'),
('cd64e178-4e5f-4206-a963-1730aabecf50','次韻宗仁弟相慶  其一','陈渊','宋','宋诗','song-poetry','','[]','吾閩山水國，幽絕勝衡廬。',48,'全唐诗/poet.song.93000.json','["吾閩山水國，幽絕勝衡廬。", "隱几雲生席，開軒柳映渠。", "連枝均魯衞，異說屏荆舒。", "此外無它慕，何門可曳裾。"]'),
('fcc18ecd-adf7-4a0f-96d2-18bfdcfce955','次韻宗仁弟相慶  其二','陈渊','宋','宋诗','song-poetry','','[]','侵疆猶未復，世不乏真儒。',48,'全唐诗/poet.song.93000.json','["侵疆猶未復，世不乏真儒。", "肯使金湯地，長爲豺虎區。", "頽齡真病鶴，急警任飛烏。", "縱有藏身處，偷安豈遠圖。"]'),
('41b80736-eaff-46b8-b53c-f5d08f2a6b9d','次韻沈公雅相慶  其一','陈渊','宋','宋诗','song-poetry','','[]','沈子膏粱胄，從余一草廬。',48,'全唐诗/poet.song.93000.json','["沈子膏粱胄，從余一草廬。", "幾年同寂寞，此日更勤渠。", "師範宗韓孟，源流接誼舒。", "艱難思報國，猶未厠朝裾。"]'),
('1a114483-73aa-41b6-b967-f76c84cc0bcf','次韻沈公雅相慶  其二','陈渊','宋','宋诗','song-poetry','','[]','尚書足勲業，振迹自窮儒。',48,'全唐诗/poet.song.93000.json','["尚書足勲業，振迹自窮儒。", "清德逾三世，忠名滿八區。", "詩才推道藴，玄旨賴童烏。", "豈厭隆中卧，慙無八陣圖。"]'),
('71cb1522-9a8c-44cf-9332-12f67775f67f','代朝宗弟和餞行二首  其一','陈渊','宋','宋诗','song-poetry','','[]','席門誰復顧寒儒，深愧頻迂長者車。',64,'全唐诗/poet.song.93000.json','["席門誰復顧寒儒，深愧頻迂長者車。", "更爲穆生時設醴，應憐馮子食無魚。", "諸生久被絃歌化，盛禮誰將簡册書。", "從此邑人蒙勸奬，定知容駟有高閭。"]'),
('6ad42dbe-a8cb-4e46-bab6-ab8eca34a5d3','代朝宗弟和餞行二首  其二','陈渊','宋','宋诗','song-poetry','','[]','少年經業富三餘，肯羡相如駟馬車。',64,'全唐诗/poet.song.93000.json','["少年經業富三餘，肯羡相如駟馬車。", "要向青雲開羽翼，豈辭黄卷注蟲魚。", "平生頗負連鰲手，老大猶隨荐鶚書。", "此去果符叢桂兆，敢求椽筆掲吾閭。"]'),
('c733aad0-93c3-4419-9003-36d8b85390b9','興國燦老往漳州二偈送之  其一','陈渊','宋','宋诗','song-poetry','','[]','江梅又趁一陽迴，身在旃檀林下来。',32,'全唐诗/poet.song.93000.json','["江梅又趁一陽迴，身在旃檀林下来。", "行到漳南香未歇，百花聞此一時開。"]'),
('f5e5ad79-e60a-4406-b4e4-2c94cb6638b3','興國燦老往漳州二偈送之  其二','陈渊','宋','宋诗','song-poetry','','[]','浮雲出岫本無心，桔橰俯仰人所引。',32,'全唐诗/poet.song.93000.json','["浮雲出岫本無心，桔橰俯仰人所引。", "一大藏教留後人，看與不看渠自省。"]'),
('1771856c-eb37-43d8-8738-97366a2e5507','鄧端友臨要閣五首  其一','陈渊','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昔年曾到十三樓，一日西湖十頃秋。',32,'全唐诗/poet.song.93000.json','["昔年曾到十三樓，一日西湖十頃秋。", "寒碧軒中最宜暑，只緣脩竹近清流。"]'),
('bbf4ce8f-a6b2-424b-98f7-d7afd016f4d7','鄧端友臨要閣五首  其二','陈渊','宋','宋诗','song-poetry','','[]','十里烟波竹外溪，隔溪青嶂遶窗扉。',32,'全唐诗/poet.song.93000.json','["十里烟波竹外溪，隔溪青嶂遶窗扉。", "詩人不見東坡老，直節空餘一尺圍。"]'),
('9cfc31c7-f9e2-4861-858d-d3d26e9e6ed4','鄧端友臨要閣五首  其三','陈渊','宋','宋诗','song-poetry','','[]','誰家多竹門可款，臨要閣前沙岸傍。',32,'全唐诗/poet.song.93000.json','["誰家多竹門可款，臨要閣前沙岸傍。", "謾道薰風能解愠，正應蒼玉自生涼。"]'),
('ad9a289c-6d1a-43ee-8484-3750266efea5','鄧端友臨要閣五首  其四','陈渊','宋','宋诗','song-poetry','','[]','繁枝蓋地欲成幄，傑榦凌空不礙簷。',32,'全唐诗/poet.song.93000.json','["繁枝蓋地欲成幄，傑榦凌空不礙簷。", "爲語韓公莫除好，此間風月豈須添。"]'),
('0c2bdf94-4bdc-4ea4-a53d-550de207c1e2','鄧端友臨要閣五首  其五','陈渊','宋','宋诗','song-poetry','','[]','甘苦元從舌上知，竹間風味與誰期。',32,'全唐诗/poet.song.93000.json','["甘苦元從舌上知，竹間風味與誰期。", "萬竿可斬從人說，一榻乘涼要自嬉。"]'),
('fa2afedc-9cd9-47d0-a90b-243b4aa2348e','端友和臨要閣詩再次韻五首  其一','陈渊','宋','宋诗','song-poetry','','[]','茅齋西望水邊樓，亦復開軒對奕秋。',32,'全唐诗/poet.song.93000.json','["茅齋西望水邊樓，亦復開軒對奕秋。", "欲效子猷偏種竹，竹前那得一溪流。"]'),
('15217900-48e4-4895-878b-d03b4f5c6027','端友和臨要閣詩再次韻五首  其二','陈渊','宋','宋诗','song-poetry','','[]','乘興誰當訪剡溪，竹間應復掩雙扉。',32,'全唐诗/poet.song.93000.json','["乘興誰當訪剡溪，竹間應復掩雙扉。", "也知劇暑攻人急，正賴青雙一解圍。"]'),
('30b7de53-d54b-4603-9b3a-69335b2f1811','端友和臨要閣詩再次韻五首  其三','陈渊','宋','宋诗','song-poetry','','[]','午窗青夢接羲皇，茗盌無多置我傍。',32,'全唐诗/poet.song.93000.json','["午窗青夢接羲皇，茗盌無多置我傍。", "此味若令兒輩覺，人間容有竹風涼。"]'),
('446063fb-79ce-47db-9d9c-40004fd311b2','端友和臨要閣詩再次韻五首  其四','陈渊','宋','宋诗','song-poetry','','[]','宿靄初收一卷簾，萬山騰沓擁飛簷。',32,'全唐诗/poet.song.93000.json','["宿靄初收一卷簾，萬山騰沓擁飛簷。", "靜看野色連蒼竹，便覺閑中氣味添。"]'),
('995988ee-6dcc-4ec8-88b0-f104ab3bdb4c','端友和臨要閣詩再次韻五首  其五','陈渊','宋','宋诗','song-poetry','','[]','不將朝服換斑衣，正以親年慰所期。',32,'全唐诗/poet.song.93000.json','["不將朝服換斑衣，正以親年慰所期。", "却恐英名喧衆口，未容莱子作兒嬉。"]'),
('d9606f76-79ef-4b2d-bdf5-d63d5f9ededf','送朝宗弟赴試南宫','陈渊','宋','宋诗','song-poetry','','[]','霜餘賓雁日南征，念子衝寒去我閩。',64,'全唐诗/poet.song.93000.json','["霜餘賓雁日南征，念子衝寒去我閩。", "應向月娥占昨夢，欲扳仙桂赴新春。", "平生學海真無底，晚節詞鋒更有神。", "要路爭先吾老矣，可無高論躡平津。"]'),
('5e0f1a3f-d248-4902-9e6f-e9d5e99ea308','慶鄧德達得子','陈渊','宋','宋诗','song-poetry','','[]','海中仙果真難得，天上麒麟必異才。',32,'全唐诗/poet.song.93000.json','["海中仙果真難得，天上麒麟必異才。", "速客未爲湯餅供，荐觴須俟鯉魚来。"]'),
('386daae7-f8a7-49c4-bc91-4cbfa2e8d404','書心畫詩','陈渊','宋','宋诗','song-poetry','','[]','書法從中得，難將筆下尋。',72,'全唐诗/poet.song.93000.json','["書法從中得，難將筆下尋。", "欲知神合處，始悟畫由心。", "篆隸秦非古，真行晉迄今。", "奇蹤存翰墨，妙意本胸襟。", "雄徤猊飜石，騫騰鳥出林。", "古人求筆正，八法響隨音。"]'),
('303afe8a-fed8-4d21-b88d-4730554ca7f6','題興國寺碧落軒  其一','陈渊','宋','宋诗','song-poetry','','[]','北山其下僧伽塔，影落軒前草樹間。',32,'全唐诗/poet.song.93000.json','["北山其下僧伽塔，影落軒前草樹間。", "誰向月明看白牯，靜中相對兩俱閑。"]'),
('baa8b93c-2f42-452f-b2b8-9d293d2987a2','題興國寺碧落軒  其二','陈渊','宋','宋诗','song-poetry','','[]','休論暮四同朝四，且說前三與後三。',32,'全唐诗/poet.song.93000.json','["休論暮四同朝四，且說前三與後三。", "造物戲人無足較，老禪深處要重參。"]'),
('2bb13a93-1609-4d47-a897-b88233511130','端友以桂漿兩樽見惠賦詩六首  其一','陈渊','宋','宋诗','song-poetry','','[]','白衣挈榼踵吾門，頗說雙泉更有兄。',32,'全唐诗/poet.song.93000.json','["白衣挈榼踵吾門，頗說雙泉更有兄。", "洗盞爲君開醉色，不知人世有王閎。"]'),
('18dbc8f5-a310-401d-b35e-6452f3d27eb0','端友以桂漿兩樽見惠賦詩六首  其二','陈渊','宋','宋诗','song-poetry','','[]','秋水無聲瀉玉觥，鏡奩初啓淨無塵。',32,'全唐诗/poet.song.93000.json','["秋水無聲瀉玉觥，鏡奩初啓淨無塵。", "未將滋味誇殊勝，已覺風神最惱人。"]'),
('5f84808e-10ae-486c-8507-b21b939d8587','端友以桂漿兩樽見惠賦詩六首  其三','陈渊','宋','宋诗','song-poetry','','[]','濁者爲賢聖是清，古人無復論甘辛。',32,'全唐诗/poet.song.93000.json','["濁者爲賢聖是清，古人無復論甘辛。", "因觀表裏如冰玉，始信荀楊未盡醇。"]'),
('4a7ccb6a-f902-4733-9e04-c5106cdb8d92','端友以桂漿兩樽見惠賦詩六首  其四','陈渊','宋','宋诗','song-poetry','','[]','鼠竊跳梁十里間，數杯中夜得安眠。',32,'全唐诗/poet.song.93000.json','["鼠竊跳梁十里間，數杯中夜得安眠。", "千艘雷動人方擾，一榻山頹我自仙。"]'),
('b7fe05ac-0cf6-43cb-bd95-c2567fd61aff','端友以桂漿兩樽見惠賦詩六首  其五','陈渊','宋','宋诗','song-poetry','','[]','餉我兩罇才斗許，客来索飲不論升。',32,'全唐诗/poet.song.93000.json','["餉我兩罇才斗許，客来索飲不論升。", "明朝此物豈易得，縱有市酤寧獨醒。"]'),
('37e49a28-50be-4467-8720-c70935c12f0c','端友以桂漿兩樽見惠賦詩六首  其六','陈渊','宋','宋诗','song-poetry','','[]','投轄誰云有祖風，啜醨難與貴人同。',32,'全唐诗/poet.song.93000.json','["投轄誰云有祖風，啜醨難與貴人同。", "竹林若許供鷄黍，助我醇醪幸少豐。"]'),
('ff731daf-770f-4c00-8f69-29f3433b6c95','代陳應之作','陈渊','宋','宋诗','song-poetry','','[]','淑德初無玷，高情更出塵。',48,'全唐诗/poet.song.93000.json','["淑德初無玷，高情更出塵。", "擇鄰思教子，剪髪爲延賓。", "裁鑒推前識，提攜即偉人。", "東牀他日選，烏府號忠臣。"]'),
('23131596-35dc-43b8-8de2-fc9bb473127d','謁璨老病未能起留二偈示之  其一','陈渊','宋','宋诗','song-poetry','','[]','趙州不出三門，淨名堅卧一榻。',28,'全唐诗/poet.song.93000.json','["趙州不出三門，淨名堅卧一榻。", "我来堂下便迴，此間有問有答。"]'),
('03b7ac75-1407-4077-8452-1c986f19dd6e','謁璨老病未能起留二偈示之  其二','陈渊','宋','宋诗','song-poetry','','[]','西堂偶爾頭痛，首座從来脚跛。',28,'全唐诗/poet.song.93000.json','["西堂偶爾頭痛，首座從来脚跛。", "堂頭更自黙黙，客来一場懡㦬。"]'),
('3a2b0c9f-80e2-4a94-be4d-38b4f160f25d','和璨老示雙井茶紙被簡板三偈  其一','陈渊','宋','宋诗','song-poetry','','[]','雙井江南妙品，不減建溪月團。',28,'全唐诗/poet.song.93000.json','["雙井江南妙品，不減建溪月團。", "但使睡魔不作，可須歸去蓬山。"]'),
('03f99c0f-b026-49a7-8de7-5c6d2201030c','和璨老示雙井茶紙被簡板三偈  其二','陈渊','宋','宋诗','song-poetry','','[]','江靜微波皺縠，庭空落絮鋪茵。',28,'全唐诗/poet.song.93000.json','["江靜微波皺縠，庭空落絮鋪茵。", "正是鄰牀作夢，直須款款反身。"]'),
('6c7833c8-dbe3-47b0-ba97-5fac1c0d0334','和璨老示雙井茶紙被簡板三偈  其三','陈渊','宋','宋诗','song-poetry','','[]','縱使前詞洗盡，不妨後信重通。',28,'全唐诗/poet.song.93000.json','["縱使前詞洗盡，不妨後信重通。", "會取曹溪一滴，語言文字皆空。"]'),
('674b2ecc-f0b7-4588-a8d2-92054a9972e5','次韻蕭茂德','陈渊','宋','宋诗','song-poetry','','[]','未能仰首試鳴號，且復塵埃奈此勞。',64,'全唐诗/poet.song.93000.json','["未能仰首試鳴號，且復塵埃奈此勞。", "健筆凌雲誰誤許，扁舟乘雪興何高。", "餘生敢歎鬚如戟，薄俗終防笑有刀。", "留滯周南何足數，人間如我九牛毛。"]'),
('19efdc33-184b-4c2d-968a-e4a3fc8e930d','留龍居士試建茶既去輒分送幷頌寄之','陈渊','宋','宋诗','song-poetry','','[]','未下鈐鎚墨如漆，已入篩羅白如雪。',64,'全唐诗/poet.song.93000.json','["未下鈐鎚墨如漆，已入篩羅白如雪。", "從來黑白不相融，吸盡方知了無別。", "老龍過我睡初醒，爲破雲腴同一啜。", "舌根回味只自知，放盞相看欲何說。"]'),
('849b9e15-7239-448a-90c9-0ba63c44c1a2','得老龍見和復呈','陈渊','宋','宋诗','song-poetry','','[]','是渠白芽，聚爲黑塊。',50,'全唐诗/poet.song.93000.json','["是渠白芽，聚爲黑塊。", "方訝墨堅，復如粉碎。", "生滅滅已，元非內外。", "說性說形，又說一味。", "急點一杯，扶居士醉。"]'),
('356b0ede-6e90-4a15-90dd-8af7d013ba0a','題仙霞嶺上庵中示仲思','陈渊','宋','宋诗','song-poetry','','[]','媯之後，封于茲。',48,'全唐诗/poet.song.93000.json','["媯之後，封于茲。", "出我車，濟乎沂。", "龍得雨，燕始歸。", "一投匕，遂拂衣。", "忠州孫，見者思。", "發一笑，譯其辭。"]'),
('756c0639-c297-4a47-84b5-bf07c6f92505','顔樂亭','陈渊','宋','宋诗','song-poetry','','[]','亭名顔樂枕高山，自有行藏遠契顔。',64,'全唐诗/poet.song.93000.json','["亭名顔樂枕高山，自有行藏遠契顔。", "玉陛不求千載遇，蓽門贏得一生閑。", "簞瓢陋巷堪游衍，富貴浮雲任往還。", "更續洛川求所學，會傳餘論落人間。"]'),
('25eab997-f32d-439a-818f-ab070c1d6dcf','濯纓亭','陈渊','宋','宋诗','song-poetry','','[]','涉世誰能不混塵，幸無塵土點簪紳。',64,'全唐诗/poet.song.93000.json','["涉世誰能不混塵，幸無塵土點簪紳。", "滄浪解洗許由耳，醽醁還澆靖節巾。", "心地已非汙可染，盤銘自警德常新。", "此亭要與名俱永，不信西風能汙人。"]'),
('1ec935d3-ca66-4b14-92ff-dd2a1126b2f3','寄傲軒','陈渊','宋','宋诗','song-poetry','','[]','南窗何似北窗涼，寄傲乘風各有方。',64,'全唐诗/poet.song.93000.json','["南窗何似北窗涼，寄傲乘風各有方。", "俯仰尚嫌天地窄，卷舒寧計古今長。", "酒斟盞裏浮醅綠，菊采籬邊滿眼黄。", "萬事醉來俱不醒，時飛清夢到羲皇。"]'),
('c0c03b15-8fae-425a-80e1-9d22e2098f04','朝陽峰','陈渊','宋','宋诗','song-poetry','','[]','扶桑擁晴紅，梧桐藹深翠。',24,'全唐诗/poet.song.93000.json','["扶桑擁晴紅，梧桐藹深翠。", "鳴鳳在高岡，昭昭聖王瑞。"]'),
('cc1a824f-7853-420e-92af-15a8df5a8654','妙高峰','陈渊','宋','宋诗','song-poetry','','[]','仰止萬仞高，巍巍插天碧。',24,'全唐诗/poet.song.93000.json','["仰止萬仞高，巍巍插天碧。", "端如仁者靜，妙處疇能識。"]'),
('a27ec0ae-372e-4454-ab96-29eaba9118af','真隱峰','陈渊','宋','宋诗','song-poetry','','[]','高人有真趣，林壑暫棲遲。',24,'全唐诗/poet.song.93000.json','["高人有真趣，林壑暫棲遲。", "悠悠經濟心，未許巢由知。"]'),
('53b4e4f3-cb2e-4219-b631-9a5588fcc202','凝翠東峰','陈渊','宋','宋诗','song-poetry','','[]','東山欣仰止，嵐光翠欲滴。',24,'全唐诗/poet.song.93000.json','["東山欣仰止，嵐光翠欲滴。", "駕言山中游，藍衣照春色。"]'),
('e04618b3-baf5-43a9-8509-61032f858835','凝翠西峰','陈渊','宋','宋诗','song-poetry','','[]','西峰高且峻，下有祈靈祠。',24,'全唐诗/poet.song.93000.json','["西峰高且峻，下有祈靈祠。", "來游適公暇，細和梁翁詩。"]'),
('45a13bde-9cb1-4259-a9aa-5292f9f7eaa4','碧雲峰','陈渊','宋','宋诗','song-poetry','','[]','碧雲高出山，飄如翠鸞舞。',24,'全唐诗/poet.song.93000.json','["碧雲高出山，飄如翠鸞舞。", "萬里從飛龍，八方望霖雨。"]'),
('da09cc53-a64b-4150-8f69-21e4ee2f14da','己亥秋陪伯山遊中條窮盡山中之勝明年春迓王毅伯再過山下呈伯山','趙鼎','宋','宋诗','song-poetry','','[]','條山有佳色，不入俗子眼。',288,'全唐诗/poet.song.93000.json','["條山有佳色，不入俗子眼。", "結廬傍洓水，永與山作伴。", "一脚落宦遊，坐歎千里遠。", "長恐山靈檄，重令猿鶴怨。", "朅來河之湄，用意固不淺。", "擬從水石行，稍釋煙霞戀。", "而於闤闠中，舉首即相見。", "相看猶有情，不改舊顔面。", "自憐非故吾，撫心祗媿赧。", "唯公絕俗姿，體道任舒卷。", "笑揖浮邱伯，雙鳬脱覊絆。", "步武招我陪，放歌容我亂。", "窅窕空翠間，風馭躡雲棧。", "山亦爲君容，景態互明煥。", "别去今幾時，茲遊倐飛電。", "所思在巖壑，欲往不得便。", "此身被官縛，事廹胡可緩。", "東風漲邊塵，羸馬注長坂。", "崎曲餘百里，盡日期往返。", "問途策而前，不復微吟款。", "向來經行處，猶作生綃展。", "悵念捫蘿手，去斂趨庭板。", "忽放微雲開，顧我一笑筦。", "出没高樹端，退避還偃蹇。"]'),
('f50d1649-f155-4104-b898-4a2dee094b49','陪王毅伯遊柏梯寺次毅伯韻','趙鼎','宋','宋诗','song-poetry','','[]','伊昔耐辱人，誅茅此山谷。',240,'全唐诗/poet.song.93000.json','["伊昔耐辱人，誅茅此山谷。", "愛閑如愛官，食薇如食肉。", "酌泉吸山光，清泠飽空腹。", "故居今宛然，修篁蔽山麓。", "我亦困塵籠，暮年思退縮。", "道人梯柏處，夢想長在目。", "崎嶇乃夙心，寧問隘車轂。", "危蹬亂水石，悲風號竹木。", "款步轉嶔岈，舉頭蒙樸蔌。", "徑欲走其顛，仰羨孤飛鶩。", "層峰擁户來，何啻三十六。", "幽人豈知此，相對一茅屋。", "真成拓異境，不勝無遺鏃。", "夜枕却生寒，尚煩盃酒燠。", "清夢那得長，魚鼓驚晨粥。", "五老曉相迎，霧雨如盥沐。", "引我眺北嶺，坐覺天宇蹙。", "朝日湧地低，明霞疑可掬。", "欲留採黄精，媿此鬢髪秃。", "正恐泛槎星，已見君平卜。"]'),
('1d910b1e-b639-4ea2-8c2b-0421e3cdf73c','次韻','趙鼎','宋','宋诗','song-poetry','','[]','平生隱遁資，白駒在空谷。',240,'全唐诗/poet.song.93000.json','["平生隱遁資，白駒在空谷。", "儻令眼有山，寧問食無肉。", "要當揖爽氣，滌此勤書腹。", "得官大河濱，枕带首陽麓。", "如聞五老勝，坐使山峰縮。", "捫蘿上巉絕，作意快心目。", "却視宇宙間，萬化轉一轂。", "道人真有道，直上駕危木。", "神光秘巖隈，靈草蒙樸蔌。", "空令蓮社子，紛擾亂鳬鶩。", "先生志高古，真遊窮六六。", "飄然清夜夢，時到山頭屋。", "念此感塵迹，一往如飛鏃。", "哦詩示觀覽，律呂回春燠。", "作字紀經行，典刑餘食粥。", "使我蒙鄙心，蓬首加櫛沐。", "致我外塵垢，益歎生理蹙。", "夜潄落箭泉，明月冷盈掬。", "朝飰過靈峰，何憚屐齒秃。", "茲焉畢餘齡，更無疑可卜。"]'),
('04ec584e-66b1-4103-abe7-8498995afe66','再次韻','趙鼎','宋','宋诗','song-poetry','','[]','蒼顔五老人，潛此十里谷。',240,'全唐诗/poet.song.93000.json','["蒼顔五老人，潛此十里谷。", "孤標面有稜，瘦骨饑無肉。", "手揮雲霧開，絕澗坦其腹。", "乃知奇偉狀，未省出山麓。", "窮幽偶見之，欲遁不及縮。", "亦憐麋鹿資，笑睨回青目。", "政欲挽渠衣，未應回我轂。", "卻顧巖壑底，鬱鬱聳喬木。", "尚茲遺棟梁，况乃問樸蔌。", "我亦脱網羅，江湖漾孤鶩。", "念此難折腰，本無蘇印六。", "何意從公遊，大嚼渠渠屋。", "公仍爲銷寫，妙語矜破鏃。", "一看雲卧冷，固鄙權門燠。", "懸知飯藜羹，不換咄嗟粥。", "笑我漫彈冠，短髪不勝沐。", "真恐緣壁枯，莫作蝸行蹙。", "但當葺詩業，萬象入吾掬。", "要與麯生狂，一掃中書秃。", "此計是耶非，更擬從公卜。"]'),
('b7d5da75-1733-420e-8252-a0d8c95eda41','王官谷夜歸次伯山韻','趙鼎','宋','宋诗','song-poetry','','[]','讀公出谷詩，語峻有骨肋。',36,'全唐诗/poet.song.93000.json','["讀公出谷詩，語峻有骨肋。", "使我兩目明，燭籠照昏黒。", "欲和輙復已，夜漏下幾刻。"]'),
('b73010fb-267a-41ad-8d6e-fea2c6cd287b','出郭次伯山韻','趙鼎','宋','宋诗','song-poetry','','[]','道心日和平，向人絕城府。',36,'全唐诗/poet.song.93000.json','["道心日和平，向人絕城府。", "雅意在泉石，外物等泥土。", "終尋勾漏公，丹砂養龍虎。"]'),
('96ce2fcd-2680-410a-848c-67d3429b7d3c','欲遊静林不果','趙鼎','宋','宋诗','song-poetry','','[]','林泉共一山，欲往不得暇。',36,'全唐诗/poet.song.93000.json','["林泉共一山，欲往不得暇。", "我不如陶生，日到遠公社。", "安得縮地術，坐我雲門下。"]'),
('3f8398dd-8602-4538-b395-99b4ac0d7cdf','翠微閣','趙鼎','宋','宋诗','song-poetry','','[]','秋山插半空，山半倚危閣。',36,'全唐诗/poet.song.93000.json','["秋山插半空，山半倚危閣。", "游子山下行，秦川正搖落。", "日暮天宇寛，西風卷雲幕。"]'),
('b5df28eb-ca1a-4793-af15-2482196b0e84','南泉','趙鼎','宋','宋诗','song-poetry','','[]','陰液淪山顛，天匠鑿其腹。',48,'全唐诗/poet.song.93000.json','["陰液淪山顛，天匠鑿其腹。", "噴薄湧飛泉，散落珠百斛。", "幽人時一來，但愛消煩溽。", "何當作膏雨，萬里蒙霡霂。"]'),
('b773fcf6-921e-4167-a809-8ebb2762cb36','還城次必强韻','趙鼎','宋','宋诗','song-poetry','','[]','俗駕不可留，歸途無乃遽。',36,'全唐诗/poet.song.93000.json','["俗駕不可留，歸途無乃遽。", "未飽愛山心，復踏還城路。", "今彼城中人，朝暮催鐘鼓。"]'),
('b18c1df7-0729-4b90-93d7-b3e0c70d41f0','獨樂園夜飲梅花下再賦','趙鼎','宋','宋诗','song-poetry','','[]','我有一樽酒，爲君消百憂。',120,'全唐诗/poet.song.93000.json','["我有一樽酒，爲君消百憂。", "當春梅盛發，去作花間遊。", "嫦娥從東来，愛此亦遲留。", "便欲買花去，玉玦戀枝頭。", "花動月光亂，月移花影流。", "橫斜滿盃盤，酒面香浮浮。", "舉觴吸明月，與花相勸酬。", "君若不盡飲，恐爲花月羞。", "緬想李太白，對酒無朋儔。", "當時明月下，還有此花不。"]'),
('3c795cba-54c8-4c9c-b4f0-cadf03b44156','次韻酬贈元長少卿','趙鼎','宋','宋诗','song-poetry','','[]','夫子稟家學，玉德潤無色。',48,'全唐诗/poet.song.93000.json','["夫子稟家學，玉德潤無色。", "搢紳先生間，早歲聲籍籍。", "晚乃落筌蹄，雲空鳥滅跡。", "功名翰墨場，一笑兒時劇。"]'),
('2710f590-0fbb-4294-94b6-9eeab3141714','寄贈向叔美二首  其一','趙鼎','宋','宋诗','song-poetry','','[]','夫子冰玉質，未肯汚膏粱。',48,'全唐诗/poet.song.93000.json','["夫子冰玉質，未肯汚膏粱。", "坐此困州縣，一飽猶皇皇。", "懷才幾時用，鬢髪行老蒼。", "今世無伯樂，不識真乘黄。"]'),
('a6b98a03-8637-4b4f-aa2e-ecb81f53c6ff','寄贈向叔美二首  其二','趙鼎','宋','宋诗','song-poetry','','[]','結交恨不早，天意非人謀。',48,'全唐诗/poet.song.93000.json','["結交恨不早，天意非人謀。", "論文一樽酒，邂逅古虞州。", "我嘗評其人，請從前輩求。", "紛紛此薄俗，定将誰與儔。"]'),
('b2cd70ee-936b-4166-9046-693fa8a91739','夢覺一首時將解安邑赴調','趙鼎','宋','宋诗','song-poetry','','[]','明月入破窗，一室炯如曉。',240,'全唐诗/poet.song.93000.json','["明月入破窗，一室炯如曉。", "幽人睡易驚，遙夜正寒悄。", "自緣懷抱惡，安得夢寐好。", "推枕惘不樂，念念墮空杳。", "所思天一涯，忽忽令人老。", "老境足悲傷，窮愁更縈繞。", "嗟余竟奚爲，濫爲策名早。", "漫浪戲一官，不覺成潦倒。", "况此百日中，隨分接紛擾。", "跧如轅下駒，孤甚沙洲鳥。", "未妨公事多，但使癡兒了。", "州縣定勞人，侏儒尚能飽。", "毋作腐鼠嚇，要同牛驥皂。", "更憐愛酒陶，未免空嚢趙。", "去矣莫留行，峥嶸歲云杪。", "三宿戀桑下，千載歸華表。", "更堪無定居，驚飈轉蓬葆。", "卧聞南飛鵲，悲鳴樹三遶。", "念爾將安之，天闊風霜渺。", "不如刷勁翮，去躡鴻鵠矯。"]'),
('7747a675-78fe-4978-b159-0d087f7be21a','龜山寺詩','趙鼎','宋','宋诗','song-poetry','','[]','夕照銜半壁，煙霏淡横練。',156,'全唐诗/poet.song.93000.json','["夕照銜半壁，煙霏淡横練。", "呼風掛帆席，晚著淮東岸。", "波流蕩伏龜，山脚插秋漢。", "白塔欻飛動，紺宇鎖華煥。", "小閣候潮平，微徑依山轉。", "雲林杳靄間，歷歷皆奇觀。", "十年客京洛，每抱轅駒歎。", "何意頓蕭然，朝來舟出汴。", "眼界霄壤分，骨相仙凡換。", "鱸從秋後肥，米到淮南賤。", "幸脫兵火餘，苦爲塵網絆。", "滄海寄餘齡，去此不難辦。", "招邀謫仙人，騎鯨遊汗漫。"]'),
('c6164155-d59b-4236-ab52-069882720993','儀真宫玉清昭應宫成鑄聖像於此','趙鼎','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','樓觀俯長江，竹樹蔽修嶺。',144,'全唐诗/poet.song.93000.json','["樓觀俯長江，竹樹蔽修嶺。", "入門却立驚，清曠非人境。", "福地包形勝，真儀入範鎔。", "護持國祚永，報貺年穀豐。", "蓬萊杳莫尋，弱水三萬里。", "我欲試丹訣，誅茅或在此。", "神僊可學否，要且扶頺齡。", "生當兵火日，飄泊安得寧。", "愛之不可留，弛擔休信宿。", "白鶴唳石壇，香煙遶雲屋。", "夜久萬籟息，松風度玉琴。", "瀟然不能寢，相伴一哀吟。"]'),
('1b5e507b-b5e6-4a00-a69c-bbefb0574e15','舟行著淺夜泊中流','趙鼎','宋','宋诗','song-poetry','','[]','雪漲秦淮水，春生白鷺洲。',192,'全唐诗/poet.song.93000.json','["雪漲秦淮水，春生白鷺洲。", "洲前棹歌發，送此一葉舟。", "轉柂起帆席，快甚誰能収。", "舟師拙於事，遂作中灘留。", "支撐莫動搖，喘汗徒呀咻。", "彈繩測河道，篙竿伺潮頭。", "疏篷雞栅低，兀坐如拘囚。", "仰羨雙飛鵠，安得從之遊。", "日落暮雲碧，波光澹如秋。", "四顧渺無極，黯黯令人愁。", "黒風卷半夜，大浪掀中流。", "傲兀不能寢，取酒聊相酬。", "人生天地間，大海一浮漚。", "風水審如此，蛟龍應見求。", "未脫干戈地，敢爲身世謀。", "醉酣還就枕，吾已信沉浮。"]'),
('5e947ab1-1aa4-4dc9-a69a-2e613f3e1395','吳帝廟','趙鼎','宋','宋诗','song-poetry','','[]','阿瞞鬼之雄，掌握弄神器。',120,'全唐诗/poet.song.93000.json','["阿瞞鬼之雄，掌握弄神器。", "孫劉相繼踵，分争足鼎峙。", "支吾僅自保，終作降囚系。", "智力非不如，亦各論其地。", "吾聞隆凖公，幾爲强楚斃。", "轉粟收散兵，正賴關中勢。", "中原乃腹心，四肢吾所制。", "英雄建立初，豈但夸一世。", "處之或不然，果非長久計。", "古人今復生，此論無以異。"]'),
('3fcf6e5e-e3db-417f-aa75-f7a9b9f49090','泊震澤道中步游善宥寺觀芍藥回舟中小飲用范四韻','趙鼎','宋','宋诗','song-poetry','','[]','非才與時背，空手行路難。',204,'全唐诗/poet.song.93000.json','["非才與時背，空手行路難。", "朱門極嚴冷，仰首不可干。", "初欲効寸進，挽舟八節灘。", "雅意同心人，贈之雲錦端。", "雖云食破硯，渇擬回狂瀾。", "胸次竟莫吐，千丈虹蜺蟠。", "誰復議行藏，浩歌空倚欄。", "南來寄疏蓬，蝦菜豈所歡。", "尋幽偶一笑，芳葩發奇觀。", "念爾託根遠，香色不易完。", "姓名逋客晦，風味書生酸。", "作詩慰流落，激烈窮雕刓。", "愁人多苦語，步遶吟且看。", "歸懷止惋結，賴此杯酒寛。", "忽忽時歲邁，凄凄風雨殘。", "曷當三徑歸，暫卜一枝安。", "寵辱何定物，向來心已闌。"]'),
('0d8cf704-d777-498c-9043-8151b62675ee','過平望趨吳興阻風遊殊勝寺用益謙韻','趙鼎','宋','宋诗','song-poetry','','[]','羃羃疏雨歇，冷冷晚風清。',168,'全唐诗/poet.song.93000.json','["羃羃疏雨歇，冷冷晚風清。", "扁舟泊清淺，落日涵空明。", "門臨稻畦沒，水浸莎岸平。", "欠伸得寛曠，杖屨喜微行。", "招提掩深靚，房户開斜横。", "紛紛諸衲子，尚作迎送情。", "神武行掛冠，吳市今變名。", "及聞名理談，頓覺肝膽傾。", "凡籠了無著，古佛當自成。", "已復外身世，何者爲官榮。", "同遊有亞父，早定登壇盟。", "歸來不受賞，慨慷羞論兵。", "閭閻取封侯，健兒勝書生。", "因之發深省，種種鴻毛輕。"]'),
('1094689c-617d-41ef-8e19-ee662558d2da','過子陵灘題僧舍壁','趙鼎','宋','宋诗','song-poetry','','[]','山水莽回互，轉眄圖畫間。',204,'全唐诗/poet.song.93000.json','["山水莽回互，轉眄圖畫間。", "念此清絕地，昔人所盤旋。", "舟子相歎嗟，示余子陵灘。", "有臺出山半，藤蘿蒙蘚斑。", "緬想建武功，用人及茅菅。", "躐取汝潁士，列宿樞極環。", "中有貧賤交，客星犯帝關。", "其能榮辱之，但及平生懽。", "志願乃有在，歸歟一漁竿。", "高風邈千載，獨立誰躋攀。", "山僧本何知，結屋臨清灣。", "笑謂舟中客，何爲争嶮艱。", "權門有遺啄，造請無寒暄。", "囁嚅到童僕，俛仰慚衣冠。", "所得諒幾何，赩汗流面顔。", "偃鼠不過飽，鷦鷯亦求安。", "子能了此義，分子一席閑。"]'),
('668fd316-bdff-47d8-acc4-27ed36d15cfe','奉送呂若谷縣丞任蒲東歸五首  其一','趙鼎','宋','宋诗','song-poetry','','[]','著鞭愧後發，挾矢争先登。',48,'全唐诗/poet.song.93000.json','["著鞭愧後發，挾矢争先登。", "肯顧危機在，尚以智力矜。", "曷不往試之，投足還兢凌。", "寄謝婁羅兒，老矣病未能。"]'),
('eeab9641-c098-459e-94a3-b2ea2f74eb91','奉送呂若谷縣丞任蒲東歸五首  其二','趙鼎','宋','宋诗','song-poetry','','[]','三年巽亭上，看盡洛中山。',48,'全唐诗/poet.song.93000.json','["三年巽亭上，看盡洛中山。", "山亦爲君好，朝昏圖畫間。", "那知張季鷹，高興不可攀。", "忽見秋風起，東隨洛水還。"]'),
('772931fb-1bd9-4427-bf5e-279a3cf38cd0','奉送呂若谷縣丞任蒲東歸五首  其三','趙鼎','宋','宋诗','song-poetry','','[]','巽也幕府舊，阿升交分深。',48,'全唐诗/poet.song.93000.json','["巽也幕府舊，阿升交分深。", "與君均骨肉，况乃相知心。", "遽復捨我去，倍覺傷離衿。", "高亭東望眼，從此費登臨。"]'),
('bad90e66-6b90-4e21-91fb-4f65b1ca8f0c','奉送呂若谷縣丞任蒲東歸五首  其四','趙鼎','宋','宋诗','song-poetry','','[]','夫子有高趣，一官聊爾耳。',48,'全唐诗/poet.song.93000.json','["夫子有高趣，一官聊爾耳。", "獨騎破虎韉，憔悴洛城裏。", "緬想文穆公，青嵩照伊水。", "百年風烈在，須公一振起。"]'),
('4f741026-52c7-466e-8c43-350deda2cfd2','奉送呂若谷縣丞任蒲東歸五首  其五','趙鼎','宋','宋诗','song-poetry','','[]','忽忽歲華暮，悠悠心事違。',48,'全唐诗/poet.song.93000.json','["忽忽歲華暮，悠悠心事違。", "此行元自懶，前計頗知非。", "公有酒堪隱，我無田可歸。", "月明枝未穏，誰念鵲孤飛。"]'),
('d90481e4-2910-4683-90f2-c75c7e0771fd','真率會諸公有詩輙次其韻','趙鼎','宋','宋诗','song-poetry','','[]','山林與鐘鼎，出處無異趣。',240,'全唐诗/poet.song.93000.json','["山林與鐘鼎，出處無異趣。", "芻豢等藜藿，同是一厭飫。", "此心無適莫，外物曾何忤。", "奚獨淡交遊，未肯厠紈袴。", "故尋漫浪人，要作尋常聚。", "主既不速客，客亦隨即赴。", "傾談劇懸河，瀉酒快流霔。", "百年人醉醒，萬物皆僑寓。", "云何造請門，日滿户外屨。", "却想耆英遊，風流甚寒素。", "淡然文字歡，一笑腥膻慕。", "我亦蹭蹬餘，早向危機悟。", "絕意鴛鷺行，幸此松蘿附。", "君詩妙鋪寫，縱横俱中度。", "我老學荒廢，一詞不能措。", "獨於樽酒間，不惜淋灕汚。", "何當賦歸歟，去斂頭角露。", "家有譍門兒，稍能隨指顧。", "鷄黍林下期，視此猶應屢。", "有興即放言，安能限章句。"]'),
('ae46716c-ebed-401f-bcf8-190066ad1c3f','寄金陵諸幼','趙鼎','宋','宋诗','song-poetry','','[]','去年都城開，南下相繼踵。',96,'全唐诗/poet.song.93000.json','["去年都城開，南下相繼踵。", "我亦具扁舟，携汝百指衆。", "汝寧爲我累，我獨於汝重。", "今而暫相遠，愁亦慮汝共。", "因人問在否，未語先悸恐。", "淚下復吞聲，寢愕不成夢。", "倘有相見期，勿復藉官俸。", "一飽不求餘，去辦南山種。"]'),
('9627d00c-6630-43b6-8064-4b9f55b0b038','乙巳二月初八日集獨樂園夜飲梅花下會者宋退翁胡明仲馬世甫張與之王子與林秀才及余凡七人以炯如流水涵青蘋爲韻賦詩分得流字','趙鼎','宋','宋诗','song-poetry','','[]','孟公飲狂車轄投，不適遂與俗沉浮。',386,'全唐诗/poet.song.93000.json','["孟公飲狂車轄投，不適遂與俗沉浮。", "謫仙醉吟驚冕旒，氣侮權倖無悔尤。", "不如淵明此意俱悠悠，飄然不繫之虚舟。", "偃蹇不從刺史遊，遇酒或能道上留。", "介不爲高通不偷，亦知出處非人謀。", "人生一世罹百憂，驚風變滅波上漚。", "胡爲滯此胸中愁，聖賢清濁皆友儔。", "九老前塵邈難求，七交高躅或可侔。", "百年典刑今在不，振起此風須此流。", "亭亭玉立郡督郵，文采秀發中甚遒。", "絳帳先生兩清修，和音相答鳴琳球。", "靖居之孫髯而脩，昂藏野鶴横高秋。", "林生風度和且柔，抗論直欲輕王侯。", "河南遊刃无全牛，弟兄傳家才術優。", "老成不堪冠屨囚，人憐拙甚營巢鳩。", "覊窮動輙遭寇讎，但欲縮首眠黄紬。", "何意獨蒙公等收，歡然一笑回青眸。", "空囊未分一錢羞，典衣猶得事勸酬。", "南州竹樹相庇庥，步隨流水尋清幽。", "尚嫌白日多喧啾，少待月出東南陬。", "黄梅一株香颼飀，青蘋浮水涵春洲。", "那知落雪紛滿頭，但覺香露沾衣裘。", "一釂百罰寧論籌，嗚嗚自作秦人謳。", "快談慨慷雜嘲咻，凜如武庫森戈矛。"]'),
('59bb63b3-4d95-474f-af68-2ae35ff2dcd0','次韻退翁遊北山之什','趙鼎','宋','宋诗','song-poetry','','[]','孤雲天末山數峰，峰頭隱隱銜烏龍。',288,'全唐诗/poet.song.93000.json','["孤雲天末山數峰，峰頭隱隱銜烏龍。", "遙臨北嶺望故國，行歌負販舟車通。", "時當高秋雨霜後，木葉紛亂號悲風。", "聲華一夢水流去，名跡千古山争穹。", "津橋煙草闕雙峙，馳道莓苔門九重。", "鳴鑾飈馭杳何許，蓬萊頂上雲濛濛。", "徒驚朝市屢更變，遑問邱壠多英雄。", "鼎湖龍去自不返，非煙長鎖琉璃宫。", "當年真聖受天命，香生菡萏祥光紅。", "宫前父老尚能說，顧瞻遺宇悲涕中。", "橋山松柏閟弓劍，有時寶氣飛長虹。", "今主紹述更神武，回眸一視雲煙空。", "請封章疏幾時上，振蹕行聞來自東。", "功成亦念剏基業，從此不復言兵戎。", "我生多難傷暌離，茫然却顧當何歸。", "伏轅不作馬思奮，塌翼應憐鳥倦飛。", "臨風且共一盃酒，要看酒面吹瀾漪。", "不湏遐想念今昔，吾廬好在尋歸期。"]'),
('89a129dd-b1a3-4d32-b1a6-25030d9052ec','雪中獨坐退翁索詩','趙鼎','宋','宋诗','song-poetry','','[]','東風解放狂花飛，何乃尚容寒作威。',64,'全唐诗/poet.song.93000.json','["東風解放狂花飛，何乃尚容寒作威。", "了無賓客共携酒，更有人家來索詩。", "天高雲漏不遮月，皎潔上下同澄輝。", "亭前有樹高百尺，爲借驚烏安一枝。"]'),
('3a86f958-d6b9-4214-a7e4-f8918b445822','戊申正月行在參吏部示諸幼','趙鼎','宋','宋诗','song-poetry','','[]','秋風鼓棹長蘆渡，吾與若曹俱豁然。',208,'全唐诗/poet.song.93000.json','["秋風鼓棹長蘆渡，吾與若曹俱豁然。", "脫跡干戈玩清絕，収身溝壑厭肥鮮。", "折腰爲米豈所願，賣劍買牛端可賢。", "韓公雅欲却窮鬼，趙壹其如無一錢。", "罷官清坐乃吾分，號寒啼饑誰汝憐。", "政緣茲事藉升斗，使我不得休林泉。", "日下揚州行在所，寸長片善希陶甄。", "汗衣塵帽門户底，包羞忍耻王公前。", "此行寧復作此態，疇昔相知吏部銓。", "謹嚴資格可馴致，雖甚不才無棄捐。", "我已投誠永結好，相從綠髪至華顛。", "矧復鴛鷺滿臺閣，功名合在中興年。", "縮頭袖手正應爾，敢問祖生先著鞭。"]'),
('62ec3393-c2d3-45cb-8c13-a41983f30c37','京師次韻邵澤民憶擬江梅花','趙鼎','宋','宋诗','song-poetry','','[]','憶並條山訪雲屋，渡水涼飈散芬馥。',64,'全唐诗/poet.song.93000.json','["憶並條山訪雲屋，渡水涼飈散芬馥。", "一枝璀璨端可人，步遶微吟揩病目。", "作意題詩向我夸，只今窗户知誰家。", "伶俜瘦馬京塵惡，障面羞看檐上花。"]'),
('303c035d-51aa-4479-b66b-da8ea3bca24a','役所寒食即事','趙鼎','宋','宋诗','song-poetry','','[]','疲民正苦淘泥沙，彼何人兮怒且譁。',64,'全唐诗/poet.song.93000.json','["疲民正苦淘泥沙，彼何人兮怒且譁。", "麄狂不肯道姓字，呼前醉態猶欹斜。", "自言寒食身無事，快意欲嚼遑恤他。", "覊愁我自感節物，遣去不問徒咨嗟。"]'),
('678d27b2-a248-4dcc-936e-87fa6f3d50ff','余去秋七月登舟逮此一年矣六月晦日午睡覺聞兒女輩相謂曰眀朝又是秋風起推枕悵然走筆記之','趙鼎','宋','宋诗','song-poetry','','[]','流萍斷梗飛花委，四海茫然無定止。',96,'全唐诗/poet.song.93000.json','["流萍斷梗飛花委，四海茫然無定止。", "古今本是一郵傳，况乃其中悲轉徙。", "秦淮霜葉亂楓林，苕霅春風泛蘋芷。", "薄酒時時伴兒女，疏篷處處愁烟水。", "故鄉知是幾長亭，眼暗相望越千里。", "悵念征鴻一紙書，明朝江上秋風起。"]'),
('5e9a4309-283a-4e4e-b297-fb4e6292fd4e','泊桐廬縣合江亭下昔有得道之士不知姓名結廬山間手植桐數本因謂之桐君縣亦以此得名','趙鼎','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','桐廬縣前江合流，合江亭下多客舟。',64,'全唐诗/poet.song.93000.json','["桐廬縣前江合流，合江亭下多客舟。", "紅樓參差出木末，小市宛轉依巖陬。", "桐君手植碧桐樹，歲歲春風柯葉柔。", "白雲一去鳳不至，暮雨丁零生客愁。"]'),
('4f2ad9f0-d3a1-4ee6-9f26-0a170cd95608','舟中呈耿元直','趙鼎','宋','宋诗','song-poetry','','[]','念昔一笑相逢初，我時尚少君壯夫。',192,'全唐诗/poet.song.93000.json','["念昔一笑相逢初，我時尚少君壯夫。", "十年再見輦轂下，我鬢斕斑君白鬚。", "落魄朋遊嗟我在，艱難兵火與君俱。", "酬恩未擬填溝壑，强顔忍復陪簮裾。", "浩然胡不徑投劾，老矣難堪歸荷鋤。", "田園墳壠亂戎馬，是身是處長羈孤。", "解維汴岸一篙水，小舟漂兀如鷖鳬。", "對床推枕坐歎息，此行未肯悲窮途。", "胸中炯炯時一吐，與生俱坐寧籧除。", "只今雲臺羅俊彦，鄙賤老醜憎樸疏。", "躍馬食肉付公等，浮家泛宅真吾徒。", "與君轉柂從此逝，秋風萬里吹江湖。"]'),
('c7b38c5c-d7ee-4bbe-8624-da41d74fa9cd','閱陶集偶有所感','趙鼎','宋','宋诗','song-poetry','','[]','彭澤縣令八十日，束帯耻爲升斗汚。',64,'全唐诗/poet.song.93000.json','["彭澤縣令八十日，束帯耻爲升斗汚。", "二十四考中書令，端委廟堂揮不去。", "兩公於此固無心，鐘鼎山林隨所寓。", "慎勿蹉跎兩失之，歲晚要尋栖息處。"]'),
('fdbc7395-73d8-4b62-bf8a-867eb3c95a9f','謝人惠麥穗','趙鼎','宋','宋诗','song-poetry','','[]','愚軒卧病空瓶儲，市米不得如求珠。',160,'全唐诗/poet.song.93000.json','["愚軒卧病空瓶儲，市米不得如求珠。", "鄰翁餽麥穗盈筥，或揉或簸喧庭除。", "磨雷隱隱破霜瓣，家童執爨煙生廚。", "須臾粥成勸我食，齊眉舉案煩妻孥。", "病餘聊復潤喉吻，軟滑盈盈如膏酥。", "宛然長粳欲争長，加以白豆爲參輿。", "童兒作顰若不足，老夫大笑爲有餘。", "虎頭食肉非不美，回視利害爲何如。", "平生不耕啖此物，壠頭汗滴慚耕夫。", "淡中有味足養福，爲君努力餐一盂。"]'),
('0f6928c5-7e33-4290-91ce-8df70a61f6b5','車駕還汴','趙鼎','宋','宋诗','song-poetry','','[]','孝感天心格，憂勤國步艱。',48,'全唐诗/poet.song.93000.json','["孝感天心格，憂勤國步艱。", "賈生休賦鵩，貢禹欲彈冠。", "白髪他鄉客，清尊此夕懽。", "如聞京兆尹，拜表請回鑾。"]'),
('69695f5c-011e-49ce-af1e-6bd732a4ec1d','圍城次退翁韻','趙鼎','宋','宋诗','song-poetry','','[]','甲馬分諸道，舟車會此都。',48,'全唐诗/poet.song.93000.json','["甲馬分諸道，舟車會此都。", "前王端有意，異世肯同途。", "人物風流盡，公私府庫虚。", "百年餘故老，相遇涕漣如。"]'),
('95314378-b6e8-45c1-a826-ff31abdde540','將歸先寄諸幼','趙鼎','宋','宋诗','song-poetry','','[]','擾擾干戈地，懸懸父子情。',48,'全唐诗/poet.song.93000.json','["擾擾干戈地，懸懸父子情。", "人間正多故，身外復何營。", "我已忘官寵，兒須辦力耕。", "歸家休歇處，團坐話無生。"]'),
('88c4b459-0938-415f-a36a-67a3b632cf51','還家示諸幼','趙鼎','宋','宋诗','song-poetry','','[]','避地重遭亂，還家幸再生。',48,'全唐诗/poet.song.94000.json','["避地重遭亂，還家幸再生。", "一身今見汝，寸祿敢留情。", "更恐死生隔，渾疑夢寐驚。", "吾今猶有愧，未遂鹿門耕。"]'),
('ba839c70-b61f-4b32-a8bc-53e1ba320166','還家','趙鼎','宋','宋诗','song-poetry','','[]','但切思家念，那知行路難。',48,'全唐诗/poet.song.94000.json','["但切思家念，那知行路難。", "盃盤無作具，菽水自加餐。", "竹老風聲勁，山深夜氣寒。", "肯教孤枕夢，容易到長安。"]'),
('8a469e10-a803-4987-8b4c-cfbfd8e7f766','馬靖國後軒','趙鼎','宋','宋诗','song-poetry','','[]','性静交遊少，身閑日月長。',48,'全唐诗/poet.song.94000.json','["性静交遊少，身閑日月長。", "忘言千句偈，宴坐一爐香。", "世有流離苦，人趨聲利塲。", "此間亦何事，高卧傲羲皇。"]'),
('dc3251ca-99ea-47cd-a8a4-2578b4659916','蒲中次韻提舉趙正之秦亭唱和五首  其一','趙鼎','宋','宋诗','song-poetry','','[]','雲端貝闕見，鼇負海山來。',48,'全唐诗/poet.song.94000.json','["雲端貝闕見，鼇負海山來。", "瑞氣元非霧，天風不染埃。", "頒常八柱建，象魏五門開。", "肯構經營念，貽謀丕顯哉。"]'),
('b6842c7f-a723-49df-83ab-f35261804e15','蒲中次韻提舉趙正之秦亭唱和五首  其二','趙鼎','宋','宋诗','song-poetry','','[]','丁丁谷聲響，泛泛棹歌來。',48,'全唐诗/poet.song.94000.json','["丁丁谷聲響，泛泛棹歌來。", "净港時吹浪，中流或起埃。", "亦知從地出，幾若鑿山開。", "帝室須梁棟，斯功當念哉。"]'),
('b56274e4-bdaa-49a3-9ec9-b3846b25c8c5','蒲中次韻提舉趙正之秦亭唱和五首  其三','趙鼎','宋','宋诗','song-poetry','','[]','隴樹迎人去，關雲逐馬來。',48,'全唐诗/poet.song.94000.json','["隴樹迎人去，關雲逐馬來。", "凄風搖白草，落日蔽黄埃。", "仗節身方遠，逢山眼暫開。", "却臨分水處，蜀道賦高哉。"]'),
('9b85744d-369a-475b-9da3-574dbeba6073','蒲中次韻提舉趙正之秦亭唱和五首  其四','趙鼎','宋','宋诗','song-poetry','','[]','要作哦詩伴，何妨結駟來。',48,'全唐诗/poet.song.94000.json','["要作哦詩伴，何妨結駟來。", "瓊林有餘韻，水檻絕纖埃。", "醉膽江山闊，吟毫花草開。", "只應聞雁夜，夢枕思悠哉。"]'),
('983a9126-cece-431c-b9b0-2cbf59bffa8c','蒲中次韻提舉趙正之秦亭唱和五首  其五','趙鼎','宋','宋诗','song-poetry','','[]','追隨六郡子，深入塞雲來。',48,'全唐诗/poet.song.94000.json','["追隨六郡子，深入塞雲來。", "關路春飛雪，沙塲夜漲埃。", "戲圍千騎獵，笑挽六鈞開。", "歷歷經遊處，初心已矣哉。"]'),
('3f66c78d-1435-4537-930b-c6b975b555ba','再到蒲中遊穆氏園','趙鼎','宋','宋诗','song-poetry','','[]','懷感花無數，其時春正深。',48,'全唐诗/poet.song.94000.json','["懷感花無數，其時春正深。", "如今重對酒，感舊獨傷心。", "山鳥那知此，向人猶好音。", "東城多樂事，疇昔共幽尋。"]'),
('c282f75c-f024-45ab-a0d4-03b3bc79a0e5','贈普照監院','趙鼎','宋','宋诗','song-poetry','','[]','飄泊嗟何往，歸來恨莫從。',48,'全唐诗/poet.song.94000.json','["飄泊嗟何往，歸來恨莫從。", "師猶作秦語，我已效吳儂。", "水淺長河浪，山低太華峰。", "幾時携手去，南北本同宗。"]'),
('ed537387-1f1c-438a-b47d-fc3dec36c059','六合縣相僧','趙鼎','宋','宋诗','song-poetry','','[]','門外江南道，瀟然誰與同。',48,'全唐诗/poet.song.94000.json','["門外江南道，瀟然誰與同。", "禅心達生死，道眼識窮通。", "聊爲機緣起，懸知色相空。", "有人真勇退，不到急流中。"]'),
('33a74b43-8875-4752-9a16-3559aaf4dd04','中秋呈元長  其一','趙鼎','宋','宋诗','song-poetry','','[]','江上中秋月，天邉白髪翁。',48,'全唐诗/poet.song.94000.json','["江上中秋月，天邉白髪翁。", "一輪還自滿，千里共誰同。", "擾擾干戈後，栖栖羈旅中。", "持盃那復問，一釂百分空。"]'),
('4e3e14e3-cb41-4371-a830-750a6f876820','中秋呈元長  其二','趙鼎','宋','宋诗','song-poetry','','[]','誰作清光伴，瀟然属兩翁。',48,'全唐诗/poet.song.94000.json','["誰作清光伴，瀟然属兩翁。", "他鄉多病後，竟夕一樽同。", "孤杵征衣淚，寒沙戰角風。", "何由遂心賞，幽思渺秋空。"]'),
('67bdad42-05bd-4923-bd19-906ba1ccc33b','中秋醉後','趙鼎','宋','宋诗','song-poetry','','[]','顧影不成舞，披襟欲御風。',48,'全唐诗/poet.song.94000.json','["顧影不成舞，披襟欲御風。", "人憐經歲别，月與舊時同。", "鶴警露華白，魚潛水鑑空。", "舉盃還徑醉，歸夢廣寒宫。"]'),
('e0ef01f5-f24d-4ef4-9f26-18ce7896506d','九日置酒坐上呈元長','趙鼎','宋','宋诗','song-poetry','','[]','未厭山林僻，那知節序遷。',48,'全唐诗/poet.song.94000.json','["未厭山林僻，那知節序遷。", "高閑愛重九，安健又今年。", "物外無韁鎖，樽中有聖賢。", "黄花自衰晚，勿復笑華顛。"]'),
('8fa6aa3a-c700-4ca1-ab79-480ad96d387a','毗陵道中','趙鼎','宋','宋诗','song-poetry','','[]','烟水毗陵道，光涵落月空。',48,'全唐诗/poet.song.94000.json','["烟水毗陵道，光涵落月空。", "夢魂塵𡏖外，眼界畫圖中。", "舟漾安期鯉，帆飛御寇風。", "鑑湖如可乞，歸老浙江東。"]'),
('e56bbbd9-704d-4e02-9925-1db6b3a71d3b','登蘭溪亭','趙鼎','宋','宋诗','song-poetry','','[]','帆落溪風轉，山明霧雨收。',48,'全唐诗/poet.song.94000.json','["帆落溪風轉，山明霧雨收。", "登臨本乘興，惝恍却生愁。", "獨雁竟安往，潛魚不可求。", "何年定歸計，復此過扁舟。"]'),
('b1b27a65-c2d5-4d85-913e-3c03d1b79af6','左馮翊寄東鎮張致一兼簡聞喜親舊','趙鼎','宋','宋诗','song-poetry','','[]','一官馮翊郡，爲况定如何。',48,'全唐诗/poet.song.94000.json','["一官馮翊郡，爲况定如何。", "水似古桐苦，風如東鎮多。", "幽心迷簿領，斷夢阻關河。", "賴有清樽酒，時時一醉歌。"]'),
('1ca902bc-3019-4039-90bc-4cfc8a7fd55a','次韻富季申寄示','趙鼎','宋','宋诗','song-poetry','','[]','相期念疇昔，道在敢憂貧。',48,'全唐诗/poet.song.94000.json','["相期念疇昔，道在敢憂貧。", "分手便千里，論心復幾人。", "微詞動招謗，爛醉可藏身。", "第恐先求舊，黄麻起世臣。"]'),
('fd8e81ba-9608-4cd1-bda6-75306fdf968f','次韻富季申雪中即事時聞北敵起兵京師戒嚴二首  其一','趙鼎','宋','宋诗','song-poetry','','[]','東風花萬點，落我酒盃間。',48,'全唐诗/poet.song.94000.json','["東風花萬點，落我酒盃間。", "欲和郢中曲，先頽坐上山。", "威稜徒料峭，生意自斕斑。", "誰是淮西將，提兵夜斬關。"]'),
('136efcf8-6171-4337-99f1-c7f50048a580','次韻富季申雪中即事時聞北敵起兵京師戒嚴二首  其二','趙鼎','宋','宋诗','song-poetry','','[]','無才居客右，孤坐一窗間。',48,'全唐诗/poet.song.94000.json','["無才居客右，孤坐一窗間。", "夢到廣寒殿，人來姑射山。", "舞低明佩冷，粧罷落花斑。", "便欲凌風去，天門隔九關。"]'),
('c83efa98-8c20-4be4-854d-a24f58e847cf','後數日雪再作','趙鼎','宋','宋诗','song-poetry','','[]','三見江南白，端來伴酒樽。',48,'全唐诗/poet.song.94000.json','["三見江南白，端來伴酒樽。", "作寒催歲暮，流潤壓冬温。", "雲卧山容濕，天低水氣昏。", "東風猶有信，昨夜到前村。"]'),
('59a85532-4172-4d99-bee6-e6e51a7e5ede','發杭州有訝太遽者','趙鼎','宋','宋诗','song-poetry','','[]','未著絕交論，但歌招隱詩。',48,'全唐诗/poet.song.94000.json','["未著絕交論，但歌招隱詩。", "人間審如此，身外復奚疑。", "喪亂物情薄，奔馳智力疲。", "溪山有佳處，投老更何之。"]'),
('4cee2f93-1b69-4ce8-99e2-aa5b1e549cb2','東軒即事二首  其一','趙鼎','宋','宋诗','song-poetry','','[]','投閑非避世，導引學修真。',48,'全唐诗/poet.song.94000.json','["投閑非避世，導引學修真。", "物外元無事，壺中别有春。", "水聲清夢寢，山色上衣巾。", "已矣将安往，鄉關渺戰塵。"]'),
('f758f372-af81-48ce-94dd-ed4852628204','東軒即事二首  其二','趙鼎','宋','宋诗','song-poetry','','[]','原憲貧非病，淵明懶是真。',48,'全唐诗/poet.song.94000.json','["原憲貧非病，淵明懶是真。", "詩留百年債，酒占四時春。", "泉石高涼地，祠官自在身。", "叨蒙有如此，何以効涓塵。"]'),
('5b0b642e-3578-43d4-b094-74f4d3cf6503','聞有長沙之命','趙鼎','宋','宋诗','song-poetry','','[]','安土無南北，論情皆弟兄。',48,'全唐诗/poet.song.94000.json','["安土無南北，論情皆弟兄。", "休尋卓庵處，要便打包行。", "萍跡雖無定，葵心終有傾。", "相望得安健，有使即傳聲。"]'),
('3c64611f-fd4d-4516-8ce6-c7e6e8ad09d5','泊小金山覺渡寺僧言建德知縣桐廬知縣婺州教授皆被召','趙鼎','宋','宋诗','song-poetry','','[]','敢歎邉氛熾，今聞公道開。',48,'全唐诗/poet.song.94000.json','["敢歎邉氛熾，今聞公道開。", "中原非世事，南國自人材。", "朱履羞彈鋏，黄金謾築臺。", "天涯轉蓬恨，何地賦歸來。"]'),
('3d581b6e-c890-411f-80b9-6432e36ae130','登舟示邢子友','趙鼎','宋','宋诗','song-poetry','','[]','盡室嗟何往，窮年浪自悲。',96,'全唐诗/poet.song.94000.json','["盡室嗟何往，窮年浪自悲。", "才疏身潦倒，地遠跡孤危。", "風雨江南岸，豺狼天一涯。", "畏途端可憫，薄宦竟奚爲。", "已失田園計，難忘升斗資。", "毋煩俗子問，有媿達人嗤。", "病馬思春草，驚烏遶夜枝。", "登舟一長歎，此意只君知。"]'),
('20fa488b-dbfb-4f0e-b243-b988dcfa6557','聞郭瑾懷甫除郎','趙鼎','宋','宋诗','song-poetry','','[]','至治本無爲，何曾帝力知。',144,'全唐诗/poet.song.94000.json','["至治本無爲，何曾帝力知。", "人惟求俊彦，天畀濟艱危。", "鼎席尊黄髪，星郎用白眉。", "鋒芒森武庫，律呂奏咸池。", "海內想風采，朝中增羽儀。", "餘光被草木，盛事播聲詩。", "感會唯千載，飛騰各一時。", "著鞭今更懶，投劾去奚疑。", "亦有乘軒戀，其如續脛悲。", "銜蘆聊避弋，遶樹未安枝。", "念舊多生死，思鄉久别離。", "自餘復何道，湖海是歸期。"]'),
('61087d75-efae-4100-a8b4-b6cc7750f591','秋試鎖宿府學','趙鼎','宋','宋诗','song-poetry','','[]','悄無人語到高堂，爽氣侵凌枕簟涼。',64,'全唐诗/poet.song.94000.json','["悄無人語到高堂，爽氣侵凌枕簟涼。", "木葉彫風秋瑟瑟，簷花流雨夜浪浪。", "燈明疏幔孤光暗，蛩咽空階怨緒長。", "心願無期清夢斷，一爐沉水自焚香。"]'),
('9ae92250-4934-4153-a86a-cf77ec815628','登第示同年','趙鼎','宋','宋诗','song-poetry','','[]','氤氲和氣鳳城春，正是英豪得志辰。',64,'全唐诗/poet.song.94000.json','["氤氲和氣鳳城春，正是英豪得志辰。", "雨露九重均造化，丹青千字富經綸。", "古來將相皆由此，今見詩書不悞人。", "何處寒鄉少年子，綠袍歸拜北堂親。"]'),
('3c606dc2-c26c-43a7-babe-5395c19298fc','守官長道之岷南過馬務寨示知寨石殿直','趙鼎','宋','宋诗','song-poetry','','[]','夜關不鎖戍無兵，負販行歌樂太平。',64,'全唐诗/poet.song.94000.json','["夜關不鎖戍無兵，負販行歌樂太平。", "綠野牛羊新牧地，頽垣烟草古邉城。", "山川自昔留形勢，基業今誰問戰争。", "隴上少年多意氣，彎弓徒自詫功名。"]'),
('cb92d2d9-8d5f-401b-85e0-21dd994e37f9','酬贈黄倅','趙鼎','宋','宋诗','song-poetry','','[]','翰墨文章妙若神，風流談笑絕纖塵。',64,'全唐诗/poet.song.94000.json','["翰墨文章妙若神，風流談笑絕纖塵。", "才華最盛東西蜀，聞望相高一二人。", "清奪峨眉千歲雪，麗如錦水萬花春。", "我生不識東坡老，猶及頤庵見後身。"]'),
('d124168e-019b-489c-90b7-770f85bdb4d0','馮翊次韻邵子文寄贈之什','趙鼎','宋','宋诗','song-poetry','','[]','三見西風洛水秋，歸心長共水悠悠。',64,'全唐诗/poet.song.94000.json','["三見西風洛水秋，歸心長共水悠悠。", "扁舟未遂蓴鱸願，俗駕空貽猿鶴羞。", "可見飄零疏酒盞，更慚落魄問朋游。", "回頭一笑君應會，薄有田園歸去休。"]'),
('3b4e9800-437a-4d5d-b814-3eaf5ff95fc4','夜送客至馬鳴橋','趙鼎','宋','宋诗','song-poetry','','[]','滿眼塵埃懶據鞍，暫逢清景即怡顔。',64,'全唐诗/poet.song.94000.json','["滿眼塵埃懶據鞍，暫逢清景即怡顔。", "月明夜水平低岸，煙淡秋林倚半山。", "隱退謾留他日計，居貧未放此身閑。", "老來媿取移文誚，會整匆匆俗駕還。"]'),
('4f6a984a-5094-48aa-87cc-da755f2b8bee','從軍滑臺  其一','趙鼎','宋','宋诗','song-poetry','','[]','中原何自假遊魂，帷幄奇謀妙若神。',64,'全唐诗/poet.song.94000.json','["中原何自假遊魂，帷幄奇謀妙若神。", "沙漠宣威元有將，燕然勒頌不無人。", "山川流恨荒涼地，桃李無言寂寞春。", "炯炯孤懷竟何補，猶能狂飲吐車茵。"]'),
('ac623c62-9f3e-4e59-ac4c-0282f1dfe0af','從軍滑臺  其二','趙鼎','宋','宋诗','song-poetry','','[]','碌碌功名安用之，更堪心事巧相違。',64,'全唐诗/poet.song.94000.json','["碌碌功名安用之，更堪心事巧相違。", "秪緣叔夜此生懶，更悟淵明前日非。", "客舍那知春色暮，東風但見柳花飛。", "瀟湘亭下煙波好，送我如將短艇歸。"]'),
('98b841cb-9571-48e3-b4ff-8670e8397c42','登廓軒用王穆之秀才韻','趙鼎','宋','宋诗','song-poetry','','[]','臨高懷遠悵夷猶，放目微吟竟日留。',64,'全唐诗/poet.song.94000.json','["臨高懷遠悵夷猶，放目微吟竟日留。", "一雁北來天杳杳，片帆東下水悠悠。", "雲烟慘淡關河暮，風雨凄涼觀閣秋。", "回首何由叫虞舜，蒼陵山色向人愁。"]'),
('3d1fa565-68e2-4c0d-bf49-ecf4e355874b','河南留守王大資','趙鼎','宋','宋诗','song-poetry','','[]','退卧東山自在身，幡然猶肯慰斯民。',64,'全唐诗/poet.song.94000.json','["退卧東山自在身，幡然猶肯慰斯民。", "名高海內推前輩，德冠朝中號偉人。", "紫誥即看還舊物，黄扉終許秉鴻鈞。", "瑤池花有千年實，更看東風幾度春。"]'),
('e41bc63d-d38a-4580-9a29-a933d955980c','洛陽九日次韻縣尉  其一','趙鼎','宋','宋诗','song-poetry','','[]','誰遣孤標最晚芳，寒蜂冷蝶尚能狂。',64,'全唐诗/poet.song.94000.json','["誰遣孤標最晚芳，寒蜂冷蝶尚能狂。", "不禁清瘦西風緊，薄洗鉛華曉露香。", "照影一樽聊作伴，誅茅三徑莫相忘。", "他年載酒能來否，相見懸知話更長。"]'),
('202fc38e-9b6b-45e5-a0f8-498cdccc074c','洛陽九日次韻縣尉  其二','趙鼎','宋','宋诗','song-poetry','','[]','貧病侵尋不少寛，行藏何事更憑欄。',64,'全唐诗/poet.song.94000.json','["貧病侵尋不少寛，行藏何事更憑欄。", "兒曹不解市朝隱，我輩政宜文字歡。", "客恨向來隨處有，秋風待此著人寒。", "賓鴻旅燕元無定，莫把黄花取次看。"]'),
('1eaf4b88-109f-44e5-921c-46c3ea9c4fed','次韻縣尉','趙鼎','宋','宋诗','song-poetry','','[]','勞人州縣若爲情，蹭蹬窮途已半生。',64,'全唐诗/poet.song.94000.json','["勞人州縣若爲情，蹭蹬窮途已半生。", "愁滿西風雙鬢白，夢回中夜寸心驚。", "每慚彭澤辭升斗，終合吳門變姓名。", "且把黄花泛盃酒，秋深蕭寺有餘清。"]'),
('0b69def1-229f-4e88-87d1-ba89b4e496ea','縣丞呂若谷置酒巽亭  其一','趙鼎','宋','宋诗','song-poetry','','[]','涼風收雨斷晴霓，漠漠青山白鷺飛。',64,'全唐诗/poet.song.94000.json','["涼風收雨斷晴霓，漠漠青山白鷺飛。", "竹樹蔽虧涵野色，樓臺滅沒淡煙霏。", "凌波鳴珮杳何許，駕鶴吹笙殊未歸。", "悵念夷猶凄望眼，碧雲千里又斜暉。"]'),
('77e7a461-ad63-45b5-89a4-bdb317b0ecc6','縣丞呂若谷置酒巽亭  其二','趙鼎','宋','宋诗','song-poetry','','[]','荒煙蔓草接平林，景物蕭蕭秋意深。',64,'全唐诗/poet.song.94000.json','["荒煙蔓草接平林，景物蕭蕭秋意深。", "水闊山長人去遠，雲閑天淡鳥飛沉。", "宫前離黍他年恨，關外西風别夜心。", "莫倚欄干重留客，子山從此費悲吟。"]'),
('7f9af472-7f18-4544-a18f-24a412880ec8','再用前韻  其一','趙鼎','宋','宋诗','song-poetry','','[]','萬里高空卷素霓，徘徊幾點暮鵶飛。',64,'全唐诗/poet.song.94000.json','["萬里高空卷素霓，徘徊幾點暮鵶飛。", "波平洛浦棹歌遠，風裊宫樓香霧霏。", "猿鶴山中應怨别，蓴鱸秋後合思歸。", "此間自有江淹賦，不用桓伊恨落暉。"]'),
('04d09310-376a-4042-825c-435eb50fed43','再用前韻  其二','趙鼎','宋','宋诗','song-poetry','','[]','一枝枝自寄深林，何得飜然著意深。',64,'全唐诗/poet.song.94000.json','["一枝枝自寄深林，何得飜然著意深。", "塞上亦知無馬失，江邉誰問有舟沉。", "煩君爛漫千鍾酒，慰我登臨一寸心。", "醉後狂歌歌更切，未應愁減越人吟。"]'),
('82ee290d-a547-4ce5-9f6b-f59be0ab1681','次韻張與之登巽亭  其一','趙鼎','宋','宋诗','song-poetry','','[]','百年遺恨了難平，只有南山不改青。',64,'全唐诗/poet.song.94000.json','["百年遺恨了難平，只有南山不改青。", "橋下温波秋渺渺，樓頭霏霧晚冥冥。", "祥鍾福地衣冠盛，氣潤中天草木靈。", "那得丹青繪縑素，煩君妙語寫無形。"]'),
('167e5aea-230b-4cb6-86d6-c5fc1bfba3e2','次韻張與之登巽亭  其二','趙鼎','宋','宋诗','song-poetry','','[]','霜洗殘秋暮吹驚，長林蔓草斂餘青。',64,'全唐诗/poet.song.94000.json','["霜洗殘秋暮吹驚，長林蔓草斂餘青。", "忘機獨鳥臨清淺，避弋孤鴻入杳冥。", "老矣未成南畝計，歸歟空媿北山靈。", "獨憐亭下瀟瀟柏，能伴幽人槁木形。"]'),
('ed006b09-ae6f-4e62-a728-3053a255e521','洛中次韻河南令王子與觀梅','趙鼎','宋','宋诗','song-poetry','','[]','桃李叢中獨立難，自憐孤艶怯春寒。',64,'全唐诗/poet.song.94000.json','["桃李叢中獨立難，自憐孤艶怯春寒。", "微風只解分香去，流水猶能照影看。", "冷落霓衣慵按舞，斕斑粧粉未勝冠。", "留連芳酒無嫌晚，要與涼蟾共倚欄。"]'),
('8b064692-d6ea-4520-ba52-c511c81f2556','定海路中觀梅','趙鼎','宋','宋诗','song-poetry','','[]','傅粉生香作意開，柔情似欲挽人回。',64,'全唐诗/poet.song.94000.json','["傅粉生香作意開，柔情似欲挽人回。", "猶憐行役匆匆去，不是尋芳得得來。", "姑射山頭若冰雪，謝家林下絕塵埃。", "空江月落東風冷，誰並孤舟一笛哀。"]'),
('f1942df1-5f0a-4d9b-bdc5-b40fe798b62a','建隆寺詩','趙鼎','宋','宋诗','song-poetry','','[]','天上旌旗照海隅，規模想像百年餘。',64,'全唐诗/poet.song.94000.json','["天上旌旗照海隅，規模想像百年餘。", "雷霆號令推神筆，龍虎風雲識讖書。", "顧盼八方平僣亂，謳歌幾世樂耕鋤。", "他時誰唱紛更術，不念艱難樹立初。"]'),
('fb2284e9-3d36-4f10-baa9-0b85dd5cbd8d','紅門掃役所觀河','趙鼎','宋','宋诗','song-poetry','','[]','砥柱西傾朔野寛，魚龍掀舞去漫漫。',64,'全唐诗/poet.song.94000.json','["砥柱西傾朔野寛，魚龍掀舞去漫漫。", "潤蒸霏霧一川暗，怒激驚風千里寒。", "九折勢須回故道，三山天爲障狂瀾。", "尋源不作乘槎計，滄海他年一釣竿。"]'),
('9ef4b1d4-cf7c-451c-80a4-644b1f3832be','役所寒食晚歸','趙鼎','宋','宋诗','song-poetry','','[]','永巷疏林棲鳥還，幽花蔓草慘荒煙。',64,'全唐诗/poet.song.94000.json','["永巷疏林棲鳥還，幽花蔓草慘荒煙。", "悄無人語寒食後，時有雨點黄昏前。", "孤坐何從得言笑，一樽不復論聖賢。", "酒酣縮首絮衾底，屋頭浩浩南風顛。"]'),
('9b01271b-158a-410d-bece-bbba49b6c51f','之官開封泛洛東下先寄京師故舊','趙鼎','宋','宋诗','song-poetry','','[]','滄波東下武牢關，物色人情共慘然。',64,'全唐诗/poet.song.94000.json','["滄波東下武牢關，物色人情共慘然。", "草檄舊傳驃騎府，浮家今在孝廉船。", "向來戎馬知何補，老去江湖定有緣。", "無限青雲著鞭處，固應分付祖生先。"]'),
('0f2944da-7299-46b9-b5b2-21d549bf31a6','暮春','趙鼎','宋','宋诗','song-poetry','','[]','花開花謝總無心，轉首薰風綠滿林。',64,'全唐诗/poet.song.94000.json','["花開花謝總無心，轉首薰風綠滿林。", "人事不隨春事了，眼雲空與暮雲深。", "錦鳩呼婦商量雨，白蟻排兵做弄陰。", "除却牆頭老山色，更無佳客肯相尋。"]'),
('48b432d2-03d6-46df-8b8d-514b28d5b67c','和元長暮春','趙鼎','宋','宋诗','song-poetry','','[]','坐歎空山落景催，幾時江上葉舟回。',64,'全唐诗/poet.song.94000.json','["坐歎空山落景催，幾時江上葉舟回。", "初無妙術留春住，强覓餘歡傍酒來。", "體力寒多便故絮，齒牙衰甚怯新梅。", "秦川洛水繁華事，白首天邉共此盃。"]'),
('a705800d-9973-4c91-ae23-e54a656d1b54','别張德遠詩','趙鼎','宋','宋诗','song-poetry','','[]','殘蟾衰柳伴牢愁，把酒悲歌汴水秋。',64,'全唐诗/poet.song.94000.json','["殘蟾衰柳伴牢愁，把酒悲歌汴水秋。", "契闊死生俱淚下，功名富貴此心休。", "殺雞爲黍思前約，問舍求田媿本謀。", "又向春風話離别，此生生計日悠悠。"]'),
('9b6f369b-ee56-4411-91f5-f75e5edf5e8e','清涼寺','趙鼎','宋','宋诗','song-poetry','','[]','數壘小山松桂幽，能令盛暑作涼秋。',64,'全唐诗/poet.song.94000.json','["數壘小山松桂幽，能令盛暑作涼秋。", "故宫於此有遺跡，客子暫來生許愁。", "萬頃雲波朝古堞，一簔寒雨送扁舟。", "他年圖畫歸攜取，要使北人清兩眸。"]'),
('91c704d3-3ae8-4ef1-ab70-38800cf871af','将發泗上','趙鼎','宋','宋诗','song-poetry','','[]','客裏尋歡豈易謀，牢歌誰與散幽憂。',64,'全唐诗/poet.song.94000.json','["客裏尋歡豈易謀，牢歌誰與散幽憂。", "可憐傖父雙蓬鬢，長寄吳儂一葉舟。", "陶令早知今日是，庾郎能賦此生愁。", "殘年流蕩歸無處，蘭芷瀟瀟江上秋。"]'),
('d38c050d-36b1-40e0-b84c-089bb6546a02','至宿聞陸昭中病痁','趙鼎','宋','宋诗','song-poetry','','[]','偉幹亭亭嘆轍鱗，弊裘破帽厭京塵。',64,'全唐诗/poet.song.94000.json','["偉幹亭亭嘆轍鱗，弊裘破帽厭京塵。", "一官耻作兒女態，扁舟去卜漁樵鄰。", "他鄉未辦饘粥計，何物更能寒熱人。", "努力扶持飽吃飯，秋風江上正鱸蓴。"]'),
('6d7d19b2-5568-41da-878c-6977c66f15cc','示陸昭中','趙鼎','宋','宋诗','song-poetry','','[]','執耒田園正所圖，無心重整少時書。',64,'全唐诗/poet.song.94000.json','["執耒田園正所圖，無心重整少時書。", "功名常若歸難必，拙直懸知退有餘。", "避謗杜門賓客絕，病痰妨飲酒盃疏。", "平生剛笑孔文舉，老我年來百不如。"]'),
('75fd07a8-1408-4228-9667-fbfcf7184ea4','六月十三日書呈元長','趙鼎','宋','宋诗','song-poetry','','[]','心遠由來絕世紛，更尋邱壑避囂塵。',64,'全唐诗/poet.song.94000.json','["心遠由來絕世紛，更尋邱壑避囂塵。", "門闌已覺貧無事，賓客應憐老畏人。", "詩不名家免招謗，酒雖作病要全身。", "香山千載流風在，鷄黍他年早卜鄰。"]'),
('2a1be151-a5f4-4a92-9ec2-64333f820190','用元長韻贈空老','趙鼎','宋','宋诗','song-poetry','','[]','虛懷無地著纖塵，獨鶴孤雲寄此身。',64,'全唐诗/poet.song.94000.json','["虛懷無地著纖塵，獨鶴孤雲寄此身。", "琴發清彈廬阜月，詩探妙意武林春。", "少陵深契賛公語，惠遠能知陶令真。", "擾擾今誰同此趣，容車山下兩閑人。"]'),
('3cd8753d-afe4-44f2-a414-3228a7a3cfb6','夜坐','趙鼎','宋','宋诗','song-poetry','','[]','寺樓鐘斷鎖長廊，誰共蕭齋一炷香。',64,'全唐诗/poet.song.94000.json','["寺樓鐘斷鎖長廊，誰共蕭齋一炷香。", "書册自能留久坐，燈花還解勸餘觴。", "風回絕壑沉虚籟，雨入幽林送嫩涼。", "老懶由來貪睡美，秋衾不怕夜初長。"]'),
('ba10c5d5-8284-475b-8552-70e38d8023a7','泊真州閘外詩','趙鼎','宋','宋诗','song-poetry','','[]','南來繫纜楚江臯，孤客羈心正鬱陶。',64,'全唐诗/poet.song.94000.json','["南來繫纜楚江臯，孤客羈心正鬱陶。", "海氣連空山色暗，秋陰覆地水風高。", "屋頭冰雹敲寒雨，枕底春雷簸怒濤。", "一點青燈雙白鬢，可無樽酒伴離騷。"]'),
('d55a70eb-9b74-44ac-89dc-a0393b45c0d2','過高郵飲張才甫家作詩爲别','趙鼎','宋','宋诗','song-poetry','','[]','短棹人誰識姓名，相逢况是十年兄。',64,'全唐诗/poet.song.94000.json','["短棹人誰識姓名，相逢况是十年兄。", "江關契闊秋來恨，兵火流離别後情。", "高論看君揮麈柄，雄圖憐我付楸枰。", "酒闌月落孤舟起，便是江湖萬里行。"]'),
('8b79502f-3eba-4c23-ba99-5d0b1d1a9f1a','和鄭有功次范元長韻','趙鼎','宋','宋诗','song-poetry','','[]','憑陵風雪不相貸，逋客向來生事寒。',64,'全唐诗/poet.song.94000.json','["憑陵風雪不相貸，逋客向來生事寒。", "京國回頭九關隔，江湖吊影一身單。", "著鞭意氣初非淺，唾手功名不作難。", "老矣收心定何許，蓴鱸聊饌腐儒餐。"]'),
('4a2d890a-ad58-4dbe-a44e-d3588d0d1c06','歲晏感懷  其一','趙鼎','宋','宋诗','song-poetry','','[]','欲雪濃雲凍不收，凄寒偏著敝貂裘。',64,'全唐诗/poet.song.94000.json','["欲雪濃雲凍不收，凄寒偏著敝貂裘。", "客愁有許要排逐，歲事無多難挽留。", "疇昔謾懷三徑約，飄零聊用一樽酬。", "即看瑶草光風轉，作意湖山汗漫遊。"]'),
('947ea7e2-7d2c-43a5-ad56-799b53d5721f','歲晏感懷  其二','趙鼎','宋','宋诗','song-poetry','','[]','掃蕩邉氛漸有期，此生已復歎差池。',64,'全唐诗/poet.song.94000.json','["掃蕩邉氛漸有期，此生已復歎差池。", "眼中種種無聊賴，身外悠悠徒爾爲。", "彭澤歸來那得酒，少陵窮甚但哦詩。", "卑棲儻遂桑榆晚，敢並鴛鴻接羽儀。"]'),
('3f064b07-2f2e-4fcc-86f1-780ce5a419a5','卧病一首','趙鼎','宋','宋诗','song-poetry','','[]','此生已復外升沉，出處由來著意深。',64,'全唐诗/poet.song.94000.json','["此生已復外升沉，出處由來著意深。", "拙甚但知閑可樂，災餘猶有病相尋。", "貧難調護漳濱卧，老自消除魏闕心。", "莊舄鍾離各懷土，吳兒莫笑作秦音。"]'),
('e51e2141-58ae-481d-8aaf-9425eebc8548','次韻子蒼諸公韻','趙鼎','宋','宋诗','song-poetry','','[]','亂來那復較升沉，愁極仍嗟病骨侵。',64,'全唐诗/poet.song.94000.json','["亂來那復較升沉，愁極仍嗟病骨侵。", "雙袖龍鍾羈客淚，一樽傾倒故人心。", "沙寒獨雁難求侣，山近浮雲易作陰。", "落軫斷弦非衆聽，暮年淮海歎知音。"]'),
('bcc69310-eac6-4aa7-ad2c-8f5b3c2fe28b','再用前韻示范六','趙鼎','宋','宋诗','song-poetry','','[]','舉目山河往恨沉，吳霜一點鬢毛侵。',64,'全唐诗/poet.song.94000.json','["舉目山河往恨沉，吳霜一點鬢毛侵。", "飄零顧我非前日，慷慨唯君識此心。", "香散藥畦花漫漫，波侵蝶沼竹陰陰。", "平生載酒論文地，鴻雁歸時問信音。"]'),
('2e691f2a-2f35-4555-b535-c457ff2f7c2c','將至三衢楊村道中小飲','趙鼎','宋','宋诗','song-poetry','','[]','衢江波上半帆風，散髪篷窗笑傲中。',64,'全唐诗/poet.song.94000.json','["衢江波上半帆風，散髪篷窗笑傲中。", "晚境但深耽酒癖，窮途猶愧作詩工。", "天邉壠坂三秦阻，海上山川百越通。", "得盡餘齡安一飽，此身何敢較西東。"]'),
('b4c95a71-e9be-480e-8c64-2ff11db3d82a','長沙倅劉元舉寄示參議伯山酬唱之什因亦次韻二首  其一','趙鼎','宋','宋诗','song-poetry','','[]','揮毫曾看妙如神，傾瀉明珠百斛珍。',64,'全唐诗/poet.song.94000.json','["揮毫曾看妙如神，傾瀉明珠百斛珍。", "疇昔笑談知寡和，後來風度絕無人。", "應憐老矣紆朱紱，早約歸歟岸角巾。", "明鏡未須羞鬢髪，一樽相與永青春。"]'),
('0b8cae85-df00-4905-b5ed-79f65c12ae29','長沙倅劉元舉寄示參議伯山酬唱之什因亦次韻二首  其二','趙鼎','宋','宋诗','song-poetry','','[]','秋風澤國正鱸蓴，歸意長隨陸海珍。',64,'全唐诗/poet.song.94000.json','["秋風澤國正鱸蓴，歸意長隨陸海珍。", "簿領窮年迷舊學，瘡痍千里愧斯人。", "袖中本是釣竿手，頭上無非漉酒巾。", "節物驚心勞夢寐，衢江西岸小梅春。"]'),
('a71535e7-15e1-4efa-b7ef-96bf5dc53ce5','送張京與之宰解縣','趙鼎','宋','宋诗','song-poetry','','[]','憶嘗從事舜蒲州，把酒論文並俊遊。',64,'全唐诗/poet.song.94000.json','["憶嘗從事舜蒲州，把酒論文並俊遊。", "千古關河增義氣，一時人物最風流。", "飄零無復相從樂，潦倒難堪送别愁。", "爲我去尋山下路，疏雲流水五峰秋。"]'),
('c01b09aa-a214-4fb0-85a0-7df2ff4da023','得蜀信','趙鼎','宋','宋诗','song-poetry','','[]','雲水關山恨渺茫，尺書能慰九回腸。',64,'全唐诗/poet.song.94000.json','["雲水關山恨渺茫，尺書能慰九回腸。", "劍南親舊知安健，陜右兵民亦奮揚。", "契闊十年悲故國，飄零百指滯殊鄉。", "何由結伴春風暖，也向襄陽下洛陽。"]'),
('e08fd37b-f9b1-466c-a417-2320cb875c36','寒食日書事','趙鼎','宋','宋诗','song-poetry','','[]','江海飄零幾送春，飛蓬無地寄孤根。',64,'全唐诗/poet.song.94000.json','["江海飄零幾送春，飛蓬無地寄孤根。", "夢回南浦人千里，醉倚東風酒一樽。", "可是今年暗寒食，不堪多病怯黄昏。", "兒童自趁秋千約，花落空庭獨掩門。"]'),
('d08523cc-e447-4ee6-95c4-d306d9be2930','清明詩','趙鼎','宋','宋诗','song-poetry','','[]','鄉書難附北歸雲，燕子猶尋舊主人。',64,'全唐诗/poet.song.94000.json','["鄉書難附北歸雲，燕子猶尋舊主人。", "流水迢迢長念遠，飛花糝糝又傷春。", "向來軒冕非吾意，何處園林託此身。", "只有長歌一樽酒，暮年風味最情親。"]'),
('8264ccd1-528e-461e-a27f-4aa5aa23d908','和元長書懷二首  其一','趙鼎','宋','宋诗','song-poetry','','[]','神靈久憤敵塵侵，畀付經營惜寸陰。',64,'全唐诗/poet.song.94000.json','["神靈久憤敵塵侵，畀付經營惜寸陰。", "聞道倒戈回易水，行看休戰牧桃林。", "寧論少壯非前日，及見升平亦本心。", "亂後親朋無恙否，試憑北雁寄歸音。"]'),
('f4f5478f-297d-45bf-9c5f-a820cbe73899','和元長書懷二首  其二','趙鼎','宋','宋诗','song-poetry','','[]','孤懷詎勝百憂侵，息影由來貴處陰。',64,'全唐诗/poet.song.94000.json','["孤懷詎勝百憂侵，息影由來貴處陰。", "志謝長嘶走千里，身如倦翼返深林。", "雲山處處明雙目，樽酒時時洗寸心。", "更賴清詩爲陶寫，朱弦流水歎遺音。"]'),
('74947b7e-80cd-4b8c-8d4e-dded918988c8','晚風定放小舟江心','趙鼎','宋','宋诗','song-poetry','','[]','蕩漾扁舟入渺瀰，一夫搖櫓疾如飛。',64,'全唐诗/poet.song.94000.json','["蕩漾扁舟入渺瀰，一夫搖櫓疾如飛。", "涵空鑑影月光淡，襯地羅紋風力微。", "未擬然犀窮水府，猶能酌酒勸江妃。", "眼中清絕非人世，定使魯連何許歸。"]'),
('030978fa-4411-4ff8-8034-178d065b2cab','同苗秀才楊山人登舟','趙鼎','宋','宋诗','song-poetry','','[]','本無籌策堪人用，盍掛衣冠遂物情。',64,'全唐诗/poet.song.94000.json','["本無籌策堪人用，盍掛衣冠遂物情。", "官職向來滋味薄，干戈經此夢魂驚。", "君猶極口談經義，我已無心卜死生。", "何必吳門變名字，煙江萬里葉舟輕。"]'),
('7d1ee9b3-90ee-4c35-815a-59a7008fa5a3','靖安道中見梅','趙鼎','宋','宋诗','song-poetry','','[]','塵容俗狀早知非，脫迹歸來喜復悲。',64,'全唐诗/poet.song.94000.json','["塵容俗狀早知非，脫迹歸來喜復悲。", "隴上人遙千萬里，江邉花發兩三枝。", "兵戈阻絕書難到，雪霰飄零雁去遲。", "跋馬東風一回首，落英還與淚紛披。"]'),
('1419f4cf-7f7c-4ac7-8bd7-cb616bc73329','又泊蘭溪亭','趙鼎','宋','宋诗','song-poetry','','[]','孤帆薄暮轉清溪，空翠回環望眼迷。',64,'全唐诗/poet.song.94000.json','["孤帆薄暮轉清溪，空翠回環望眼迷。", "夢想莫知家遠近，羈遊將遍浙東西。", "歸來分合投閑散，老去情猶惜解攜。", "明月深林有烏鵲，悲鳴未許一枝棲。"]'),
('f2a2499a-67dc-4fa1-bdb6-4ac223714611','發四明奔昌國用韓叔夏韻呈覺民參政','趙鼎','宋','宋诗','song-poetry','','[]','曉掛危檣兩席開，孤城西望幾時回。',64,'全唐诗/poet.song.94000.json','["曉掛危檣兩席開，孤城西望幾時回。", "飄搖一舸隨潮去，彷彿三山入眼來。", "身世從今寄雲海，親朋何在渺風埃。", "乘桴肆志吾安敢，就戮鯨鯢亦快哉。"]'),
('277d4393-66ea-4694-b7d0-72467b96356b','過石佛洋','趙鼎','宋','宋诗','song-poetry','','[]','鳴鐃疊鼓兩山傍，曉泛回潮石佛洋。',64,'全唐诗/poet.song.94000.json','["鳴鐃疊鼓兩山傍，曉泛回潮石佛洋。", "漠漠東風吹瘴霧，曈曈暖日上扶桑。", "如聞鶴馭來空闊，知有神洲在渺茫。", "何必山林啗靈藥，他年鼓枻訪東皇。"]'),
('cecacbfd-d432-4754-a8fe-e6b542472b0c','越土水淺易涸而近山無木可採故常有薪水之憂既歸黄岡遂脫此責作詩示同舍','趙鼎','宋','宋诗','song-poetry','','[]','經年薪水困行朝，一日歸來百念消。',64,'全唐诗/poet.song.94000.json','["經年薪水困行朝，一日歸來百念消。", "決決溪流鳴枕下，丁丁谷響應山椒。", "小安課伐猶多事，無復移居莫見招。", "老矣羞爲吳市隱，買田從此混漁樵。"]'),
('597382d7-7522-41a7-8ac1-755c4f1cee46','丁未冬同陸昭中渡江泊秦淮稅亭之側癸丑三月自建康移守南昌登舟顧覽即昔年繫纜之所也時昭中亡矣感歎存沒作詩寄黄岡親舊','趙鼎','宋','宋诗','song-poetry','','[]','江湖南北寄飛蓬，歎息流光俛仰中。',64,'全唐诗/poet.song.94000.json','["江湖南北寄飛蓬，歎息流光俛仰中。", "千里月明人念遠，一年春事水流東。", "驚心存沒風花轉，閱世悲歡夢境空。", "欲寄此情那可盡，相逢唯有一樽同。"]'),
('e5ee40d1-e022-4449-8a0c-f884702409a7','次張真君韻','趙鼎','宋','宋诗','song-poetry','','[]','聞君結屋臨山磵，多種黄精與紫芝。',64,'全唐诗/poet.song.94000.json','["聞君結屋臨山磵，多種黄精與紫芝。", "雲氣每占華蓋頂，松陰長護玉津池。", "溪流盤轉近百里，山色清虛無一姿。", "傳得僊人新句法，封題遙寄五言詩。"]'),
('b92419ba-22d8-43a1-b746-6009bb5c7cea','中秋夜清坐讀歐陽公正統論二首  其一','趙鼎','宋','宋诗','song-poetry','','[]','稍覺清涼換縠衣，獨憐衰鬢與秋期。',64,'全唐诗/poet.song.94000.json','["稍覺清涼換縠衣，獨憐衰鬢與秋期。", "清樽浪作經年計，黄卷長懷萬古悲。", "蛩咽幽吟愁露草，鵲飜寒影遶風枝。", "此生此念能忘否，夢破蒼龍西去時。"]'),
('c3495ff5-55b7-4636-b066-c5d8bb6242a6','中秋夜清坐讀歐陽公正統論二首  其二','趙鼎','宋','宋诗','song-poetry','','[]','露濯秋空灝氣生，沉沉天宇夜空明。',64,'全唐诗/poet.song.94000.json','["露濯秋空灝氣生，沉沉天宇夜空明。", "南樓老子興不淺，赤壁先生夢更清。", "小艇擬尋銀漢路，哀砧還起玉關情。", "何心把酒論歡賞，細字文書對短檠。"]'),
('aa0f0cd7-e0f6-4efd-9a1d-b60177dd1b5c','九日晚坐獨酌一杯','趙鼎','宋','宋诗','song-poetry','','[]','木落江城風露寒，坐驚芳歲逼彫殘。',64,'全唐诗/poet.song.94000.json','["木落江城風露寒，坐驚芳歲逼彫殘。", "晚來自愛一杯暖，老去元無九日歡。", "擬借靈均蘭作佩，尚餘陶令菊堪餐。", "平生徧插茱萸處，短夢悠悠行路難。"]'),
('58365a7d-c302-441a-a07b-fc95b91ed476','泊舟鹽橋兒子洙輙於市買歷尾題云客裏其如日費多因取筆足成一詩','趙鼎','宋','宋诗','song-poetry','','[]','蹭蹬生涯一釣簔，東西淮海信濤波。',64,'全唐诗/poet.song.94000.json','["蹭蹬生涯一釣簔，東西淮海信濤波。", "亂來益覺人情薄，客裏其如日費多。", "麟閣壯圖今老矣，菟裘歸計奈貧何。", "越吟楚奏那能已，時倚哀彈拍棹歌。"]'),
('cd9a2095-660c-4be6-b4f2-a117fd0f8c32','雪中與洙輩飲','趙鼎','宋','宋诗','song-poetry','','[]','朝市邱園定孰優，要将閑適換深憂。',64,'全唐诗/poet.song.94000.json','["朝市邱園定孰優，要将閑適換深憂。", "門闌終日斷還往，父子一樽相勸酬。", "雲鎖山林寒悄悄，風吹雪霰暮悠悠。", "醉餘身世知何許，莫向東陵覓故侯。"]'),
('237a8d38-4d90-4bad-9665-fa994c70650d','大雪連日不已','趙鼎','宋','宋诗','song-poetry','','[]','日日愁陰慘不開，驚風和雪振窮埃。',64,'全唐诗/poet.song.94000.json','["日日愁陰慘不開，驚風和雪振窮埃。", "百年未省南州見，千里應隨北客來。", "塞馬曉悲沙上月，隴人遙恨笛中梅。", "獨憐寸草滋榮意，知道春從斗柄迴。"]'),
('95a3e7c6-b68e-4677-bc06-b8a60c0a742a','雪晴東軒獨坐','趙鼎','宋','宋诗','song-poetry','','[]','雲山回合翠重重，不放幽人遠目窮。',64,'全唐诗/poet.song.94000.json','["雲山回合翠重重，不放幽人遠目窮。", "高竹有時催凍雪，饑禽竟日咽悲風。", "悠悠事與本謀異，擾擾人誰此意同。", "却坐蒲團聊袖手，更無一語可書空。"]'),
('4ec7e1c0-67e9-4b84-ae55-726636cf85f6','過石門洋','趙鼎','宋','宋诗','song-poetry','','[]','平生戎馬踏塵埃，晚看滄波眼漸開。',64,'全唐诗/poet.song.94000.json','["平生戎馬踏塵埃，晚看滄波眼漸開。", "眩轉忽從千仞落，低昂時見一山來。", "風頭淅瀝吹成雨，枕底鏗轟怒作雷。", "雅欲騎鯨傲人世，吾其於此賦歸哉。"]'),
('a106dce0-5ff1-4342-ae89-05bacc6ddfe0','丙子夏病卧汗後','趙鼎','宋','宋诗','song-poetry','','[]','枯腸得水若通靈，溟汗周身一雨零。',64,'全唐诗/poet.song.94000.json','["枯腸得水若通靈，溟汗周身一雨零。", "行客筋骸困方歇，醉人心骨喚初醒。", "病蟬移夢入新殻，老鶴息神梳舊翎。", "乞得殘生對兒女，不愁無粟貯陶瓶。"]'),
('e2e0dccc-5ed6-43fd-93e9-deb4f86d7f8f','河中太守','趙鼎','宋','宋诗','song-poetry','','[]','掄才梁棟定誰須，聳拔長松第一株。',224,'全唐诗/poet.song.94000.json','["掄才梁棟定誰須，聳拔長松第一株。", "令聞允爲時屬望，豐功當在帝都俞。", "將令異日作霖雨，暫使斯民歌袴襦。", "播物仁風隨扇發，向人和氣與春舒。", "請看嶷嶷諸郎秀，是應詵詵盛德符。", "廣陌乘黄將驥子，丹山威鳳带鵷鶵。", "聲名最重連城寶，文采光騰照夜珠。", "賈誼著書驚一世，平津射策冠諸儒。", "傳經固自卑劉向，遺直猶資見魏謩。", "便向萱堂生月桂，更尋雲路種星榆。", "人從碧海偷桃實，客自朱門墜舄鳬。", "性静綠龜宜作伴，身輕靈壽不須扶。", "金波滿泛鵝兒酒，香霧争持鵲尾爐。", "要識東人念公意，巖廊千載賛昌圖。"]'),
('cd4d3cb9-9e1a-4aaa-b329-6d5db976bb76','聽琴次退翁韻','趙鼎','宋','宋诗','song-poetry','','[]','夢尋仙子訪瀛洲，怨入春泉遶指流。',32,'全唐诗/poet.song.94000.json','["夢尋仙子訪瀛洲，怨入春泉遶指流。", "酒病着人無物解，更煩一鼓爲扶頭。"]'),
('c1bd52f8-2daf-4dc6-81cf-b9c50953e21e','正月十八日枕上','趙鼎','宋','宋诗','song-poetry','','[]','空籠疏幔曉寒清，小醉醒然不作酲。',32,'全唐诗/poet.song.94000.json','["空籠疏幔曉寒清，小醉醒然不作酲。", "欹枕誰能尋斷夢，卧聞童子誦經聲。"]'),
('15002fae-09a0-4f1f-ac31-0b6ad3c38ab0','山中書事','趙鼎','宋','宋诗','song-poetry','','[]','心遠身閑眼界清，瀟然回首萬緣輕。',32,'全唐诗/poet.song.94000.json','["心遠身閑眼界清，瀟然回首萬緣輕。", "更将滿耳是非語，換作松風溪水聲。"]'),
