('4c3caf04-f7ba-488c-9d24-de0dde9a3495','病愈','趙鼎','宋','宋诗','song-poetry','','[]','支離瘦骨怯寒侵，霧雨溟溟山更深。',32,'全唐诗/poet.song.94000.json','["支離瘦骨怯寒侵，霧雨溟溟山更深。", "醫國無功還自治，暮年藥裹最關心。"]'),
('259502b3-9306-4581-b8b6-334cd340dad9','獨坐東軒','趙鼎','宋','宋诗','song-poetry','','[]','雲山環合户深關，中有幽人竟日閑。',32,'全唐诗/poet.song.94000.json','["雲山環合户深關，中有幽人竟日閑。", "好在窗前數竿竹，與君相伴老山間。"]'),
('5c1ada3c-5031-4d41-90d6-cc4549d6a081','潮陽容老出游閩浙過泉南當謁湧老禪師因寄四句偈','趙鼎','宋','宋诗','song-poetry','','[]','老矣潮州韓吏部，饑餐渇飲似當年。',32,'全唐诗/poet.song.94000.json','["老矣潮州韓吏部，饑餐渇飲似當年。", "明明月夜長相照，莫怪無書寄大顛。"]'),
('88d1da89-ca4a-4608-a5aa-4ca4d8df16e4','吉陽寄李泰發','趙鼎','宋','宋诗','song-poetry','','[]','海風吹浪去如飛，離母山高日出遲。',32,'全唐诗/poet.song.94000.json','["海風吹浪去如飛，離母山高日出遲。", "此意此情誰會得，因書寫與故人知。"]'),
('abb3b1a5-c8c9-4aee-8724-ae8627b1fcda','寄李參政','趙鼎','宋','宋诗','song-poetry','','[]','海風飄蕩水雲飛，黎母山高月上遲。',32,'全唐诗/poet.song.94000.json','["海風飄蕩水雲飛，黎母山高月上遲。", "千里孤光一樽酒，此情惟有故人知。"]'),
('ff15f91c-ae70-49ff-bc3e-33bbbe876e01','和鄭有功游西湖二首  其一','趙鼎','宋','宋诗','song-poetry','','["\u897f\u6e56"]','放舟越淮楚，更作三吳遊。',84,'全唐诗/poet.song.94000.json','["放舟越淮楚，更作三吳遊。", "尚餘魂夢怖，敢動鄉邦愁。", "湖山自清絕，鑑中螺髻浮。", "況復得夫子，一笑忘幽憂。", "時時作清言，中有湖山秋。", "卻念無家客，坎止而乘流。", "何當與俱歸，歲晚鄰一丘。"]'),
('c231266a-b213-4fab-a4f6-f959921494f1','和鄭有功游西湖二首  其二','趙鼎','宋','宋诗','song-poetry','','["\u897f\u6e56"]','晚覺身名誤，悠悠定孰親。',48,'全唐诗/poet.song.94000.json','["晚覺身名誤，悠悠定孰親。", "卻回苕水棹，來看武林春。", "避地將安往，尋山莫厭頻。", "百錢挑竹杖，雲外踏嶙峋。"]'),
('9fcbf03c-0f4f-44b7-a990-39ef81db8746','明慶僧房夜坐','趙鼎','宋','宋诗','song-poetry','','[]','月明窗竹冷橫斜，坐看風燈落燼花。',64,'全唐诗/poet.song.94000.json','["月明窗竹冷橫斜，坐看風燈落燼花。", "老眼病餘嫌細字，枯腸寒甚怯清茶。", "囊空豈是久爲客，夢短其能飛到家。", "但有流年尋鬢髪，瀟瀟蓬葆颯霜華。"]'),
('83aadb49-3550-44f5-99ef-0010b7f67c83','趨三衢別故人時車駕幸杭州  其一','趙鼎','宋','宋诗','song-poetry','','[]','傖父何由習楚風，家山俱在古河東。',64,'全唐诗/poet.song.94000.json','["傖父何由習楚風，家山俱在古河東。", "相逢憔悴干戈後，追數悲歡夢寐中。", "摻袂又成千里別，放歌空念一尊同。", "他年倘有加餐字，試問漁舟鶴髪翁。"]'),
('e380574a-2b8c-4a90-bcff-680efcaa223a','趨三衢別故人時車駕幸杭州  其二','趙鼎','宋','宋诗','song-poetry','','[]','飄零澤國幾春風，又觸驚濤泛短蓬。',64,'全唐诗/poet.song.94000.json','["飄零澤國幾春風，又觸驚濤泛短蓬。", "四海未知棲息地，百年半在別離中。", "功名元與世緣薄，兵火向來吾道窮。", "獨倚危樓凄望眼，青山無數浙江東。"]'),
('ae5240df-f9e3-4938-af90-48bb877ed459','紫霄圃','趙鼎','宋','宋诗','song-poetry','','[]','群仙邀我遊蓬島，白鶴隨人拾瑤草。',240,'全唐诗/poet.song.94000.json','["群仙邀我遊蓬島，白鶴隨人拾瑤草。", "英靈指點洞門開，前行後擁商山皓。", "崎嶇石路燕尾分，露濕蟠桃壓竹倒。", "一山萬山雲氣深，瑯玕珠樹霜風老。", "王喬縹緲自天下，世許高情兩相好。", "中有一個字安期，笑捧金盆具瓜棗。", "食之令人可長生，遨遊八極登天行。", "有時一日三萬里，西風鶴骨霞衣輕。", "有時亦復一暫息，長歌一曲煙雲凝。", "高垂鐵鎖蒼苔古，云是神仙紫霄圃。", "芒鞋竹杖躡步間，丹鳳飛地向人舞。", "雲中雞犬異人世，藥鼎丹爐用心苦。", "開軒一飲三百杯，簷花亂落天飛雨。", "青紅黑綠亂眼前，萬草千花莫能數。", "茫然拂袖下山來，白髪婆娑鏡中睹。"]'),
('5af5acc6-985c-4ec2-8387-7e09dda7058f','喻彌陀收掩遺骸','趙鼎','宋','宋诗','song-poetry','','[]','骸骨鱗鱗曠野昏，天陰雨濕向誰論。',32,'全唐诗/poet.song.94000.json','["骸骨鱗鱗曠野昏，天陰雨濕向誰論。", "縱然有樂踰南面，爭似無爲實相門。"]'),
('40e85037-92ee-4335-aebd-1b1e500986fa','題常山草萍驛','趙鼎','宋','宋诗','song-poetry','','[]','才過常山到草萍，驛亭偏喜雨初晴。',64,'全唐诗/poet.song.94000.json','["才過常山到草萍，驛亭偏喜雨初晴。", "麥畦水漲黄雲重，柳絮風吹白雪輕。", "身世自今忘俗慮，宦途從此快吟情。", "魏公已輟江西鎮，猶有甘棠頌政聲。"]'),
('9f938a60-3dbf-458b-847b-0f77e01c6144','山門栖巖寺','趙鼎','宋','宋诗','song-poetry','','[]','天邊箭筈一門通，香隔雲蘿幾萬重。',32,'全唐诗/poet.song.94000.json','["天邊箭筈一門通，香隔雲蘿幾萬重。", "好借巖風爲披拂，移文有語笑塵容。"]'),
('dbdc0e9b-9833-4c3a-aab7-2be21687b8b0','暮村','趙鼎','宋','宋诗','song-poetry','','[]','孤村煙樹暝黄昏，一簇人家半掩門。',32,'全唐诗/poet.song.94000.json','["孤村煙樹暝黄昏，一簇人家半掩門。", "看盡栖鴉啼噪後，牧童歸去雨聲繁。"]'),
('e1b5292b-f768-451f-bf67-2ca1b7ff21ff','落花','趙鼎','宋','宋诗','song-poetry','','[]','花飛便覺春容減，一陣狂風滿地紅。',32,'全唐诗/poet.song.94000.json','["花飛便覺春容減，一陣狂風滿地紅。", "可惜餘芳留不得，夜深人靜月朦朧。"]'),
('5353515b-67a7-4173-9d7d-dafe0bee79e6','倦妝','趙鼎','宋','宋诗','song-poetry','','[]','錦帕新裁玩月犀，旋開妝合間雲螭。',32,'全唐诗/poet.song.94000.json','["錦帕新裁玩月犀，旋開妝合間雲螭。", "一成貪耍慵梳洗，日晚惟添翠黛眉。"]'),
('0c043785-d9d1-44d8-a501-c80a01208937','思鄉','趙鼎','宋','宋诗','song-poetry','','[]','何意分南北，無由問死生。',48,'全唐诗/poet.song.94000.json','["何意分南北，無由問死生。", "永纏風樹感，深動渭陽情。", "兩姊各衰白，諸甥未老成。", "塵煙渺湖海，惻惻寸心驚。"]'),
('8c8f801b-55b4-4826-9f31-84f552b46ab7','題謁松陵三賢堂','趙鼎','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','垂虹過高岸，左江右湖水。',228,'全唐诗/poet.song.94000.json','["垂虹過高岸，左江右湖水。", "洞庭相吐吞，滄海迷涯涘。", "長波卷風雨，莽蒼窮南紀。", "人材鍾秀穎，習俗擅清美。", "高風想三賢，足以振頹靡。", "一時挺孤標，千載照青史。", "荒祠倚橋側，草草漁樵市。", "舟車往來衝，今誰踵前軌。", "我從都城出，萬事空化委。", "就跡月重輕，心期要偷擬。", "異代豈無人，意欲從此始。", "山林與鐘鼎，一決乃英偉。", "近聞北客言，兵戎纏鞏汜。", "誰能務採納，尚得扶隳毀。", "歸歟固夙心，寧作一身喜。", "亦念征戍兒，白骨委荒壘。", "道路異秦吳，魂夢隔生死。", "江湖信清絕，浮泛聊爾耳。", "卻坐寫孤懷，悲風生綠綺。"]'),
('848c6478-6614-4b4a-9659-7bd0e4c5f07a','醉和顔美中元夕絕句','趙鼎','宋','宋诗','song-poetry','','[]','年年人月喜團圓，好在詩邊又酒邊。',32,'全唐诗/poet.song.94000.json','["年年人月喜團圓，好在詩邊又酒邊。", "莫道玄風只漁釣，也隨世俗夜無眠。"]'),
('cb642db1-c7c6-411b-9149-25f736d4eaa7','道堂','趙鼎','宋','宋诗','song-poetry','','[]','疏松怪石水泠泠，白葛烏紗晚醉醒。',32,'全唐诗/poet.song.94000.json','["疏松怪石水泠泠，白葛烏紗晚醉醒。", "想見眼前無俗物，一爐沉水寫黄庭。"]'),
('5103fa4a-6185-47b5-b333-7ef1360a4f73','靈巖寺','趙鼎','宋','宋诗','song-poetry','','[]','疏我爲茲山好，登臨到日曛。',49,'全唐诗/poet.song.94000.json','["疏我爲茲山好，登臨到日曛。", "巖幽餘暑雪，鍾冷入秋雲。", "篇詠唯僧助，塵煩與俗分。", "明朝入東棹，因得識吾文。"]'),
('2ded1998-1a33-453f-8dc6-c3e16e3cbc6f','瀟湘亭','趙鼎','宋','宋诗','song-poetry','','[]','疏綠柳平蕪遠際天，青山迴抱水相連。',65,'全唐诗/poet.song.94000.json','["疏綠柳平蕪遠際天，青山迴抱水相連。", "半空梅雨昏窗色，一棹萍風破暝煙。", "酒到愁來那覺醉，詩逢佳客不論篇。", "只知身在將軍府，一夢江南落枕邊。"]'),
('fe08db68-96b5-446a-b7b7-72f694cf7aaf','和聶之美重遊東郡','趙鼎','宋','宋诗','song-poetry','','[]','疏躍馬津亭未幾何，宦遊容易十年過。',65,'全唐诗/poet.song.94000.json','["疏躍馬津亭未幾何，宦遊容易十年過。", "飄搖空似隨流梗，寂寞猶如掛壁梭。", "西嶺應餘當日翠，南湖直減幾分波。", "輸君尚得飛征蓋，重向東園聽楚歌。"]'),
('515f6419-40f7-44ba-8795-965deacdb9cb','句  其一','趙鼎','宋','宋诗','song-poetry','','[]','疏速宜凈掃妖氛了，來看錢塘八月潮。',17,'全唐诗/poet.song.94000.json','["疏速宜凈掃妖氛了，來看錢塘八月潮。"]'),
('2151068d-bed2-40b6-a4cc-643b98d262a0','句  其二','趙鼎','宋','宋诗','song-poetry','','[]','疏身騎箕尾歸天上，氣作山河壯本朝。',17,'全唐诗/poet.song.94000.json','["疏身騎箕尾歸天上，氣作山河壯本朝。"]'),
('c89d3cf2-6dbd-4a76-aeda-18386431581c','句  其三','趙鼎','宋','宋诗','song-poetry','','[]','疏顔齋在倅廳，面對逍遙樓。',13,'全唐诗/poet.song.94000.json','["疏顔齋在倅廳，面對逍遙樓。"]'),
('8f98fe9b-ac2a-4198-8934-3ad8e2f3c082','竊觀太守內翰尚書佳什因以元韻述懷','郭仲荀','宋','宋诗','song-poetry','','[]','蚤學詩書愧不成，慨然投筆就功名。',64,'全唐诗/poet.song.94000.json','["蚤學詩書愧不成，慨然投筆就功名。", "少年征逐臨窮塞，晚歲優游寓赤城。", "世路炎涼何足校，宦途寵辱固堪驚。", "祠庭得請君恩重，退老江山佚性情。"]'),
('3a287b36-8827-4b65-8518-054f0a94780c','奉和宮使內翰佳什','郭仲荀','宋','宋诗','song-poetry','','[]','老來乞得奉祠宮，退食何妨不自公。',96,'全唐诗/poet.song.94000.json','["老來乞得奉祠宮，退食何妨不自公。", "任使世情分冷煖，無勞品秩論穹崇。", "功名至此休看鏡，戰伐于今喜掛弓。", "梨棗具陳呼稚子，笙歌閑作樂衰翁。", "芳菲莫負三春賞，聚散難逢一笑同。", "小圃栽培粗倫理，頻須把酒殢東風。"]'),
('2f1ba518-c304-4b94-b885-4cb399ad7879','題張子正觀察溪風亭','郭仲荀','宋','宋诗','song-poetry','','[]','廣岸流波遠，清飈襟袖開。',48,'全唐诗/poet.song.94000.json','["廣岸流波遠，清飈襟袖開。", "登臨忘畏景，宴息絕纖埃。", "逐渡輕雲去，零空細雨來。", "斯亭不受暑，歸客意裴回。"]'),
('c4e711fe-db39-4ee5-8b8e-5166224f8c19','寄泉州教忠光禪師','李邴','宋','宋诗','song-poetry','','[]','曩歲曾經度厄津，深將法力荷雲門。',32,'全唐诗/poet.song.94000.json','["曩歲曾經度厄津，深將法力荷雲門。", "如今稍覺神明復，擬欲酬師不報恩。"]'),
('97f7f728-3e8c-47d3-a728-93a60c896075','梅','李邴','宋','宋诗','song-poetry','','[]','綿霜歷雪忿開遲，風笛無情抵死吹。',32,'全唐诗/poet.song.94000.json','["綿霜歷雪忿開遲，風笛無情抵死吹。", "鼎實未成心尚苦，不甘桃李傍疏籬。"]'),
('e93d0719-1662-4191-9e17-84366914600f','藏六庵','李邴','宋','宋诗','song-poetry','','[]','莫言藏六便忘筌，一六俱非是本然。',32,'全唐诗/poet.song.94000.json','["莫言藏六便忘筌，一六俱非是本然。", "枯木有人能採菌，白牛無地可施牽。"]'),
('e9753681-3bdf-475d-b9d6-d611d1b3cf24','九日','李邴','宋','宋诗','song-poetry','','[]','木落霜洲溪水清，登臨滿目是飄零。',48,'全唐诗/poet.song.94000.json','["木落霜洲溪水清，登臨滿目是飄零。", "黄花有意憐幽獨，白酒無聊漫醉醒。", "牢愁錯倚西風立，楚些巴渝不可聽。"]'),
('f9a5c3fd-beb4-4122-b8c3-bbbff5c2845b','宮詞四首  其一','李邴','宋','宋诗','song-poetry','','[]','綠樹鶯啼春夢覺，樓外雞人唱清曉。',32,'全唐诗/poet.song.94000.json','["綠樹鶯啼春夢覺，樓外雞人唱清曉。", "深紅淺白競東風，爲憐滿眼枝枝好。"]'),
('df8dab21-07ef-464f-8ff7-8f637868acb0','宮詞四首  其二','李邴','宋','宋诗','song-poetry','','[]','舞袖何年絡臂韝，蛛絲網斷玉搔頭。',32,'全唐诗/poet.song.94000.json','["舞袖何年絡臂韝，蛛絲網斷玉搔頭。", "羊車一去空餘竹，紈扇相看不到秋。"]'),
('64311715-e4da-4861-b65e-c4b88982db83','宮詞四首  其三','李邴','宋','宋诗','song-poetry','','[]','鮫綃淚滴鴛鴦冷，月上欄桿照孤影。',32,'全唐诗/poet.song.94000.json','["鮫綃淚滴鴛鴦冷，月上欄桿照孤影。", "躑躅開花過粉牆，轆轤汲水敲金井。"]'),
('cf53a94f-fe00-4cf2-b8a4-8f759785fa5f','宮詞四首  其四','李邴','宋','宋诗','song-poetry','','[]','妄意長如鳳管寒，君恩不學縷衣寬。',32,'全唐诗/poet.song.94000.json','["妄意長如鳳管寒，君恩不學縷衣寬。", "漢家公主歌黄鵠，猶有琵琶馬上彈。"]'),
('61f2beb7-4fe5-4c80-9195-7c5564272eaa','戒珠寺雪軒','李邴','宋','宋诗','song-poetry','','[]','四山環繞翠岧嶢，想見凌晨雪未消。',32,'全唐诗/poet.song.94000.json','["四山環繞翠岧嶢，想見凌晨雪未消。", "八萬四千修月手，不知何處琢瓊瑤。"]'),
('bff6cc65-7b4c-481c-ac64-b362b60981f4','書台州上方不出院僧壁','李邴','宋','宋诗','song-poetry','','[]','不下山來十四年，區區笑我走塵寰。',32,'全唐诗/poet.song.94000.json','["不下山來十四年，區區笑我走塵寰。", "只應後夜經聲寂，明月清風自往還。"]'),
('44f491cb-7053-4c1b-b3bd-4ff4b6db9a5f','建炎丞相成國呂忠穆公退老堂詩','李邴','宋','宋诗','song-poetry','','[]','晉公伐叛致太平，歸來綠野勤經營。',352,'全唐诗/poet.song.94000.json','["晉公伐叛致太平，歸來綠野勤經營。", "沈淪不復經濟意，晚節更爲人所評。", "文饒佐武取河朔，平泉草木羅清英。", "功成未嘗一寓目，鑱石作記空傳名。", "何如堂堂渭川老，崛起自與天扶傾。", "歲在作噩駭機發，忠臣憤叱思殞生。", "氛埃不爲紫霄蔽，日月卻向黄道行。", "壯年鐵衣勤汗馬，白首金鼎調和羹。", "張皇國威起穨壓，約敕吏蠹歸章程。", "羌戎破膽思尋盟，盜賊脫甲來輸誠。", "轅門諸將指呼耳，公有胸中十萬兵。", "銳然請老樊小圃，爨席卻與漁樵爭。", "煙霞放目傲軒冕，水石步屧遺機衡。", "雖然四海望不置，搴旒下矚煕皇明。", "宣王于今事北伐，周公不日歌東征。", "迎還兩宮天地慶，埽灑六合風塵清。", "是時公歸迺可耳，豈得遽適羲皇情。", "祝公壽考如衛武，百歲箴儆謀群卿。", "祝公功名如郭令，身與廟社同安榮。", "忠誠向來金石貫，勳烈遂將天壤幷。", "他年升堂奉杖屨，願留隙地誅柴荆。", "但令公孫肯開閤，不用野王來撫箏。"]'),
('e0f94b27-6570-476f-8933-a21902f7759e','慶老石帆庵','李邴','宋','宋诗','song-poetry','','[]','鶉作衣裳鐵作肝，老將身事付寒巖。',65,'全唐诗/poet.song.94000.json','["鶉作衣裳鐵作肝，老將身事付寒巖。", "諸天香積猶多供，百鳥山花已罷銜。", "定起水沉和月冷，詩成冰彩敵本來緘。", "山頭畫舸誰安檝，我欲看公使石帆。"]'),
('b7880408-3723-4b5c-b0f0-230d0fe0d513','訪慶老不值','李邴','宋','宋诗','song-poetry','','[]','惠遠過溪應送陸，玉川入寺不逢曦。',32,'全唐诗/poet.song.94000.json','["惠遠過溪應送陸，玉川入寺不逢曦。", "夕陽半嶺鴉栖樹，拄杖尋山步步遲。"]'),
('b1321284-d0d3-463f-9de4-251593b15cd8','白蓮庵','李邴','宋','宋诗','song-poetry','','[]','宴坐鵲巢肩，觀花柳生肘。',24,'全唐诗/poet.song.94000.json','["宴坐鵲巢肩，觀花柳生肘。", "幽人夜半至，古月明戶牖。"]'),
('12d25b25-bd32-4dbb-9e61-982d144320e5','寶林寺','李邴','宋','宋诗','song-poetry','','[]','青燈映獨宿，世事忽如遺。',48,'全唐诗/poet.song.94000.json','["青燈映獨宿，世事忽如遺。", "一榻寒無夢，高齋靜見詩。", "長空消海氣，遠壑淡幽姿。", "欲問無生意，高人不可期。"]'),
('c0748483-1790-4e6f-a53e-bf56c8bf3f56','銅雀硯','李邴','宋','宋诗','song-poetry','','[]','魏宮歌舞已成塵，重見陶家幾世孫。',32,'全唐诗/poet.song.94000.json','["魏宮歌舞已成塵，重見陶家幾世孫。", "銅雀不鳴唯解渇，管城何罪遽遭髠。"]'),
('faa05bbb-0aeb-4218-9458-d0b09890b4fa','行田同安題康店鋪','李邴','宋','宋诗','song-poetry','','[]','短衣自獵南山虎，正好漁樵不亂群。',32,'全唐诗/poet.song.94000.json','["短衣自獵南山虎，正好漁樵不亂群。", "妄以宿嫌誅醉尉，令人翻恨李將軍。"]'),
('dc2763ba-88b6-4337-a07c-e219696c4147','謁迪上人','李邴','宋','宋诗','song-poetry','','[]','數脊招提四面山，羨師終日掩禪關。',64,'全唐诗/poet.song.94000.json','["數脊招提四面山，羨師終日掩禪關。", "憑闌人語風煙上，乞食僧來紫翠間。", "萬水深藏雲泱莽，一溪空鎖月彎環。", "十年不踏門前路，只遺松風送我還。"]'),
('a6166bc4-aa1d-4c6c-9be9-c00c347a3690','琴泉軒次韻','李邴','宋','宋诗','song-poetry','','[]','但怪朱絲韻枯木，那知古澗墜寒泉。',64,'全唐诗/poet.song.94000.json','["但怪朱絲韻枯木，那知古澗墜寒泉。", "鳥啼靜夜應傳譜，風入寒松擬續弦。", "妙體難尋斤斵處，高吟寧墮膝橫邊。", "飲光到此如欣舞，笑倒雲門逸格禪。"]'),
('930b336b-4af0-4bbb-be7e-33b4fb8416d8','句  其一','李邴','宋','宋诗','song-poetry','','[]','柳老拋綿後，梅酸著骨時。',12,'全唐诗/poet.song.94000.json','["柳老拋綿後，梅酸著骨時。"]'),
