('cc899a63-fdf0-48f4-84da-2c7c06ff5e27','題王文孺臞菴','向子諲','宋','宋诗','song-poetry','','[]','仙翁五十鬢猶青，高臥柴門晝亦扃。',64,'全唐诗/poet.song.94000.json','["仙翁五十鬢猶青，高臥柴門晝亦扃。", "茅舍已忘鐘鼎夢，蒲輪休過薜蘿亭。", "陰森門巷先生柳，寂寞江天處士星。", "晚歲田間農事了，閑鈔寗戚相牛經。"]'),
('651b4e40-869d-4558-b48a-996ef906fb41','題薌林','向子諲','宋','宋诗','song-poetry','','[]','莫問清江與洛陽，山林總是一般香。',32,'全唐诗/poet.song.94000.json','["莫問清江與洛陽，山林總是一般香。", "兩家地占西南勝，可是前人例姓楊。"]'),
('902cbf18-8894-4f22-a568-f9d9754d2e5b','題米元暉橫軸  其一','向子諲','宋','宋诗','song-poetry','','[]','早爲山谷印可，晚陪帝所清閑。',28,'全唐诗/poet.song.94000.json','["早爲山谷印可，晚陪帝所清閑。", "筆力休論扛鼎，神功更解移山。"]'),
('3bbf3097-724c-439f-8974-3777c658e932','題米元暉橫軸  其二','向子諲','宋','宋诗','song-poetry','','[]','向日家居道士，今朝落筆仙鄉。',28,'全唐诗/poet.song.94000.json','["向日家居道士，今朝落筆仙鄉。", "胸次山高水遠，筆端雲起風狂。"]'),
('cac9c61d-e041-4192-b29d-a8894f0241e4','山齋','向子諲','宋','宋诗','song-poetry','','[]','橫側數峰碧，逶迤一徑開。',24,'全唐诗/poet.song.94000.json','["橫側數峰碧，逶迤一徑開。", "無人相就宿，時有白雲來。"]'),
('fe85626b-ccfa-4499-b009-2799ad04b21e','句','向子諲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','康廬山水雄，三峽又爭長。',12,'全唐诗/poet.song.94000.json','["康廬山水雄，三峽又爭長。"]'),
('dbea538c-3122-48ce-a1b7-9537f44f63a7','爲向子諲寫卦影幷題','狄偁','宋','宋诗','song-poetry','','[]','水畔幡竿險，分符得異恩。',24,'全唐诗/poet.song.94000.json','["水畔幡竿險，分符得異恩。", "潮回波似鏡，聊以寄君身。"]'),
('a2741052-7a10-441f-b58e-f883ab7a93a8','題石橋','蔣璨','宋','宋诗','song-poetry','','[]','石橋西去接煙霞，方廣山頭佛子家。',32,'全唐诗/poet.song.94000.json','["石橋西去接煙霞，方廣山頭佛子家。", "今日我來生善念，分明盞上見茶花。"]'),
('ef889804-d8f1-48a2-93de-decf8ac2c047','過沖寂觀  其一','蔣璨','宋','宋诗','song-poetry','','[]','兔井橋邊鷁首橫，過逢仍怯近鄉情。',64,'全唐诗/poet.song.94000.json','["兔井橋邊鷁首橫，過逢仍怯近鄉情。", "路人失喜交頭語，鄰犬何知掉尾迎。", "重到雲房驚落寞，直須金闕早崇成。", "百年香火追先志，始信吾宗世濟榮。"]'),
('5d03986d-252f-4cfb-8981-dd658d36528d','過沖寂觀  其二','蔣璨','宋','宋诗','song-poetry','','[]','慣見琳宮全盛時，朅來荒梗倍傷悽。',64,'全唐诗/poet.song.94000.json','["慣見琳宮全盛時，朅來荒梗倍傷悽。", "虛堂不復瞻遺蹟，敗壁纔容覓舊題。", "帝傅前修皆榘矱，雲孫後裔合攀躋。", "興衰補弊應商略，徙倚修廊日欲西。"]'),
('a06807d4-c3a3-440a-8001-9d078d31abfe','句','蔣璨','宋','宋诗','song-poetry','','[]','正索解人那復得，其誰知我固無從。',16,'全唐诗/poet.song.94000.json','["正索解人那復得，其誰知我固無從。"]'),
('a9af26a1-7664-490d-86e9-875431f6f95a','偈','釋如勝','宋','宋诗','song-poetry','','[]','人人領略釋迦，箇箇平欺達磨。',28,'全唐诗/poet.song.94000.json','["人人領略釋迦，箇箇平欺達磨。", "及乎問著宗綱，束手盡云放過。"]'),
('378bf0d5-0ee9-4342-9ba6-3dead8dbebc9','參玄歌','釋道川','宋','宋诗','song-poetry','','[]','一尺水，一丈波，妙高峰頂笑呵呵。',383,'全唐诗/poet.song.94000.json','["一尺水，一丈波，妙高峰頂笑呵呵。", "七步周行渾屬我，不妨閑唱太平歌。", "靈利漢，不消多，法門廣大徧周沙。", "若能當處分明了，只在如今一剎那。", "莫求真，休覓假，真假中間都放下。", "晃晃威光爍太虛，不知誰是知音者。", "讚不欣，徒說謗，三際無心俱掃蕩。", "正體堂堂一物無，是佛是魔俱一棒。", "小根聞說暗攢眉，繩上生虵又更疑。", "撥轉面前關棙子，只許當人獨自知。", "阿呵呵，在圓覺，流出菩提遍寥廓。", "鬼面神頭幾百般，無瑕鏡裏皆消卻。", "君不見覿面相逢機掣電，直饒天眼不能觀，點著不來真死漢。", "勸君參，參徹靈明自己禪。", "善財不用南方去，黑白分明在目前。", "勸君信，信心戰退魔軍陣。", "此是華嚴最上乘，森羅萬象皆相應。", "勸君修，六門通達任優游。", "寒山拾得纔相見，指點豐干哂未休。", "火風催，四山逼，那時要見君端的。", "有箇真空解脫門，千眼大悲何處覓。", "有時放，有時收，唯有知音暗點頭。", "杏華村裏如相見，跳出溈山水牯牛。", "有時喜，有時嗔，無位真人迸面門。"]'),
('1c5fa8b2-0c87-4272-9050-c500fa8c003d','偈二首  其一','釋道川','宋','宋诗','song-poetry','','[]','群陰剝盡一陽生，草木園林盡發萌。',32,'全唐诗/poet.song.94000.json','["群陰剝盡一陽生，草木園林盡發萌。", "唯有衲僧無底鉢，依前盛飯又盛羹。"]'),
('1b16f10c-e99a-4c67-90c7-4d1e2c8862ec','偈二首  其二','釋道川','宋','宋诗','song-poetry','','[]','東邊覷了復西觀，拄杖重重話歲寒。',32,'全唐诗/poet.song.94000.json','["東邊覷了復西觀，拄杖重重話歲寒。", "带雨一枝花落盡，不煩公子倚欄干。"]'),
('23c6f7e7-34cf-44fc-a8d4-e9441bf0c302','頌古二十八首  其一','釋道川','宋','宋诗','song-poetry','','[]','明鏡當臺照不差，短長子醜盡歸家。',32,'全唐诗/poet.song.94000.json','["明鏡當臺照不差，短長子醜盡歸家。", "山河大地渾如故，不妨隨處翫煙霞。"]'),
('60c173c6-5579-4170-8295-78bede910688','頌古二十八首  其二','釋道川','宋','宋诗','song-poetry','','[]','東西南北水茫茫，無角鐵牛入海藏。',32,'全唐诗/poet.song.94000.json','["東西南北水茫茫，無角鐵牛入海藏。", "千眼大悲尋不見，倒騎佛殿入僧堂。"]'),
('7c98f5a5-63ea-4661-9ca5-062a7e357da3','頌古二十八首  其三','釋道川','宋','宋诗','song-poetry','','[]','蝴蜂休戀舊時窼，五百郎君不奈何。',64,'全唐诗/poet.song.94000.json','["蝴蜂休戀舊時窼，五百郎君不奈何。", "慾火逼來無走路，癡心要上白牛車。", "門前羊鹿權爲喻，室內啀喍總是訛。", "蓬㶿臭煙相惱處，出身不用動干戈。"]'),
('213ed216-2e24-4369-b02d-2b43fc3c1e22','頌古二十八首  其四','釋道川','宋','宋诗','song-poetry','','[]','觀音門普普門收，纔著襴衫便不羞。',64,'全唐诗/poet.song.94000.json','["觀音門普普門收，纔著襴衫便不羞。", "昨夜猿啼新嶺上，今朝鶴唳古溪頭。", "惡風飄墮迴光息，慾火焚燒當處休。", "瓔珞受來都不用，平生活計冷湫湫。"]'),
('b5eef4d9-c970-4cad-ae01-1fcdfeacf0c6','頌古二十八首  其五','釋道川','宋','宋诗','song-poetry','','[]','七手八腳，神頭鬼面。',36,'全唐诗/poet.song.94000.json','["七手八腳，神頭鬼面。", "棒打不開，刀割不斷。", "閻浮跳躑月千回，頭頭不離空王殿。"]'),
('c64ed4c8-a28a-4cac-9ed1-621a5d868a3a','頌古二十八首  其六','釋道川','宋','宋诗','song-poetry','','[]','有相有求皆是妄，無形無相墮偏枯。',32,'全唐诗/poet.song.94000.json','["有相有求皆是妄，無形無相墮偏枯。", "堂堂密密何曾間，一道寒光爍太虛。"]'),
('319d934c-479d-473c-a42c-cb6b2ef3a1a9','頌古二十八首  其七','釋道川','宋','宋诗','song-poetry','','[]','山堂靜坐夜無言，寂寂寥寥本自然。',32,'全唐诗/poet.song.94000.json','["山堂靜坐夜無言，寂寂寥寥本自然。", "何事西風動林野，一聲寒雁淚長天。"]'),
('353cf72e-aef0-4bc8-bb07-dd38f3322f5b','頌古二十八首  其八','釋道川','宋','宋诗','song-poetry','','[]','生涯如夢若浮雲，活計都無絕六親。',32,'全唐诗/poet.song.94000.json','["生涯如夢若浮雲，活計都無絕六親。", "留得一雙青白眼，笑他無限往來人。"]'),
('4e9bc515-819c-45ef-9220-9d483b5e6fe3','頌古二十八首  其九','釋道川','宋','宋诗','song-poetry','','[]','三際求心心不見，兩眼依然對兩觀。',32,'全唐诗/poet.song.94000.json','["三際求心心不見，兩眼依然對兩觀。", "不須遺劍刻舟尋，雪月風華常見面。"]'),
('2168bfb7-18a0-4af4-acd3-048b0f95d46c','頌古二十八首  其一○','釋道川','宋','宋诗','song-poetry','','[]','水中捉月，鏡裏尋頭。',56,'全唐诗/poet.song.94000.json','["水中捉月，鏡裏尋頭。", "刻舟求劍，騎牛覓牛。", "空花陽焰，夢幻浮漚。", "一筆勾斷，要休更休。", "巴歌杜酒村田樂，不風流處也風流。"]'),
('d9065544-b174-4386-8195-5718ca9e75b7','頌古二十八首  其一一','釋道川','宋','宋诗','song-poetry','','[]','他心三藏太顢頇，猢孫觀了看劃船。',32,'全唐诗/poet.song.94000.json','["他心三藏太顢頇，猢孫觀了看劃船。", "對面國師尋不見，祇爲從來被眼謾。"]'),
('3367a67c-26b4-4030-bc86-67a455aacfb3','頌古二十八首  其一二','釋道川','宋','宋诗','song-poetry','','[]','生死有無佛，虛名如電拂。',40,'全唐诗/poet.song.94000.json','["生死有無佛，虛名如電拂。", "俊鷂博天飛，不打籬邊鶻。", "無欠無餘若太虛，不知誰解強名模。"]'),
('7d07e1fb-2358-4ac2-8fb8-a9dc2dbb11ec','頌古二十八首  其一三','釋道川','宋','宋诗','song-poetry','','[]','三尺寒光射斗牛，鏌鋣提處鬼神愁。',32,'全唐诗/poet.song.94000.json','["三尺寒光射斗牛，鏌鋣提處鬼神愁。", "蠻夷不識軍將令，誤入重圍血頸流。"]'),
('599c39dc-0562-4f4a-82ca-01f32af46700','頌古二十八首  其一四','釋道川','宋','宋诗','song-poetry','','[]','三佛形容總不真，眼中瞳子面前人。',32,'全唐诗/poet.song.94000.json','["三佛形容總不真，眼中瞳子面前人。", "若能信得家中寶，啼鳥山花一樣春。"]'),
('57a39bd3-cb90-4635-bffe-7adc959c9742','頌古二十八首  其一五','釋道川','宋','宋诗','song-poetry','','[]','臺山路，驀直去，趙老見婆無別語。',32,'全唐诗/poet.song.94000.json','["臺山路，驀直去，趙老見婆無別語。", "勘破回來知不知，莫信閑人說是非。"]'),
('3bcc90d9-46f8-495e-b340-29fa9e52180b','頌古二十八首  其一六','釋道川','宋','宋诗','song-poetry','','[]','避暑逃寒問是非，不離寒暑少人知。',48,'全唐诗/poet.song.94000.json','["避暑逃寒問是非，不離寒暑少人知。", "正中來也無回互，句裏藏鋒辨者稀。", "嚴天雪，火雪飛，風吹日炙杜闍黎。"]'),
('5b5d4e4a-c3fb-4f5d-b61e-3e66a8aef2b9','頌古二十八首  其一七','釋道川','宋','宋诗','song-poetry','','[]','演出大藏教，言端語亦端。',24,'全唐诗/poet.song.94000.json','["演出大藏教，言端語亦端。", "兩頭都坐斷，一劍倚天寒。"]'),
('2bd9a65b-b89e-42b2-8dfe-37a0ae5ff8c7','頌古二十八首  其一八','釋道川','宋','宋诗','song-poetry','','[]','罰錢出院，衆人皆見。',46,'全唐诗/poet.song.94000.json','["罰錢出院，衆人皆見。", "有理難伸，風流滿面。", "直饒興化全提，未免令行一半。", "這一半，明眼衲僧點檢看。"]'),
('2ce64704-3735-4357-9173-78fc3d1dc0e1','頌古二十八首  其一九','釋道川','宋','宋诗','song-poetry','','[]','現出虛空眼便花，更教打破事如麻。',33,'全唐诗/poet.song.94000.json','["現出虛空眼便花，更教打破事如麻。", "直饒指出當堂這縫，分明鷂子過新羅。"]'),
('057b5c36-16fb-4212-a0da-e1d4c135c25e','頌古二十八首  其二○','釋道川','宋','宋诗','song-poetry','','[]','分明柑橘勿譊訛，獻花借水辨龍蛇。',32,'全唐诗/poet.song.94000.json','["分明柑橘勿譊訛，獻花借水辨龍蛇。", "白紙一張都蓋了，免教天下動干戈。"]'),
('b7c72bd1-a33f-4e8e-bafc-337efe5d331d','頌古二十八首  其二一','釋道川','宋','宋诗','song-poetry','','[]','高聲撥火招司徒，火焰炎天驀面驅。',32,'全唐诗/poet.song.94000.json','["高聲撥火招司徒，火焰炎天驀面驅。", "祇向此間能穩坐，任教門外雪盈衢。"]'),
('09266b8f-3538-455d-bc6b-19bf90fd0051','頌古二十八首  其二二','釋道川','宋','宋诗','song-poetry','','[]','語不邪，笑不來。',28,'全唐诗/poet.song.94000.json','["語不邪，笑不來。", "拙鋪設，巧安排。", "猢猻將板拍，野老舞三臺。"]'),
('ed3300c4-d1b6-4415-9f62-7e5f6546027a','頌古二十八首  其二三','釋道川','宋','宋诗','song-poetry','','[]','師子咬人，狂狗逐塊。',26,'全唐诗/poet.song.94000.json','["師子咬人，狂狗逐塊。", "三十里來方始悟，何似當初莫入去。"]'),
('a2aef016-ea33-47bb-96c6-452fef7ee09d','頌古二十八首  其二四','釋道川','宋','宋诗','song-poetry','','[]','休爭自己與山河，撥動干戈不奈何。',32,'全唐诗/poet.song.94000.json','["休爭自己與山河，撥動干戈不奈何。", "看取將軍施武略，兩條寒劍定龍蛇。"]'),
('d527d430-69f9-4f52-b941-50adb0b8893b','頌古二十八首  其二五','釋道川','宋','宋诗','song-poetry','','[]','丙丁童子來求火，再問炎炎燎面門。',32,'全唐诗/poet.song.94000.json','["丙丁童子來求火，再問炎炎燎面門。", "過現未來三世佛，不離其中轉法輪。"]'),
('14a20f2a-3720-4892-b0af-a61396f80703','頌古二十八首  其二六','釋道川','宋','宋诗','song-poetry','','[]','問如綿裏針，答似泥中刺。',84,'全唐诗/poet.song.94000.json','["問如綿裏針，答似泥中刺。", "咆哮二虎吼生獰，各各利牙斤可怖。", "坐卻碧峰頭，截斷當陽路。", "直饒擎出秘魔叉，路狹草深難進步。", "相見不相逢，回互不回互。", "四七二三眼相睹，雲從龍兮風從虎。"]'),
('1d53f6c8-8029-4c29-9660-c5e0c7c38028','頌古二十八首  其二七','釋道川','宋','宋诗','song-poetry','','[]','將杖探其水，方知水淺深。',54,'全唐诗/poet.song.94000.json','["將杖探其水，方知水淺深。", "路遙知馬力，歲久辨人心。", "子不孝，父不慈。", "恭而無禮，親而有疏。", "不入驚人浪，難逢稱意魚。"]'),
('3559d1bb-5193-4294-9387-76fc953787d4','偈二首  其一','釋元素','宋','宋诗','song-poetry','','[]','大丈夫，秉慧劍，般若鋒兮金剛焰。',32,'全唐诗/poet.song.94000.json','["大丈夫，秉慧劍，般若鋒兮金剛焰。", "非但能摧外道心，早曾落卻天魔膽。"]'),
('94472c27-f040-45ae-8baf-f8fb7577b3d2','偈二首  其二','釋元素','宋','宋诗','song-poetry','','[]','未開口時先分付，擬思量處隔千山。',32,'全唐诗/poet.song.94000.json','["未開口時先分付，擬思量處隔千山。", "莫言佛法無多子，未透玄關也大難。"]'),
('44cda99a-35fb-4847-a903-b2310309c6da','偈二十二首  其一','釋洵','宋','宋诗','song-poetry','','[]','窮谷無人作上元，一燈歷劫鎮長存。',65,'全唐诗/poet.song.94000.json','["窮谷無人作上元，一燈歷劫鎮長存。", "諸人盡在光明裏，看時不見暗昏昏。", "燈籠與露柱相交，佛殿與三門鬬額。", "留雪罰嶂橫趍下海，九疊峰𨁝跳上天。"]'),
('dff16bd7-4dc9-4a32-b9f0-4139431bb105','偈二十二首  其二','釋洵','宋','宋诗','song-poetry','','[]','朔風掃地卷黄葉，門外千峰凜寒色。',32,'全唐诗/poet.song.94000.json','["朔風掃地卷黄葉，門外千峰凜寒色。", "夜半烏龜带雪飛，石女溪頭皺用眉。"]'),
('7fdeccf3-543a-4057-9a61-bb59340430ca','偈二十二首  其三','釋洵','宋','宋诗','song-poetry','','[]','萬人叢裏求知已，百草頭邊識老僧。',32,'全唐诗/poet.song.94000.json','["萬人叢裏求知已，百草頭邊識老僧。", "從此更無回避處，三頭兩面得人憎。"]'),
('7ff453f7-c049-4423-a72b-e7fb22927959','偈二十二首  其四','釋洵','宋','宋诗','song-poetry','','[]','有佛處，不得住，藕絲孔裏行官路。',32,'全唐诗/poet.song.94000.json','["有佛處，不得住，藕絲孔裏行官路。", "無佛處，急走過，十字街頭相對坐。"]'),
('c6125758-e9e7-46c2-b367-1fcca48c770b','偈二十二首  其五','釋洵','宋','宋诗','song-poetry','','[]','拽回天關，踏翻地軸。',32,'全唐诗/poet.song.94000.json','["拽回天關，踏翻地軸。", "拄杖化爲龍，一雨沛然足。", "在坑滿坑，在谷盈谷。"]'),
('890b720f-0d4a-4fc5-9241-5faea6bf2dfc','偈二十二首  其六','釋洵','宋','宋诗','song-poetry','','[]','一葉翻空便見秋，不風流處也風流。',32,'全唐诗/poet.song.94000.json','["一葉翻空便見秋，不風流處也風流。", "當頭薦得便歸去，看取木人騎土牛。"]'),
('9f21ee6e-073a-474e-ad6a-da79e7cdef1d','偈二十二首  其七','釋洵','宋','宋诗','song-poetry','','[]','是非海裏橫身入，豺虎群中放步行。',100,'全唐诗/poet.song.94000.json','["是非海裏橫身入，豺虎群中放步行。", "自是渠儂無影迹，從教天下競頭爭。", "常在動用中，動用收不得。", "常在萬象中，出萬象一頭。", "你若簸土揚塵，我則空澄海湛。", "你若單提獨弄，我則豎四橫三。", "不是渠儂多意氣，他家曾踏上頭關。"]'),
('91f32091-0dd6-41e2-ae4e-319a5fcd2de8','偈二十二首  其八','釋洵','宋','宋诗','song-poetry','','[]','天下無二道，聖賢無兩心。',24,'全唐诗/poet.song.94000.json','["天下無二道，聖賢無兩心。", "世尊不說說，迦葉不聞聞。"]'),
('103208b0-53da-45a2-8011-4cdf2981f991','偈二十二首  其九','釋洵','宋','宋诗','song-poetry','','[]','針劄不到處，放下死蛇頭。',48,'全唐诗/poet.song.94000.json','["針劄不到處，放下死蛇頭。", "唱拍相應時，權塵俱脫盡。", "明眼漢，沒窼臼。", "百尺竿頭放步行，大洋海裏和身倒。"]'),
('2465d6a2-5a84-4962-8e6e-a9f382ea2112','偈二十二首  其一○','釋洵','宋','宋诗','song-poetry','','[]','掩室摩竭，正令已行。',40,'全唐诗/poet.song.94000.json','["掩室摩竭，正令已行。", "杜口毗耶，全機脫略。", "更來開口，猶欠三拳。", "擬欲吞聲，不消一钁。"]'),
('b6cb6b25-a474-4c28-834c-441622dd6d74','偈二十二首  其一一','釋洵','宋','宋诗','song-poetry','','[]','歲月去人如箭急，一年祇有十五日。',32,'全唐诗/poet.song.94000.json','["歲月去人如箭急，一年祇有十五日。", "雪砌禪人總不知，但見鉢盂兩度濕。"]'),
('d0b31ec6-79fb-45f3-b01e-995cc53031f2','偈二十二首  其一二','釋洵','宋','宋诗','song-poetry','','[]','不是玄妙奇特，亦非聖解凡情。',30,'全唐诗/poet.song.94000.json','["不是玄妙奇特，亦非聖解凡情。", "茂林芳草摧殘盡，坐看春風吹又青。"]'),
('eb0294b9-6b2f-47bd-a639-3719cd5f33c5','偈二十二首  其一三','釋洵','宋','宋诗','song-poetry','','[]','榕溪脈脈，鹿嶺巉巉。',36,'全唐诗/poet.song.94000.json','["榕溪脈脈，鹿嶺巉巉。", "龍象蹴踏，前三後三。", "二人一見便歸去，何待山堂更指南。"]'),
('1f0a80b2-6cc5-4e6c-8c98-c760a4d20088','偈二十二首  其一四','釋洵','宋','宋诗','song-poetry','','[]','吾君收得中原寶，塞外煙塵凈如掃。',32,'全唐诗/poet.song.94000.json','["吾君收得中原寶，塞外煙塵凈如掃。", "萬國歌謠賀太平，家家門館長安道。"]'),
('480695fa-ab05-4fe6-a81a-b68725be23ef','偈二十二首  其一五','釋洵','宋','宋诗','song-poetry','','[]','春風吹裂峰頭石，晏下東峰絕蹤跡。',32,'全唐诗/poet.song.94000.json','["春風吹裂峰頭石，晏下東峰絕蹤跡。", "日輪正午現全身，生鐵蒺藜當面擲。"]'),
('975a16a7-6257-4a8e-a39f-28a91fd40456','偈二十二首  其一六','釋洵','宋','宋诗','song-poetry','','[]','三年來在此山中，上下人情貴一同。',32,'全唐诗/poet.song.94000.json','["三年來在此山中，上下人情貴一同。", "今日溪頭休惜別，德雲祇在妙高峰。"]'),
('6f180952-35ce-4fd8-914e-39339099aef5','偈二十二首  其一七','釋洵','宋','宋诗','song-poetry','','[]','頭顱百皺髪又白，兩手扶犁更出來。',54,'全唐诗/poet.song.94000.json','["頭顱百皺髪又白，兩手扶犁更出來。", "拈起舊時氈拍板，大家看我舞三臺。", "囉囉哩，囉囉哩。", "無處有月波澄，有處無風浪起。"]'),
('290f418b-8cb6-40c0-bc6a-1c94fa73213e','偈二十二首  其一八','釋洵','宋','宋诗','song-poetry','','[]','昔人三箭定天山，自謂英雄蓋世間。',32,'全唐诗/poet.song.94000.json','["昔人三箭定天山，自謂英雄蓋世間。", "何似雪峰一隻箭，等閑穿過石門關。"]'),
('9aea7f69-0f1e-4981-a149-602b21733325','偈二十二首  其一九','釋洵','宋','宋诗','song-poetry','','[]','月不堪破五，衲僧猛提取。',36,'全唐诗/poet.song.94000.json','["月不堪破五，衲僧猛提取。", "打動東海魚，失卻南山虎。", "借問是何宗，逢人莫錯舉。"]'),
('802f4487-131d-48b6-968c-06cedb6b1892','偈二十二首  其二○','釋洵','宋','宋诗','song-poetry','','[]','髑髏捻碎眼睛寒，便把南辰對北看。',32,'全唐诗/poet.song.94000.json','["髑髏捻碎眼睛寒，便把南辰對北看。", "無限風流慵賣弄，乘時推倒鐵圍山。"]'),
('0344a7f6-f5c8-4920-bcd2-72daae83544f','偈二十二首  其二一','釋洵','宋','宋诗','song-poetry','','[]','安居無相大伽藍，莫問前三與後三。',32,'全唐诗/poet.song.94000.json','["安居無相大伽藍，莫問前三與後三。", "箇裏不容生一念，龍蛇猿鳥自相參。"]'),
('fa2e8fc8-6f3d-43be-8d74-93479645f745','偈二十二首  其二二','釋洵','宋','宋诗','song-poetry','','[]','若欲正提綱，直教大地荒。',24,'全唐诗/poet.song.94000.json','["若欲正提綱，直教大地荒。", "擬來衝雪刃，不免露鋒鋩。"]'),
('99de0034-0866-4211-97b0-6310208e8409','偈三十五首  其一','釋祖珍','宋','宋诗','song-poetry','','[]','青氈本屬吾家，日用何曾欠闕。',28,'全唐诗/poet.song.94000.json','["青氈本屬吾家，日用何曾欠闕。", "要識裏許清規，除是君子可八。"]'),
('f582114e-e794-4c30-ae3d-a9d645011868','偈三十五首  其二','釋祖珍','宋','宋诗','song-poetry','','[]','非衣不傳於法，非法不授於衣。',40,'全唐诗/poet.song.94000.json','["非衣不傳於法，非法不授於衣。", "衣既已授，法若爲傳。", "玲瓏八面自回合，峭峻一方誰敢窺。"]'),
('2e19b98d-b3fe-47f3-889e-0436cf67051a','偈三十五首  其三','釋祖珍','宋','宋诗','song-poetry','','[]','高而無上不可極，淵而無下不可測。',32,'全唐诗/poet.song.94000.json','["高而無上不可極，淵而無下不可測。", "欲知步步透雙關，看取清風生兩腋。"]'),
('b40218f5-8aa7-4f04-bb1d-0b679c134c7a','偈三十五首  其四','釋祖珍','宋','宋诗','song-poetry','','[]','自慚疏拙百無能，下板長行粥飯僧。',32,'全唐诗/poet.song.94000.json','["自慚疏拙百無能，下板長行粥飯僧。", "豈謂因緣有僥倖，千斤擔子若爲勝。"]'),
('4fae28cc-5f33-4d52-a216-e10099035cfe','偈三十五首  其五','釋祖珍','宋','宋诗','song-poetry','','[]','二月春將半，桃花開爛熳。',24,'全唐诗/poet.song.94000.json','["二月春將半，桃花開爛熳。", "紛紛尋劍客，誰是不疑漢。"]'),
('9653c8bf-0cae-479c-b071-eb662e35b3c8','偈三十五首  其六','釋祖珍','宋','宋诗','song-poetry','','[]','百歲光陰如劈箭，無常生滅日遷變。',48,'全唐诗/poet.song.94000.json','["百歲光陰如劈箭，無常生滅日遷變。", "唯有摩訶般若多，耀古騰今無背面。", "見不見，碗子撲落地，碟子成八片。"]'),
('0270a4dd-ac20-4315-8585-8632aeb040a5','偈三十五首  其七','釋祖珍','宋','宋诗','song-poetry','','[]','十五日已前，藏身處沒蹤跡。',55,'全唐诗/poet.song.94000.json','["十五日已前，藏身處沒蹤跡。", "十五日已後，沒蹤跡處莫藏身。", "正當十五日，布袋頭開，全身顯露。", "不憐鵝護雪，且喜蠟入冰。"]'),
('eb62b40c-3be6-41a9-a022-2e3ce1636424','偈三十五首  其八','釋祖珍','宋','宋诗','song-poetry','','[]','長年追逐走埃塵，嬴得閑名累此身。',32,'全唐诗/poet.song.94000.json','["長年追逐走埃塵，嬴得閑名累此身。", "爭似別峰峰頂上，一菴高臥與雲鄰。"]'),
('f39aa7cb-8081-45b1-9e0f-6a856f2fd24d','偈三十五首  其九','釋祖珍','宋','宋诗','song-poetry','','[]','巖谷相從始晏然，又攜瓶錫應時緣。',32,'全唐诗/poet.song.94000.json','["巖谷相從始晏然，又攜瓶錫應時緣。", "奉川此去無多遠，興發何妨訪戴船。"]'),
('c2e23745-94a3-48bc-ae13-bcb641fe799c','偈三十五首  其一○','釋祖珍','宋','宋诗','song-poetry','','[]','衰老百一堪，擔頭入鬧籃。',24,'全唐诗/poet.song.94000.json','["衰老百一堪，擔頭入鬧籃。", "生涯何所有，彌勒是同龕。"]'),
('7d58e4c1-a2b9-4847-964b-061c666cd8fa','偈三十五首  其一一','釋祖珍','宋','宋诗','song-poetry','','[]','大道只在目前，要且目前難睹。',28,'全唐诗/poet.song.94000.json','["大道只在目前，要且目前難睹。", "欲識大道真體，不離聲色言語。"]'),
('5870ba04-b8ba-422b-ac6f-38ec8c3b0d8b','偈三十五首  其一二','釋祖珍','宋','宋诗','song-poetry','','[]','尋牛須訪跡，學道訪無心。',24,'全唐诗/poet.song.94000.json','["尋牛須訪跡，學道訪無心。", "跡在牛還在，無心道易尋。"]'),
('09a1d174-8f5a-48c3-810f-b75eb6c3b7c4','偈三十五首  其一三','釋祖珍','宋','宋诗','song-poetry','','[]','離四句，絕百非，頭長三尺知是誰。',32,'全唐诗/poet.song.94000.json','["離四句，絕百非，頭長三尺知是誰。", "江北江南問王老，一狐疑了一狐疑。"]'),
('76fa9953-cd26-40d5-a212-2b92f9e6a616','偈三十五首  其一四','釋祖珍','宋','宋诗','song-poetry','','[]','佛不遠人，即心而證。',20,'全唐诗/poet.song.94000.json','["佛不遠人，即心而證。", "法無所著，觸境皆如。"]'),
('1d2a8d4b-ee21-476a-b7e3-7d1a0ca4a0f3','偈三十五首  其一五','釋祖珍','宋','宋诗','song-poetry','','[]','向上一路，千聖不傳。',36,'全唐诗/poet.song.94000.json','["向上一路，千聖不傳。", "恁麽明得，十萬八千。", "桃紅李白薔薇紫，問著春風總不知。"]'),
('41384ae0-f42b-4b9d-a713-da196ea06df5','偈三十五首  其一六','釋祖珍','宋','宋诗','song-poetry','','[]','春已去，夏初臨，相逢休話本來心。',32,'全唐诗/poet.song.94000.json','["春已去，夏初臨，相逢休話本來心。", "隨緣齋粥海山寺，從聽堂前草自深。"]'),
('911e0da2-524b-4764-beb2-91cf54b1d2d7','偈三十五首  其一七','釋祖珍','宋','宋诗','song-poetry','','[]','吾心似秋月，碧潭清皎潔。',24,'全唐诗/poet.song.94000.json','["吾心似秋月，碧潭清皎潔。", "無物堪比倫，教我如何說。"]'),
('e71c64c1-6894-4fce-9071-079c7045f5e0','偈三十五首  其一八','釋祖珍','宋','宋诗','song-poetry','','[]','諸人被十二時使，老僧使得十二時。',32,'全唐诗/poet.song.94000.json','["諸人被十二時使，老僧使得十二時。", "牧童嶺上一聲笛，驚起群鴉繞樹飛。"]'),
('b57f2fd1-e058-43eb-b6b7-fb4c95742552','偈三十五首  其一九','釋祖珍','宋','宋诗','song-poetry','','[]','飄空一葉兩新收，暑退涼生萬壑秋。',32,'全唐诗/poet.song.94000.json','["飄空一葉兩新收，暑退涼生萬壑秋。", "貼肉汗衫纔脫下，橫吹木笛倒騎牛。"]'),
('78af55a8-8dad-46be-ab45-f4869d5fbcaa','偈三十五首  其二○','釋祖珍','宋','宋诗','song-poetry','','[]','物物到心上，全心物自閑。',24,'全唐诗/poet.song.94000.json','["物物到心上，全心物自閑。", "古今城郭裏，得者住如山。"]'),
('850f72a6-559e-4617-8cdf-7b05a5a619d1','偈三十五首  其二一','釋祖珍','宋','宋诗','song-poetry','','[]','九夏斯臨結集時，滿堂雲水復明誰。',32,'全唐诗/poet.song.94000.json','["九夏斯臨結集時，滿堂雲水復明誰。", "若言相見交肩過，未免依前落見知。"]'),
('4bbf218b-74e4-4e1c-bb2a-5c696ef24277','偈三十五首  其二二','釋祖珍','宋','宋诗','song-poetry','','[]','十五日已前，過去心不可得。',51,'全唐诗/poet.song.94000.json','["十五日已前，過去心不可得。", "十五日已後，未來心不可得。", "正當十五日，現在心不可得。", "三心既不有，萬象復明誰。"]'),
('ec8fa221-d022-480c-8362-88e3842caad1','偈三十五首  其二三','釋祖珍','宋','宋诗','song-poetry','','[]','文殊三處度夏，別峰兩院禁足。',28,'全唐诗/poet.song.94000.json','["文殊三處度夏，別峰兩院禁足。", "誰知把住放行，盡道違真逆俗。"]'),
('57e3a3dd-0845-4967-8a11-09d85ee3f98e','偈三十五首  其二四','釋祖珍','宋','宋诗','song-poetry','','[]','知幻即離，不作方便。',20,'全唐诗/poet.song.94000.json','["知幻即離，不作方便。", "離幻即覺，亦無漸次。"]'),
('165ff523-f04a-498f-b008-c41b6c45db58','偈三十五首  其二五','釋祖珍','宋','宋诗','song-poetry','','[]','青春已去，朱夏斯臨。',52,'全唐诗/poet.song.94000.json','["青春已去，朱夏斯臨。", "放下橫肩楖𣗖，宴坐古佛叢林。", "荆山之璞不須覓，赤水之珠何用尋。", "縱饒尋覓得，失卻本來心。"]'),
('9449fa31-84a6-4fb7-85a4-e28f7b5280ad','偈三十五首  其二六','釋祖珍','宋','宋诗','song-poetry','','[]','我所得智慧，微妙最第一。',24,'全唐诗/poet.song.94000.json','["我所得智慧，微妙最第一。", "衆生諸根鈍，著樂癡所盲。"]'),
('18c34a0d-b015-4ab7-91b9-ebd267839fca','偈三十五首  其二七','釋祖珍','宋','宋诗','song-poetry','','[]','眼若不睡，諸夢自除。',20,'全唐诗/poet.song.94000.json','["眼若不睡，諸夢自除。", "心若不異，萬法一如。"]'),
('76d65068-6800-473a-9191-030e023551c9','偈三十五首  其二八','釋祖珍','宋','宋诗','song-poetry','','[]','有句無句，如藤倚樹。',20,'全唐诗/poet.song.94000.json','["有句無句，如藤倚樹。", "眼睛定動，失卻巴鼻。"]'),
('7207bf39-392b-4d4d-ae55-6b91e038687f','偈三十五首  其二九','釋祖珍','宋','宋诗','song-poetry','','[]','向上一路，千聖不傳。',20,'全唐诗/poet.song.94000.json','["向上一路，千聖不傳。", "學者勞形，如猿捉影。"]'),
('7db00b0e-37d2-4f44-a43a-41ef812df2f5','偈三十五首  其三○','釋祖珍','宋','宋诗','song-poetry','','[]','斷除鬚髪著僧衣，精進當遵古佛儀。',32,'全唐诗/poet.song.94000.json','["斷除鬚髪著僧衣，精進當遵古佛儀。", "一念不生親領略，方知我法妙難思。"]'),
('4f5492c2-3622-4b9d-aa95-e0118a56300a','偈三十五首  其三一','釋祖珍','宋','宋诗','song-poetry','','[]','心月孤圓，虛明洞透。',21,'全唐诗/poet.song.94000.json','["心月孤圓，虛明洞透。", "曉耀古輝今，絲毫不漏。"]'),
('90b93740-b9df-4858-8022-d35e7e1fda70','偈三十五首  其三二','釋祖珍','宋','宋诗','song-poetry','','[]','靈文一閱五千卷，感果當知越四禪。',32,'全唐诗/poet.song.94000.json','["靈文一閱五千卷，感果當知越四禪。", "應笑毗耶方丈裏，卻容天女問因緣。"]'),
('ff406aee-b507-40c8-adb1-08b2f1e7272c','偈三十五首  其三三','釋祖珍','宋','宋诗','song-poetry','','[]','蔡居士，昔也恁麽來，今也恁麽去。',43,'全唐诗/poet.song.94000.json','["蔡居士，昔也恁麽來，今也恁麽去。", "今昔兩無殊，去來擬何處。", "住住，明明百草頭，明明無生路。"]'),
('5369baed-8d77-4ab2-8147-a46e375df169','偈三十五首  其三四','釋祖珍','宋','宋诗','song-poetry','','[]','陋巷閉門唯讀書，了無塵果自如初。',32,'全唐诗/poet.song.94000.json','["陋巷閉門唯讀書，了無塵果自如初。", "時來坐脫西窗下，驚起須彌遶太虛。"]'),
('7cbc9ac0-1d25-49d9-bdd3-141435e44976','偈三十五首  其三五','釋祖珍','宋','宋诗','song-poetry','','[]','是處青山可垛跟，白雲流水繞孤村。',32,'全唐诗/poet.song.94000.json','["是處青山可垛跟，白雲流水繞孤村。", "笑攜拄杖出門去，三世誰知一口吞。"]'),
('eedb9b74-dab2-43c7-8299-8237cf0f2d76','游龍湫拜諾矩羅尊者','釋祖珍','宋','宋诗','song-poetry','','[]','十里松溪到上流，斷崖千尺瀉龍湫。',32,'全唐诗/poet.song.94000.json','["十里松溪到上流，斷崖千尺瀉龍湫。", "誰言尊者心無著，冷眼長年看不休。"]'),
('5c1276c4-1263-46b2-9326-01c0141df5ba','臨終偈','釋祖珍','宋','宋诗','song-poetry','','[]','生本無生，死本無死。',20,'全唐诗/poet.song.94000.json','["生本無生，死本無死。", "生死二途，了無彼此。"]'),
('b7a23d8f-fd1b-41c3-ba7a-96d4ef07679c','偈二首  其一','釋擇崇','宋','宋诗','song-poetry','','[]','柴鳴竹爆驚人耳，大洋海底紅塵起。',80,'全唐诗/poet.song.94000.json','["柴鳴竹爆驚人耳，大洋海底紅塵起。", "家犬聲獰夜不休，陸地行船三萬里。", "堅牢地神笑呵呵，須彌山王眼覷鼻。", "把我東行卻向西，南山聲應北山裏。", "千手大悲開眼看，無量慈悲是誰底。"]'),
('4629719b-ed18-4203-a71a-03f3b86e3228','偈二首  其二','釋擇崇','宋','宋诗','song-poetry','','[]','西山青，無謂情。',52,'全唐诗/poet.song.94000.json','["西山青，無謂情。", "洪井碧，無涓滴。", "西山人，見曷親。", "西山事，無可似。", "若是靈利底舉著便知，懵懂者付與德山臨濟。"]'),
('9cb647d1-07d1-41e9-8133-b1da2c69d3cc','頌古二首  其一','釋擇崇','宋','宋诗','song-poetry','','[]','浪靜風恬正好看，秋江澄澈碧天寬。',32,'全唐诗/poet.song.94000.json','["浪靜風恬正好看，秋江澄澈碧天寬。", "漁人競把絲輪擲，不見冰輪蘸水寒。"]'),
('0ad6cac2-0e59-4b5c-a970-5812e600dc28','頌古二首  其二','釋擇崇','宋','宋诗','song-poetry','','[]','金佛不度爐，窮源有處無。',60,'全唐诗/poet.song.94000.json','["金佛不度爐，窮源有處無。", "木佛不度火，渾崙齩不破。", "泥佛不度水，何處不是你。", "真佛屋裏坐，趙州言是禍。", "水牯會耕田，黄牛能拽磨。"]'),
('43863b12-389a-4915-9d9a-1990142834cd','讀莊子一受其成形不忘以待盡','釋擇崇','宋','宋诗','song-poetry','','[]','人生悉如此，誰悟此中玄。',48,'全唐诗/poet.song.94000.json','["人生悉如此，誰悟此中玄。", "白日無私照，青山任意眠。", "松風來不斷，泉石自相便。", "路出千峰上，雲歸竹徑邊。"]'),
('f1bd8ea2-388f-4656-a58a-ce4e5972fc64','司空山歌','釋擇崇','宋','宋诗','song-poetry','','[]','司空山，在雲外，時人到得方自在。',319,'全唐诗/poet.song.94000.json','["司空山，在雲外，時人到得方自在。", "我今隨力幸登臨，四顧巍巍無向背。", "絕遮攔，難比況，千山萬山齊恃仰。", "九夏炎炎雪正飛，三冬颯颯華初放。", "春不榮，秋不落，隱隱昭昭倚寥廓。", "直下人間咫尺間，欲上之人難措腳。", "人跡絕，野境寬，觸事無能懶散便。", "有時向日巖前坐，有時乘困日高眠。", "不學禪，不修道，只麽騰騰恣顛倒。", "百種無求箇野人，隨分隨緣能作造。", "不從他，不覓己，一句靈靈萬緣裏。", "自從識得祖師關，歷歷明明此爲始。", "無妙名，無忌諱，來者向渠只麽是。", "任你千般與萬般，何曾出得箇些子。", "分明說報知音，目炙風吹不用尋。", "須彌南畔相逢著，積翠臺邊旨更深。", "旨更深，誰會得，東村王老眼前黑。", "李四張三不信伊，問盡鄰家轉疑惑。", "轉疑惑，不較多，爲君吟作司空歌。", "宮商角徵任吹唱，角徵宮商爭奈何。"]'),
('f32c7533-ee7c-4deb-a22d-9e2822ccf218','偈二首  其一','釋慧初','宋','宋诗','song-poetry','','[]','一趯趯翻四大海，一拳拳倒須彌山。',32,'全唐诗/poet.song.94000.json','["一趯趯翻四大海，一拳拳倒須彌山。", "佛祖位中留不住，又吹漁笛汩羅灣。"]'),
('fbfb44a4-ae17-41aa-9a35-96a8b34f14c7','偈二首  其二','釋慧初','宋','宋诗','song-poetry','','[]','九月二十五，聚頭相共舉。',46,'全唐诗/poet.song.94000.json','["九月二十五，聚頭相共舉。", "瞎卻正法眼，拈卻雲門普。", "德山不會說禪，嬴得村歌社舞。", "阿呵呵，邏邏哩。"]'),
('7a23455c-2500-4283-9cad-12ef9ddc8512','偈','釋普信','宋','宋诗','song-poetry','','[]','殘雪既消盡，春風日漸多。',24,'全唐诗/poet.song.94000.json','["殘雪既消盡，春風日漸多。", "若將時節會，佛法又如何。"]'),
('c706360a-2930-4409-bf5c-f0903c16b7db','頌古九首  其一','釋普信','宋','宋诗','song-poetry','','[]','據坐凝眸語未形，一槌直下意何明。',32,'全唐诗/poet.song.94000.json','["據坐凝眸語未形，一槌直下意何明。", "倒行此令如相委，無限清風動地生。"]'),
('ce345689-b143-4c53-b248-c90df0dbc0fa','頌古九首  其二','釋普信','宋','宋诗','song-poetry','','[]','當時卞璧親持獻，未遇徒然更再三。',32,'全唐诗/poet.song.94000.json','["當時卞璧親持獻，未遇徒然更再三。", "折葦渡江江上水，滔滔今古色如藍。"]'),
('8fef6750-ecea-4773-b276-b8af4ccfd54c','頌古九首  其三','釋普信','宋','宋诗','song-poetry','','[]','相爭但見風旛動，不肯回頭識動心。',32,'全唐诗/poet.song.94000.json','["相爭但見風旛動，不肯回頭識動心。", "從此老盧露消息，松風江月盡知音。"]'),
('5d4e5aa1-a62b-4f55-a90f-3e727feb7b40','頌古九首  其四','釋普信','宋','宋诗','song-poetry','','[]','寥寥風月臥煙霞，百鳥從茲不獻花。',32,'全唐诗/poet.song.94000.json','["寥寥風月臥煙霞，百鳥從茲不獻花。", "人義盡從貧處斷，世情偏向有錢家。"]'),
('56b0c8a9-9dc3-4a05-94a7-cb2cf1be440f','頌古九首  其五','釋普信','宋','宋诗','song-poetry','','[]','道得無言杈下死，霍山猛跳入懷中。',32,'全唐诗/poet.song.94000.json','["道得無言杈下死，霍山猛跳入懷中。", "三千里外虛相賺，更有何人透此宗。"]'),
('bf843349-9fe1-441e-981c-e0b9b2b22b14','頌古九首  其六','釋普信','宋','宋诗','song-poetry','','[]','當時苦口曾不道，悟來靈骨方尋討。',32,'全唐诗/poet.song.94000.json','["當時苦口曾不道，悟來靈骨方尋討。", "練江寒月兩蕭蕭，浮雲散盡天如掃。"]'),
('2365df53-4c6c-410e-b01b-d3ae3a0257c7','頌古九首  其七','釋普信','宋','宋诗','song-poetry','','[]','收來輥去事方圓，獨許漁郎上鈎船。',32,'全唐诗/poet.song.94000.json','["收來輥去事方圓，獨許漁郎上鈎船。", "明月蘆花同一色，落霞孤鶩共遙天。"]'),
('ceb0afc2-79db-4626-84bb-a86308580598','頌古九首  其八','釋普信','宋','宋诗','song-poetry','','[]','大用縱橫掣電機，爍迦羅眼尚膠黐。',32,'全唐诗/poet.song.94000.json','["大用縱橫掣電機，爍迦羅眼尚膠黐。", "迷途夢裏爭唇吻，卻憶隨他去一回。"]'),
('7696ebff-801d-4724-844e-5b55159baf86','頌古九首  其九','釋普信','宋','宋诗','song-poetry','','[]','漁翁瀟灑任東西，蘆管橫吹韻不齊。',32,'全唐诗/poet.song.94000.json','["漁翁瀟灑任東西，蘆管橫吹韻不齊。", "夜靜月明魚不食，扁舟臥入武陵溪。"]'),
('0ebd5836-09a4-41f9-bffb-2ce69c5506eb','偈','釋興道','宋','宋诗','song-poetry','','[]','同雲欲雪未雪，愛日似暉不暉。',46,'全唐诗/poet.song.94000.json','["同雲欲雪未雪，愛日似暉不暉。", "寒雀啾啾鬧籬落，朔風冽冽舞簾帷。", "要會韶陽親切句，今朝覿面爲提撕。"]'),
('b747267f-fd95-4c66-8246-473602887fea','頌','釋果慜','宋','宋诗','song-poetry','','[]','南泉提起下刀誅，六臂修羅救得無。',32,'全唐诗/poet.song.94000.json','["南泉提起下刀誅，六臂修羅救得無。", "設使兩堂俱道得，也應流血滿街衢。"]'),
('34560b08-b1d1-4da9-925e-61c5e322f58d','偈','釋圓','宋','宋诗','song-poetry','','[]','新縫紙被烘來暖，一覺安眠到五更。',32,'全唐诗/poet.song.94000.json','["新縫紙被烘來暖，一覺安眠到五更。", "聞得上方鐘鼓動，又添一日在浮生。"]'),
('6dccd6f1-5e39-47b9-bed8-579f989f8d48','偈','釋守慧','宋','宋诗','song-poetry','','[]','但知今日復明日，不覺前秋與後秋。',32,'全唐诗/poet.song.94000.json','["但知今日復明日，不覺前秋與後秋。", "平步坦然歸故里，卻乘好月過滄洲。"]'),
('4bb2754e-af11-428c-b188-d7ed306e4be2','偈二首  其一','釋禮','宋','宋诗','song-poetry','','[]','奪不奪，縱有餘。',36,'全唐诗/poet.song.94000.json','["奪不奪，縱有餘。", "臨岐不分袂，富貴卻蕭疏。", "句裏不曾舒慷慨，禹門先自透金魚。"]'),
('0cb3fd26-1e9d-4f2c-9f31-8e16597d51f9','偈二首  其二','釋禮','宋','宋诗','song-poetry','','[]','不是翻濤手，徒誇跨海鯨。',24,'全唐诗/poet.song.94000.json','["不是翻濤手，徒誇跨海鯨。", "由基方撚鏃，枝上衆猿驚。"]'),
('425e411e-a608-4652-af93-c4cc219db24b','偈二首  其一','釋端裕','宋','宋诗','song-poetry','','[]','德山入門便棒，多向皮袋裏埋蹤。',51,'全唐诗/poet.song.94000.json','["德山入門便棒，多向皮袋裏埋蹤。", "臨濟入門便喝，總在聲塵中出沒。", "若是英靈衲子，直須足下風生，超越古今途轍。"]'),
('d8c82b14-acea-4b52-9502-f8b2a1b22121','偈二首  其二','釋端裕','宋','宋诗','song-poetry','','[]','易填巨壑，難滿漏巵。',40,'全唐诗/poet.song.94000.json','["易填巨壑，難滿漏巵。", "若有操持，了無難易。", "拈卻大地，寬綽有餘。", "放出纖毫，礙塞無中。"]'),
('141977ef-c53b-44cb-a8f1-d55afaac5a0b','頌古十首  其一','釋端裕','宋','宋诗','song-poetry','','[]','修行不落與不昧，盡作野狐涎唾腥。',32,'全唐诗/poet.song.94000.json','["修行不落與不昧，盡作野狐涎唾腥。", "拾取娘生窮相口，拶開雲路吸雷霆。"]'),
('ce318001-7d05-4aa7-8907-e845596c1585','頌古十首  其二','釋端裕','宋','宋诗','song-poetry','','[]','玉簫吹作鳳鸞吟，惹動遊人離別心。',32,'全唐诗/poet.song.94000.json','["玉簫吹作鳳鸞吟，惹動遊人離別心。", "一陳東風捲寥廓，四方八面少知音。"]'),
('9654d13a-411b-493e-b1a8-80dc515ac794','頌古十首  其三','釋端裕','宋','宋诗','song-poetry','','[]','高堂公子醉雙陸，亂撒明珠發異光。',32,'全唐诗/poet.song.94000.json','["高堂公子醉雙陸，亂撒明珠發異光。", "一擲輸嬴誰辨得，滿盤骰子不成雙。"]'),
('59541d9f-f159-4a74-bcde-0c84ea329d9b','頌古十首  其四','釋端裕','宋','宋诗','song-poetry','','[]','劫火洞然俱敗壞，青天白日愈光輝。',32,'全唐诗/poet.song.94000.json','["劫火洞然俱敗壞，青天白日愈光輝。", "王孫醉寢迷春夢，不覺鶯啼柳絮飛。"]'),
('775ec83a-90e9-4551-bf9f-b65439dfadf5','頌古十首  其五','釋端裕','宋','宋诗','song-poetry','','[]','百千諸佛眉彎曲，無訂無修眼搭癡。',32,'全唐诗/poet.song.94000.json','["百千諸佛眉彎曲，無訂無修眼搭癡。", "踏著未消連底凍，一時認作碧琉璃。"]'),
('ce625a19-7ac0-4cc7-b722-b79102965503','頌古十首  其六','釋端裕','宋','宋诗','song-poetry','','[]','波斯捧出海南香，白眼崑崙與論量。',32,'全唐诗/poet.song.94000.json','["波斯捧出海南香，白眼崑崙與論量。", "賈客不諳彈舌語，只看兩箇鼻頭長。"]'),
('3fd05933-e207-4322-976e-18520ace4303','頌古十首  其七','釋端裕','宋','宋诗','song-poetry','','[]','芭蕉拄杖與奪，直要當風眼活。',28,'全唐诗/poet.song.94000.json','["芭蕉拄杖與奪，直要當風眼活。", "剎那纔昧隔生，鼻孔遭他牽撮。"]'),
('bcf23825-74ab-470f-a1ad-092ff5832c89','頌古十首  其八','釋端裕','宋','宋诗','song-poetry','','[]','清凈法身花藥欄，眉毛刺倒須彌山。',32,'全唐诗/poet.song.94000.json','["清凈法身花藥欄，眉毛刺倒須彌山。", "誰將玉笛傳凄怨，吹過蘆藂明月彎。"]'),
('75abbc8c-f50e-4649-93c5-e86a7dc0c67d','頌古十首  其九','釋端裕','宋','宋诗','song-poetry','','[]','久雨不晴，雲門道劄。',48,'全唐诗/poet.song.94000.json','["久雨不晴，雲門道劄。", "陽烏奮羽翰，蛟龍縮鱗鬛。", "爲是時節，爲是佛法。", "一箭兩垛謾猜量，眼裏瞳人眉搭颯。"]'),
('e04cc326-0f99-4eeb-8d79-e7fcb2029565','偈十三首  其一','釋法泰','宋','宋诗','song-poetry','','[]','客從遠方來，遺我一張琴。',48,'全唐诗/poet.song.94000.json','["客從遠方來，遺我一張琴。", "中含太古意，舉世無知音。", "子期徒側耳，師曠謾追尋。", "今朝呈似君，試請彈一曲。"]'),
('e2023bbb-acfd-4476-b628-084ba0ca13a3','偈十三首  其二','釋法泰','宋','宋诗','song-poetry','','[]','達得人空法空，未稱祖師家風。',42,'全唐诗/poet.song.94000.json','["達得人空法空，未稱祖師家風。", "體得全用全照，亦非衲僧要妙。", "直須打破牢關，識取向上一竅。"]'),
('f38a24c2-332f-4657-affa-7e04f4521d90','偈十三首  其三','釋法泰','宋','宋诗','song-poetry','','[]','開口錯，合口喪，明眼衲僧無伎倆。',32,'全唐诗/poet.song.94000.json','["開口錯，合口喪，明眼衲僧無伎倆。", "春風吹落桃李花，淡煙疏雨籠青嶂。"]'),
('fcde488f-13cb-4de1-855d-bf1647894d33','偈十三首  其四','釋法泰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一葉落，天下秋，看看空際火雲收。',32,'全唐诗/poet.song.94000.json','["一葉落，天下秋，看看空際火雲收。", "萬里長江凈如練，謝家人不在漁舟。"]'),
('06c513a1-a1da-473b-8c05-cc6623d6532a','偈十三首  其五','釋法泰','宋','宋诗','song-poetry','','[]','一雁度長空，影落寒江水。',48,'全唐诗/poet.song.94000.json','["一雁度長空，影落寒江水。", "水無沉影心，雁無遺蹤意。", "蹤影兩相忘，憑何爲的旨。", "籬邊金菊黄，江上芙蓉翠。"]'),
('48e4913c-fe6c-4613-b958-409efa062f3a','偈十三首  其六','釋法泰','宋','宋诗','song-poetry','','[]','三角牯牛獨腳舞，兩輪石磨遶空飛。',32,'全唐诗/poet.song.94000.json','["三角牯牛獨腳舞，兩輪石磨遶空飛。", "新生孩子擎鐵棒，直上須彌打一槌。"]'),
('100a21f3-7e5a-4ff8-9b2f-ecd29ac5dbf8','偈十三首  其七','釋法泰','宋','宋诗','song-poetry','','[]','開口有時非，開口有時是。',56,'全唐诗/poet.song.94000.json','["開口有時非，開口有時是。", "粗言及細語，皆歸第一義。", "釋迦老子碗鳴聲，達磨西來屎臭氣。", "惟有山前水牯牛，身放毫光照天地。"]'),
('bf2f9a32-3bd3-4b65-a4b7-7d8299f88b6a','偈十三首  其八','釋法泰','宋','宋诗','song-poetry','','[]','推真真無有相，窮妄妄無有形。',54,'全唐诗/poet.song.94000.json','["推真真無有相，窮妄妄無有形。", "真妄兩無所有，廓然露出眼睛。", "眼睛既露，見個什麽。", "曉日爍開巖畔雪，朔風吹綻臘梅花。"]'),
('4038e1bb-5d17-4e6e-a135-d90812971ccc','偈十三首  其九','釋法泰','宋','宋诗','song-poetry','','[]','咄咄，何似生，穿雲俊鶻摩青天。',63,'全唐诗/poet.song.94000.json','["咄咄，何似生，穿雲俊鶻摩青天。", "擡眸一顧十萬里，林間鈍羽空忙然。", "求解會，著言詮，還同日午打三更。", "爭如一句聲前薦，獨向毗盧頂上行。"]'),
('e8acbd7b-2af4-4254-9280-77eefc1d05e5','偈十三首  其一○','釋法泰','宋','宋诗','song-poetry','','[]','久雨不晴，有理難伸。',44,'全唐诗/poet.song.94000.json','["久雨不晴，有理難伸。", "雲霧長埋大野，簷聲不斷前旬。", "阿喇喇，聞不聞。", "補陀巖上客，應笑未歸人。"]'),
('e49fee34-a5e8-4d9e-a999-28237cd91938','偈十三首  其一一','釋法泰','宋','宋诗','song-poetry','','[]','幽鳥語如篁，柳垂金線長。',24,'全唐诗/poet.song.94000.json','["幽鳥語如篁，柳垂金線長。", "少林傳底事，對面不囊藏。"]'),
('8d8820c1-2712-48c1-9dc7-4da1bebd40b4','偈十三首  其一二','釋法泰','宋','宋诗','song-poetry','','[]','有佛處不增，無佛處不減。',44,'全唐诗/poet.song.94000.json','["有佛處不增，無佛處不減。", "人人一段光明，歷劫何曾欠少。", "咄，釋迦謾自化西乾，達磨無端來此土。"]'),
('17186f9e-2a00-4a58-9b5c-99691e024ff5','偈十三首  其一三','釋法泰','宋','宋诗','song-poetry','','[]','勿思惟，休造作，展手開拳咄咄咄。',48,'全唐诗/poet.song.94000.json','["勿思惟，休造作，展手開拳咄咄咄。", "隨意說，任天真，鎮州蘿蔔重三所。", "堪笑老胡不知有，九年面壁太勞神。"]'),
('b3f346e9-ad8e-4844-b90d-051f4829b9c3','偈七首  其一','釋法泰','宋','宋诗','song-poetry','','[]','今朝正月已半，是處燈火繚亂。',44,'全唐诗/poet.song.94000.json','["今朝正月已半，是處燈火繚亂。", "滿城羅騎駢闐，交互往來遊翫。", "文殊走入鬧籃中，普賢端坐高樓看。"]'),
('b3db7065-f5d8-4e40-8b4e-3c0b2db364e6','偈七首  其二','釋法泰','宋','宋诗','song-poetry','','[]','渺渺邈邈，十方該括。',82,'全唐诗/poet.song.94000.json','["渺渺邈邈，十方該括。", "坦坦蕩蕩，絕形絕相。", "目欲視而睛枯，口欲談而詞喪。", "文殊普賢，全無伎倆。", "臨濟德山，不妨提唱，龜吞陝府鐵牛，蛇咬嘉州大像。", "嚇得東海鯉魚，直至如今肚脹。"]'),
('5d7a979e-832c-4cc2-b02b-6a29d308958f','偈七首  其三','釋法泰','宋','宋诗','song-poetry','','[]','火雲燒田苗，泉源絕流注。',24,'全唐诗/poet.song.94000.json','["火雲燒田苗，泉源絕流注。", "婆竭大龍王，不知在何處。"]'),
('c0791fda-894b-4d36-9d08-f40e5b0a1196','偈七首  其四','釋法泰','宋','宋诗','song-poetry','','[]','南山起雲，北山下雨。',26,'全唐诗/poet.song.94000.json','["南山起雲，北山下雨。", "老僧更爲震雷聲，助發威光令遠布。"]'),
('04ef7679-fac0-47e6-b749-59c56851f111','偈七首  其五','釋法泰','宋','宋诗','song-poetry','','[]','德山棒下金沙異，臨濟喝中賓主分。',32,'全唐诗/poet.song.94000.json','["德山棒下金沙異，臨濟喝中賓主分。", "到此若無真正眼，可憐辜負本來人。"]'),
('d337ca44-d119-4aa2-ba82-96d30e7d09dc','偈七首  其六','釋法泰','宋','宋诗','song-poetry','','[]','空手把鋤頭，步行騎水牛。',24,'全唐诗/poet.song.94000.json','["空手把鋤頭，步行騎水牛。", "人從橋上過，橋流水不流。"]'),
('4cd13eb8-b669-4b55-b515-7044e7d08329','偈七首  其七','釋法泰','宋','宋诗','song-poetry','','[]','憶昔遊方日，獲得二種物。',120,'全唐诗/poet.song.94000.json','["憶昔遊方日，獲得二種物。", "一是金剛鎚，一是千聖骨。", "持行宇宙中，氣岸高突兀。", "如是三十年，用之爲準則。", "而今年老矣，一物知何物。", "擲下金剛鎚，擊碎千聖骨。", "拋向四衢道，不能更惜得。", "任意過浮生，指南將作北。", "呼龜以爲鼈，喚豆以爲粟。", "從他明眼人，笑我無繩墨。"]'),
('4b4a4780-70d5-4110-aadc-94e04850b5a7','頌古十二首  其一','釋法泰','宋','宋诗','song-poetry','','[]','朝三暮四一何少，暮四朝三何太多。',46,'全唐诗/poet.song.94000.json','["朝三暮四一何少，暮四朝三何太多。", "多少未能知數量，有無從此見殽訛。", "不殽訛，唵囌嚧，㗭唎薩婆訶。"]'),
('c3cfe9c1-b10f-4d64-b75f-0907ab6b2545','頌古十二首  其二','釋法泰','宋','宋诗','song-poetry','','[]','三腳驢子弄蹄行，步步蓮華襯足生。',32,'全唐诗/poet.song.94000.json','["三腳驢子弄蹄行，步步蓮華襯足生。", "堪笑草中尋覓者，不知芳樹囀新鶯。"]'),
('b1441f83-0b3c-4b20-b88c-ebdcf31b0534','頌古十二首  其三','釋法泰','宋','宋诗','song-poetry','','[]','無量秤子兩頭平，拈起應須見得明。',32,'全唐诗/poet.song.94000.json','["無量秤子兩頭平，拈起應須見得明。", "若向箇中爭分兩，知渠錯認定盤星。"]'),
('8051132b-9ccb-4dfd-91f4-3ad08ff5a682','頌古十二首  其四','釋法泰','宋','宋诗','song-poetry','','[]','十分風采露堂堂，玉蘂瓊華未比量。',32,'全唐诗/poet.song.94000.json','["十分風采露堂堂，玉蘂瓊華未比量。", "剛被傍人論好醜，因茲難嫁與潘郎。"]'),
('b1a0591a-f941-4baa-af08-e8fe61b74c74','頌古十二首  其五','釋法泰','宋','宋诗','song-poetry','','[]','子卿不下單于拜，始末常遵漢帝儀。',32,'全唐诗/poet.song.94000.json','["子卿不下單于拜，始末常遵漢帝儀。", "雪後乃知松柏操，事難方見丈夫兒。"]'),
('6d2a953d-fef7-446c-9686-f59cd941f00e','頌古十二首  其六','釋法泰','宋','宋诗','song-poetry','','[]','得人一牛，還人一馬。',20,'全唐诗/poet.song.94000.json','["得人一牛，還人一馬。", "有往有來，可知禮也。"]'),
('556be5ef-6c7c-41af-882a-3dfa4ab7c1e2','頌古十二首  其七','釋法泰','宋','宋诗','song-poetry','','[]','應用從來不覆藏，當機何得昧真常。',32,'全唐诗/poet.song.94000.json','["應用從來不覆藏，當機何得昧真常。", "只知報道王來也，不覺渾身在帝鄉。"]'),
('bbb52c8e-2e24-42f9-8d1f-9ed77460d3c1','頌古十二首  其八','釋法泰','宋','宋诗','song-poetry','','[]','不落因果何曾墮，不昧因果何曾脫。',52,'全唐诗/poet.song.94000.json','["不落因果何曾墮，不昧因果何曾脫。", "當堂鏡破兩頭忘，掃影滅蹤無摸索。", "無摸索，何倚托。", "秋風吹梧桐，樹葉鳴嚗嚗。"]'),
('52db21b1-9a35-48fb-8326-e8ba54a76cd4','頌古十二首  其九','釋法泰','宋','宋诗','song-poetry','','[]','商嶺東西路不分，兩間茅屋一溪雲。',32,'全唐诗/poet.song.94000.json','["商嶺東西路不分，兩間茅屋一溪雲。", "師年耳聵知師意，人是人非不欲聞。"]'),
('1c609247-c67c-4926-911f-cf64c4abb241','頌古十二首  其一○','釋法泰','宋','宋诗','song-poetry','','[]','樹倒藤枯意若何，溈山開口笑呵呵。',32,'全唐诗/poet.song.94000.json','["樹倒藤枯意若何，溈山開口笑呵呵。", "可憐三尺龍泉劍，喚作陶家壁上梭。"]'),
('ab34710e-0bda-4ebb-ae8a-20db7017271e','頌古十二首  其一一','釋法泰','宋','宋诗','song-poetry','','[]','有無不問語先墮，明鏡當臺雙照破。',32,'全唐诗/poet.song.94000.json','["有無不問語先墮，明鏡當臺雙照破。", "迷雲散盡曉天空，杲日團團紅似火。"]'),
('ef6a5201-54c2-45ee-aa89-b73b4059b777','頌古十二首  其一二','釋法泰','宋','宋诗','song-poetry','','[]','多子塔前衣付後，更傳何物示於人。',32,'全唐诗/poet.song.94000.json','["多子塔前衣付後，更傳何物示於人。", "雙珠迸出剎竿倒，直得寒光徹四鄰。"]'),
('219f8b31-f7c5-49e4-aa64-d1bf96d6b252','四時般若  其一','釋法泰','宋','宋诗','song-poetry','','[]','日暖風和天地春，野華芳草一翻新。',32,'全唐诗/poet.song.94000.json','["日暖風和天地春，野華芳草一翻新。", "靈山佳致依然在，誰是當年微笑人。"]'),
('61335377-aab6-4481-9055-b77968a8da49','四時般若  其二','釋法泰','宋','宋诗','song-poetry','','[]','萬木扶疏夏景長，園林梅杏嚼紅香。',32,'全唐诗/poet.song.94000.json','["萬木扶疏夏景長，園林梅杏嚼紅香。", "山前麥熟還知否，一一當機爲舉揚。"]'),
('ff227906-d466-404a-b649-4e71744a1bb1','四時般若  其三','釋法泰','宋','宋诗','song-poetry','','[]','飄飄黄葉墜幽庭，萬里無雲宇宙清。',32,'全唐诗/poet.song.94000.json','["飄飄黄葉墜幽庭，萬里無雲宇宙清。", "颯颯涼飈生戶外，韶陽三句轉分明。"]'),
('0bec01ea-45fc-4e7f-b2a7-2aa3ab5e7760','四時般若  其四','釋法泰','宋','宋诗','song-poetry','','[]','林木蕭條復本根，嚴霜凍雪鏁松門。',32,'全唐诗/poet.song.94000.json','["林木蕭條復本根，嚴霜凍雪鏁松門。", "地爐煨火通身暖，寒暑到來休更論。"]'),
('141133fc-b2f8-4f25-be4b-e68488c8bf14','贊達磨','釋法泰','宋','宋诗','song-poetry','','[]','泛舶來梁自普通，一鎚擊碎有爲功。',32,'全唐诗/poet.song.94000.json','["泛舶來梁自普通，一鎚擊碎有爲功。", "誰云面壁無言說，爭奈當門齒露風。"]'),
('1649dc51-320c-46b0-a0ca-222629549103','頌古四十四首  其一','釋法泰','宋','宋诗','song-poetry','','[]','生無所生，死無所死。',40,'全唐诗/poet.song.94000.json','["生無所生，死無所死。", "風動塵飛，波澄浪止。", "和合離散，隨處發現。", "滿月彎弓，雙雕一箭。"]'),
('18880f17-2836-4fae-a7a8-6974357c0064','頌古四十四首  其二','釋法泰','宋','宋诗','song-poetry','','[]','重城曉入冒輕煙，鬧市相逢豈偶然。',56,'全唐诗/poet.song.94000.json','["重城曉入冒輕煙，鬧市相逢豈偶然。", "一句等閑相借問，平田忽爾浪滔天。", "月上女，實堪憐，雲髻高梳何處去，借婆裙子拜婆年。"]'),
('a0e5b11d-b11d-4873-add4-5c74ae468c59','頌古四十四首  其三','釋法泰','宋','宋诗','song-poetry','','[]','不是風兮不是旛，一重山後一重山。',32,'全唐诗/poet.song.94000.json','["不是風兮不是旛，一重山後一重山。", "青春雨過無餘因，獨倚危樓望剎竿。"]'),
('754665f0-7fd3-4be5-a1fe-dddf1782a69d','頌古四十四首  其四','釋法泰','宋','宋诗','song-poetry','','[]','堂堂妙相絕錙銖，善惡都忘見也無。',32,'全唐诗/poet.song.94000.json','["堂堂妙相絕錙銖，善惡都忘見也無。", "萬里雲收天界凈，海心無浪月輪孤。"]'),
('c2075cd8-b4d6-403e-8561-5e552db9399f','頌古四十四首  其五','釋法泰','宋','宋诗','song-poetry','','[]','張公養得三箇兒，長大不知誰立志。',32,'全唐诗/poet.song.94000.json','["張公養得三箇兒，長大不知誰立志。", "呼來月下同蹤由，眼睛箇箇皆相似。"]'),
('3ba9208f-d3d8-4533-a07b-32cdd96877a1','頌古四十四首  其六','釋法泰','宋','宋诗','song-poetry','','[]','朱沙鏡裏開顔笑，白玉盤中展腳眠。',32,'全唐诗/poet.song.94000.json','["朱沙鏡裏開顔笑，白玉盤中展腳眠。", "大抵人生難得共，得團圓處且團圓。"]'),
('07d39759-9bc3-4534-b946-7c0529f0f455','頌古四十四首  其七','釋法泰','宋','宋诗','song-poetry','','[]','三界無法，何處求心。',36,'全唐诗/poet.song.94000.json','["三界無法，何處求心。", "山容雨過，松韻風吟。", "橫眠倒臥無餘事，一任莓苔滿地侵。"]'),
('f28f247c-8906-49ac-8ab8-1815a7307bf2','頌古四十四首  其八','釋法泰','宋','宋诗','song-poetry','','[]','百丈開田說大義，理事圓融無不備。',64,'全唐诗/poet.song.94000.json','["百丈開田說大義，理事圓融無不備。", "梵音清徹十方聞，草樹鋤鍬皆聳起。", "末後雙拳再展開，拖泥带水爲癡獃。", "船流到岸五千里，刻舟求劍徒悠哉。"]'),
('f2b8c44b-3a42-4619-87a9-28866a04746e','頌古四十四首  其九','釋法泰','宋','宋诗','song-poetry','','[]','相見不虛圖，分明付與渠。',52,'全唐诗/poet.song.94000.json','["相見不虛圖，分明付與渠。", "汝醉我扶起，我倒汝相扶。", "交互爲賓主，相將入帝都。", "高歌大笑九衢裏，天上人間我唯爾。"]'),
('a267b0cb-0441-4135-98af-8eb76f621eec','頌古四十四首  其一○','釋法泰','宋','宋诗','song-poetry','','[]','膠投漆，水和乳，一卷一舒，全賓全主。',46,'全唐诗/poet.song.94000.json','["膠投漆，水和乳，一卷一舒，全賓全主。", "誰言不落青黄，就中要人道取。", "誰道取，分付鑊湯，熟蒸爛煮。"]'),
('df29f8aa-b576-4429-8d5b-6da379b4014e','頌古四十四首  其一一','釋法泰','宋','宋诗','song-poetry','','[]','行婆能擊塗毒鼓，遠近聞之皆膽怖。',44,'全唐诗/poet.song.94000.json','["行婆能擊塗毒鼓，遠近聞之皆膽怖。", "唯有南泉與趙州，同死同生殊不顧。", "阿呵呵，伎死禪和不奈何。"]'),
('c22e2407-52b7-4447-8388-9902b0bc2de3','頌古四十四首  其一二','釋法泰','宋','宋诗','song-poetry','','[]','試問田中有幾人，插鍬叉手意分明。',32,'全唐诗/poet.song.94000.json','["試問田中有幾人，插鍬叉手意分明。", "可憐不逐南山去，撒手歸家罷問程。"]'),
('db19bf71-813c-481f-a531-a2c2a5d7e8e3','頌古四十四首  其一三','釋法泰','宋','宋诗','song-poetry','','[]','堂堂妙相真難比，歷歷梵音猶更奇。',44,'全唐诗/poet.song.94000.json','["堂堂妙相真難比，歷歷梵音猶更奇。", "可憐逐句尋言者，嗟過長沙覿面機。", "知不知，黄鶴樓崔顥題詩。"]'),
('8f2f0bf9-0aed-409b-9e8e-7efadb52b73e','頌古四十四首  其一四','釋法泰','宋','宋诗','song-poetry','','[]','宗師垂手貴天真，肯事雕蟲篆刻新。',32,'全唐诗/poet.song.94000.json','["宗師垂手貴天真，肯事雕蟲篆刻新。", "只向平田淺草處，等閑推出玉麒麟。"]'),
('cbf84e59-b0d0-433c-a126-4db54947024b','頌古四十四首  其一五','釋法泰','宋','宋诗','song-poetry','','[]','趙州三度喫茶，禾山打鼓難比。',40,'全唐诗/poet.song.94000.json','["趙州三度喫茶，禾山打鼓難比。", "休於句下尋求，識取口中滋味。", "若識得，觀音院裏有彌勒。"]'),
('d25d4108-0346-4382-91cf-d2b81d79059e','頌古四十四首  其一六','釋法泰','宋','宋诗','song-poetry','','[]','等閑施設豈徒然，平地波瀾欲浸天。',32,'全唐诗/poet.song.94000.json','["等閑施設豈徒然，平地波瀾欲浸天。", "更向胡梯敲數下，免教失腳墮黄泉。"]'),
('f8b3663c-2af0-48f4-8011-306044b8ac2d','頌古四十四首  其一七','釋法泰','宋','宋诗','song-poetry','','[]','病餐毒藥訪良醫，醫使元餐藥治之。',32,'全唐诗/poet.song.94000.json','["病餐毒藥訪良醫，醫使元餐藥治之。", "病去藥回滋味別，舌頭具眼者方知。"]'),
('19b73500-8282-4b41-bf7f-5e9470edc504','頌古四十四首  其一八','釋法泰','宋','宋诗','song-poetry','','[]','打破當年山鬼窟，豁開正眼耀乾坤。',32,'全唐诗/poet.song.94000.json','["打破當年山鬼窟，豁開正眼耀乾坤。", "三拳肋下無多子，一喝雷轟迸海門。"]'),
('d0d945b8-9d22-4542-92b5-f187c0d2ce99','頌古四十四首  其一九','釋法泰','宋','宋诗','song-poetry','','[]','溪邊嫩柳條條綠，陌上桃花樹樹紅。',32,'全唐诗/poet.song.94000.json','["溪邊嫩柳條條綠，陌上桃花樹樹紅。", "勿謂東君無管带，更加暖日與和風。"]'),
('2755f03d-9187-4859-8643-c48ec434e623','頌古四十四首  其二○','釋法泰','宋','宋诗','song-poetry','','[]','臭煙蓬㶿中，迸出鐵蒺藜。',24,'全唐诗/poet.song.94000.json','["臭煙蓬㶿中，迸出鐵蒺藜。", "當如如未委，喪卻目前機。"]'),
('74dc4947-8a07-4175-bd7f-5f331f531839','頌古四十四首  其二一','釋法泰','宋','宋诗','song-poetry','','[]','皮裹骨兮骨裹皮，分明道了復何疑。',32,'全唐诗/poet.song.94000.json','["皮裹骨兮骨裹皮，分明道了復何疑。", "拈起草鞋如未委，不如別處且烏龜。"]'),
('516ec34f-e7ea-450f-9113-f02fadc3c555','頌古四十四首  其二二','釋法泰','宋','宋诗','song-poetry','','[]','無寒暑處爲君通，枯木生死花又一重。',33,'全唐诗/poet.song.94000.json','["無寒暑處爲君通，枯木生死花又一重。", "堪笑刻舟求劍者，至今猶在冷灰中。"]'),
('d8c3189d-839f-461a-95d1-4a00b90f7902','頌古四十四首  其二三','釋法泰','宋','宋诗','song-poetry','','[]','白衣拜相喜難加，暫時流落向天涯。',32,'全唐诗/poet.song.94000.json','["白衣拜相喜難加，暫時流落向天涯。", "移身換步人難用，夜來歸宿五侯家。"]'),
('1c1b402a-ac22-435c-ad86-5645db73121b','頌古四十四首  其二四','釋法泰','宋','宋诗','song-poetry','','[]','無鬚鎖子兩頭搖，無瑕璧玉三回獻。',32,'全唐诗/poet.song.94000.json','["無鬚鎖子兩頭搖，無瑕璧玉三回獻。", "反遭刖足太無端，誰料正言還似反。"]'),
('e06169ea-58cf-449c-8f51-e6de9313e013','頌古四十四首  其二五','釋法泰','宋','宋诗','song-poetry','','[]','吞卻易，吐還難，須彌頂上無風寒。',32,'全唐诗/poet.song.94000.json','["吞卻易，吐還難，須彌頂上無風寒。", "昨夜三更白如晝，不知誰共倚闌觀。"]'),
('e0dc7806-cec0-405b-b5a8-1fd09b668b33','頌古四十四首  其二六','釋法泰','宋','宋诗','song-poetry','','[]','雪峰古澗泉深，趙州石橋水苦。',68,'全唐诗/poet.song.94000.json','["雪峰古澗泉深，趙州石橋水苦。", "若知異水同源，飲者不妨疑悟。", "不從鼻孔入，白浪高三級。", "從此不答話，豈免酬高價。", "金剛圈子栗棘蓬，解透橫行四天下。"]'),
('c2f00fb4-72ba-41d4-8bb8-5ee9e9ed4937','頌古四十四首  其二七','釋法泰','宋','宋诗','song-poetry','','[]','嵯峨萬仞是曹山，氣岸雄雄坐祖關。',32,'全唐诗/poet.song.94000.json','["嵯峨萬仞是曹山，氣岸雄雄坐祖關。", "橫按鏌鋣全正令，太平寰宇斬癡頑。"]'),
('9268d73e-ee4e-4b83-aaf7-bbf6c00c559b','頌古四十四首  其二八','釋法泰','宋','宋诗','song-poetry','','[]','窣堵波成賞匠人，工錢一二與三文。',32,'全唐诗/poet.song.94000.json','["窣堵波成賞匠人，工錢一二與三文。", "可憐眼裏無筋者，當面定將數目分。"]'),
('b0fa8291-1953-45cf-a23b-3d8fa6580732','頌古四十四首  其二九','釋法泰','宋','宋诗','song-poetry','','[]','高樓美女一雙雙，各向瓊窗坐玉牀。',33,'全唐诗/poet.song.94000.json','["高樓美女一雙雙，各向瓊窗坐玉牀。", "繡綉出鴛鴦呈似了，金針深插錦香囊。"]'),
('2e73b6af-d2c9-4851-9c4e-f4a2a617affb','頌古四十四首  其三○','釋法泰','宋','宋诗','song-poetry','','[]','垂鈎四海釣獰龍，格外玄談知己從。',32,'全唐诗/poet.song.94000.json','["垂鈎四海釣獰龍，格外玄談知己從。", "相見披衫带席帽，不妨把手上高峰。"]'),
('616f4c4d-dd83-49d7-86f4-54b9be3eba9e','頌古四十四首  其三一','釋法泰','宋','宋诗','song-poetry','','[]','驀刃開時飛銕騎，電光閃處擲金槌。',32,'全唐诗/poet.song.94000.json','["驀刃開時飛銕騎，電光閃處擲金槌。", "一城瞎卻渾閑事，直至而今成是非。"]'),
('f796f00a-174f-4a65-b0be-339fad3c2d1d','頌古四十四首  其三二','釋法泰','宋','宋诗','song-poetry','','[]','一拳拳倒黄鶴樓，一趯趯翻鸚鵡洲。',32,'全唐诗/poet.song.94000.json','["一拳拳倒黄鶴樓，一趯趯翻鸚鵡洲。", "幸有傍人爲著力，自家端坐看揚州。"]'),
('cb7530ac-aa6b-4d64-83de-3c0f45502cd1','頌古四十四首  其三三','釋法泰','宋','宋诗','song-poetry','','[]','格外談，驚人句，懵懂禪和徒指注。',60,'全唐诗/poet.song.94000.json','["格外談，驚人句，懵懂禪和徒指注。", "灼然好箇佛無光，言下迷宗空自忙。", "賴有知音招慶在，譊訛一夏爲雌黄。", "雌黄出，暗寫愁腸寄知識。"]'),
('60a234a6-fac8-4a0d-8226-160225d4d73c','頌古四十四首  其三四','釋法泰','宋','宋诗','song-poetry','','[]','白紙三張通信去，展開千里卻同風。',32,'全唐诗/poet.song.94000.json','["白紙三張通信去，展開千里卻同風。", "陽春轉入胡笳曲，不是風吹別調中。"]'),
('5e35a06f-e5c5-4730-a561-83b7596048b2','頌古四十四首  其三五','釋法泰','宋','宋诗','song-poetry','','[]','河目海口，釘觜鏡舌。',34,'全唐诗/poet.song.94000.json','["河目海口，釘觜鏡舌。", "雞宿鳳巢，素非其鴨。", "直饒啐啄同時，未免當頭一劄。"]'),
('e6fed4d6-25f0-4b56-a328-c00e09c17112','頌古四十四首  其三六','釋法泰','宋','宋诗','song-poetry','','[]','對一說，五教三乘盡該攝。',28,'全唐诗/poet.song.94000.json','["對一說，五教三乘盡該攝。", "龍宮海藏任縱橫，水底泥牛吞卻月。"]'),
('b9d4056f-4666-4c6b-aa81-5337a463762f','頌古四十四首  其三七','釋法泰','宋','宋诗','song-poetry','','[]','涼風落木楚山秋，滿樹寒蟬噪不休。',32,'全唐诗/poet.song.94000.json','["涼風落木楚山秋，滿樹寒蟬噪不休。", "紅蓼白蘋開兩岸，不知誰在釣魚舟。"]'),
('f25b1c5f-7c4a-48ea-9cd7-7979a7cdd881','頌古四十四首  其三八','釋法泰','宋','宋诗','song-poetry','','[]','明鏡當臺湛如水，無端特地起塵埃。',32,'全唐诗/poet.song.94000.json','["明鏡當臺湛如水，無端特地起塵埃。", "積成山嶽面前立，千手大悲擘不開。"]'),
('c0526772-7666-4144-815e-496744af6f86','頌古四十四首  其三九','釋法泰','宋','宋诗','song-poetry','','[]','汝水向東流，楚水從南至。',40,'全唐诗/poet.song.94000.json','["汝水向東流，楚水從南至。", "皆歸大海中，鹹淡同一味。", "頂門具眼底衲僧，試向其中辨淺深。"]'),
('16b4b462-4070-4e69-bc08-43d78fe4d9f0','頌古四十四首  其四○','釋法泰','宋','宋诗','song-poetry','','[]','三人證龜成鱉，井底泥牛氣噎。',36,'全唐诗/poet.song.94000.json','["三人證龜成鱉，井底泥牛氣噎。", "直饒辯瀉懸河，有理亦難分雪。", "耿耿孤光常皎潔。"]'),
('71cb8217-5e3b-4b9a-b13c-722edc948253','頌古四十四首  其四一','釋法泰','宋','宋诗','song-poetry','','[]','風前露出無瑕璧，室內擎將如意珠。',32,'全唐诗/poet.song.94000.json','["風前露出無瑕璧，室內擎將如意珠。", "兩度獻渠渠不識，可憐流落在江湖。"]'),
('be5bcee8-f3a9-43b9-b093-29b6c4eb1044','頌古四十四首  其四二','釋法泰','宋','宋诗','song-poetry','','[]','銀椀裏盛雪，冰壺含寶月。',34,'全唐诗/poet.song.94000.json','["銀椀裏盛雪，冰壺含寶月。", "縱具四韋陀，到此虛搖舌。", "西天令嚴，此土還別。"]'),
('c0f91f2b-c3cd-4761-b798-04f8ac8dd51d','頌古四十四首  其四三','釋法泰','宋','宋诗','song-poetry','','[]','雞寒上樹，鴨寒下水。',38,'全唐诗/poet.song.94000.json','["雞寒上樹，鴨寒下水。", "三百餘會不能宣，九年面壁徒瞌睡。", "休瞌睡，上是天兮下是地。"]'),
('abc271a6-272c-4ca0-ac92-b5b57545feff','頌古四十四首  其四四','釋法泰','宋','宋诗','song-poetry','','[]','西天人不會唐言，端坐巍巍少室前。',32,'全唐诗/poet.song.94000.json','["西天人不會唐言，端坐巍巍少室前。", "剛被流支打齒缺，至令有理不能宣。"]'),
('4e5573c3-4f4d-412c-bcb3-ec6d5b7b681e','偈','釋子文','宋','宋诗','song-poetry','','[]','不昧不落作麽會，會得依前墮野狐。',32,'全唐诗/poet.song.94000.json','["不昧不落作麽會，會得依前墮野狐。", "一夜涼風生畫角，滿船明月泛江湖。"]'),
('de5a3e8c-9189-4974-9c97-be0da326a4cb','偈','釋建','宋','宋诗','song-poetry','','[]','兔馬有角，牛羊無角。',52,'全唐诗/poet.song.94000.json','["兔馬有角，牛羊無角。", "絕毫絕釐，如山如嶽。", "針鋒上師子翻身，藕竅中大鵬展翼。", "等閑突過北俱盧，日月星辰一時黑。"]'),
('62aa90fd-3ebb-486d-b2b5-1b6e5e757e8b','偈二首  其一','釋安民','宋','宋诗','song-poetry','','[]','衆賣華兮獨賣松，青春顔色不如紅。',32,'全唐诗/poet.song.94000.json','["衆賣華兮獨賣松，青春顔色不如紅。", "算來終不與時合，歸去來兮翠靄中。"]'),
('951a8544-89d7-4394-9ce4-459804c32945','偈二首  其二','釋安民','宋','宋诗','song-poetry','','[]','三面狸奴手捉月，兩頭白牯腳拏煙。',32,'全唐诗/poet.song.94000.json','["三面狸奴手捉月，兩頭白牯腳拏煙。", "戴冠碧兔立庭柏，脫殻烏龜飛上天。"]'),
('5c0e5390-10d4-4d20-a243-d74e3749e862','偈','釋元凈','宋','宋诗','song-poetry','','[]','要行便行，要坐便坐。',36,'全唐诗/poet.song.94000.json','["要行便行，要坐便坐。", "六處神通，是個什麽。", "把定時一物不爲，放行時殺人放火。"]'),
('ba44d1cd-dc7a-4891-a9ae-116cbfc2ceac','四牛圖頌  其一','釋元凈','宋','宋诗','song-poetry','','[]','混沌不分處，三緣未合時。',48,'全唐诗/poet.song.94000.json','["混沌不分處，三緣未合時。", "神通難可測，佛眼莫能窺。", "坦蕩全軀白，安眠露地肥。", "爲躭春色好，又被業風吹。"]'),
('8efed37c-de8f-4edc-a0e6-b612856865d1','四牛圖頌  其二','釋元凈','宋','宋诗','song-poetry','','[]','改換毛衣了，從茲不自由。',48,'全唐诗/poet.song.94000.json','["改換毛衣了，從茲不自由。", "只知今日事，忘卻舊時牛。", "步步雖同轍，昂昂不轉頭。", "四山成隔闊，相逐沒時休。"]'),
('c3894db7-9a07-48bb-a5ea-8b5e5f4d6c1c','四牛圖頌  其三','釋元凈','宋','宋诗','song-poetry','','[]','瞥爾家欄裏，回頭識得伊。',48,'全唐诗/poet.song.94000.json','["瞥爾家欄裏，回頭識得伊。", "不須常管带，取次倒橫騎。", "似客歸家日，如兒得母時。", "平田荒草裏，吹唱哩囉哩。"]'),
('d949f51e-d60b-4d72-a911-650740fda42f','四牛圖頌  其四','釋元凈','宋','宋诗','song-poetry','','[]','脫下娘生袴，還歸不動尊。',48,'全唐诗/poet.song.94000.json','["脫下娘生袴，還歸不動尊。", "萬緣具頓罷，一路涅槃門。", "大海波瀾息，青天絕點雲。", "披毛同異類，無剎不分身。"]'),
('a364f351-ed90-45e3-95fa-8e3935db3675','偈','釋梵思','宋','宋诗','song-poetry','','[]','趯翻生死海，踏倒涅槃岸。',24,'全唐诗/poet.song.94000.json','["趯翻生死海，踏倒涅槃岸。", "世上無活人，黄泉無死漢。"]'),
('aeae8004-df4a-4c87-90c0-686a85dedc4f','頌古九首  其一','釋梵思','宋','宋诗','song-poetry','','[]','春有百花秋有月，夏有涼風冬有雪。',32,'全唐诗/poet.song.94000.json','["春有百花秋有月，夏有涼風冬有雪。", "若無閑事在心頭，便是人間好時節。"]'),
('f122afa4-7fe4-4736-83d6-988b9fa486be','頌古九首  其二','釋梵思','宋','宋诗','song-poetry','','[]','喚應尋常誰不曉，及乎按劍總茫然。',32,'全唐诗/poet.song.94000.json','["喚應尋常誰不曉，及乎按劍總茫然。", "分明好個神仙訣，父子從來不許傳。"]'),
('cab9b156-b7d1-4bfe-8031-0449dd2c4fad','頌古九首  其三','釋梵思','宋','宋诗','song-poetry','','[]','一喝非唯三日聾，龍威虎勢也潛蹤。',32,'全唐诗/poet.song.94000.json','["一喝非唯三日聾，龍威虎勢也潛蹤。", "從前汗馬無人識，只要重論蓋代功。"]'),
('b463a03f-3af3-4963-93bd-3c1ca052aa4f','頌古九首  其四','釋梵思','宋','宋诗','song-poetry','','[]','黄鶴樓前鸚鵡洲，夕陽西去水東流。',32,'全唐诗/poet.song.94000.json','["黄鶴樓前鸚鵡洲，夕陽西去水東流。", "要知諸佛居何處，風葉蕭蕭月滿樓。"]'),
('fc14698c-33e3-4230-b1c4-f866ff1fbf9f','頌古九首  其五','釋梵思','宋','宋诗','song-poetry','','[]','摘楊花，摘楊花，打鼓弄琵琶。',26,'全唐诗/poet.song.94000.json','["摘楊花，摘楊花，打鼓弄琵琶。", "昨日栽茄子，今日種冬瓜。"]'),
('7a7ad1c2-7394-4562-80f9-a5bf4226da90','頌古九首  其六','釋梵思','宋','宋诗','song-poetry','','[]','婆子幾年尋劍客，趙州勘破有誵訛。',32,'全唐诗/poet.song.94000.json','["婆子幾年尋劍客，趙州勘破有誵訛。", "解使不由來富貴，風流何在著衣多。"]'),
('33e64708-705c-4791-8002-c766e8557ed4','頌古九首  其七','釋梵思','宋','宋诗','song-poetry','','[]','杈下要分生死路，霍山直拔透重關。',32,'全唐诗/poet.song.94000.json','["杈下要分生死路，霍山直拔透重關。", "雖然賺我三千里，瞎卻衆生眼萬千。"]'),
('bcfbdf87-da43-45d3-8908-bc2c687cd958','頌古九首  其八','釋梵思','宋','宋诗','song-poetry','','["\u6625\u5929"]','春雪滿空來，觸處是花開。',24,'全唐诗/poet.song.94000.json','["春雪滿空來，觸處是花開。", "不知園裏樹，那箇是真梅。"]'),
('083fa374-6931-463e-a5a7-3f39895c3fdc','頌古九首  其九','釋梵思','宋','宋诗','song-poetry','','[]','臘月二十五，雲門一曲新。',24,'全唐诗/poet.song.94000.json','["臘月二十五，雲門一曲新。", "一回聞舉著，笑殺洛陽人。"]'),
('bce6a9ec-911d-4bcd-8b06-586ef03a7109','偈二首  其一','釋覺','宋','宋诗','song-poetry','','[]','是即徹底是，從來脫體先天地。',76,'全唐诗/poet.song.94000.json','["是即徹底是，從來脫體先天地。", "非即徹底非，萬別千差共一機。", "是也是不著，非也非不及，此時佛祖從何立。", "曉天霜重泄真機，一顆圓明色非色。", "妙體全標處，分明只自知。"]'),
('b8242b28-4b74-4eb3-a748-d68c358b0043','偈二首  其二','釋覺','宋','宋诗','song-poetry','','[]','仰之彌高，不隔絲毫。',80,'全唐诗/poet.song.94000.json','["仰之彌高，不隔絲毫。", "要津把斷，佛祖難逃。", "鑽之彌堅，真體自然。", "鳥啼華笑，在碧巖前。", "瞻之在前，非正非偏。", "十方坐斷，威鎮大千。", "忽焉在後，一場漏逗。", "堪笑雲門，藏身北斗。"]'),
('5657339b-be6a-4201-8c0e-80587e796784','偈二首  其一','釋顯','宋','宋诗','song-poetry','','[]','喫粥了也，頭上安頭。',30,'全唐诗/poet.song.94000.json','["喫粥了也，頭上安頭。", "洗鉢盂去，爲蛇畫足。", "更問如何，自納敗闕。"]'),
('f19a28bb-8426-4f5a-a607-2f9b6bf0f512','偈二首  其二','釋顯','宋','宋诗','song-poetry','','[]','禪莫參，道休學，歇意忘機常廓落。',48,'全唐诗/poet.song.94000.json','["禪莫參，道休學，歇意忘機常廓落。", "現成公案早周遮，只箇無心已穿鑿。", "直饒坐斷未生前，難透山僧錯錯錯。"]'),
('e4ced668-2ffe-4dcc-a943-07507bb042d9','酬人偈','釋宗振','宋','宋诗','song-poetry','','[]','我有一機，直下示伊。',40,'全唐诗/poet.song.94000.json','["我有一機，直下示伊。", "青天霹靂，電卷星馳。", "德山臨濟，棒喝徒施。", "不傳之妙，於汝何虧。"]'),
('d3198892-decb-4291-83dc-d4ec240ee6fa','書壁','釋宗振','宋','宋诗','song-poetry','','[]','住在千峰最上層，年將耳順任騰騰。',32,'全唐诗/poet.song.94000.json','["住在千峰最上層，年將耳順任騰騰。", "免教名字掛人齒，甘作今朝百拙僧。"]'),
('908276ed-b7af-4224-8b87-22558cfc7fc5','答圓悟偈','學菴道人','宋','宋诗','song-poetry','','[]','露柱抽橫骨，虛空弄爪牙。',24,'全唐诗/poet.song.94000.json','["露柱抽橫骨，虛空弄爪牙。", "直饒玄會得，猶是眼中沙。"]'),
('c7b25a84-a03d-47ef-b4f0-d6ad2d7c2061','偈三首  其一','釋卿','宋','宋诗','song-poetry','','[]','杜鵑聲裏春光暮，滿地落花留不住。',44,'全唐诗/poet.song.94000.json','["杜鵑聲裏春光暮，滿地落花留不住。", "瑠璃殿上絕行蹤，誰人解插無根樹。", "只應連夜雨，又過一年春。"]'),
('e1bff709-a01a-4442-b517-23c36d5aba43','偈三首  其二','釋卿','宋','宋诗','song-poetry','','[]','蓬萊突兀無遮護，鐵壁銀山無入處。',100,'全唐诗/poet.song.94000.json','["蓬萊突兀無遮護，鐵壁銀山無入處。", "有時關棙一時開，放出毒蛇當大路。", "參禪人，早回顧，莫待臨時生怕怖。", "荆棘林中暗坐時，百尺竿頭須進步。", "三十三人老古錐，象轉龍蟠曾指注。", "休指注，成露布。", "蚊子上鐵牛，無你下嘴處。"]'),
('cf710ff4-14ac-4ca9-8630-85df49eb50b6','偈三首  其三','釋卿','宋','宋诗','song-poetry','','[]','一不是，二不成，落華流水裏啼鶯。',32,'全唐诗/poet.song.94000.json','["一不是，二不成，落華流水裏啼鶯。", "閑亭雨歇夜將半，片月還從海底生。"]'),
('5d866d84-b9fd-4b23-a595-f1cdb093aff6','偈二首  其一','釋擇明','宋','宋诗','song-poetry','','[]','趙老雲收山嶽露，茱萸雨過竹風清。',32,'全唐诗/poet.song.94000.json','["趙老雲收山嶽露，茱萸雨過竹風清。", "誰家別館池塘裏，一對鴛鴦畫不成。"]'),
('949a1c0a-f8ee-4c08-a763-27e8fa447ca9','偈二首  其二','釋擇明','宋','宋诗','song-poetry','','[]','從來家富小兒嬌，偏向江頭弄畫橈。',32,'全唐诗/poet.song.94000.json','["從來家富小兒嬌，偏向江頭弄畫橈。", "引得老爺把不住，又來船上助歌謠。"]'),
('f1d4307a-077b-442e-9ec1-8e80394d283d','偈二首  其一','釋本','宋','宋诗','song-poetry','','[]','清明已過十餘日，華雨闌珊方寸深。',32,'全唐诗/poet.song.94000.json','["清明已過十餘日，華雨闌珊方寸深。", "春色惱人眠不得，黄鸝飛過綠楊陰。"]'),
('7a569a41-b5e2-471f-aa22-08e2cf676228','偈二首  其二','釋本','宋','宋诗','song-poetry','','[]','鮑老當年笑郭郎，郭郎舞袖太郎當。',32,'全唐诗/poet.song.94000.json','["鮑老當年笑郭郎，郭郎舞袖太郎當。", "及乎鮑老當場舞，鮑老郎當勝郭郎。"]'),
('1f8226c4-ca2f-43e3-8575-1eae23f1c9c1','悟佛鑑問領旨述偈','釋清海','宋','宋诗','song-poetry','','[]','實際從來不受塵，箇中無舊亦無新。',32,'全唐诗/poet.song.94000.json','["實際從來不受塵，箇中無舊亦無新。", "青山況是吾家物，不用尋家別問津。"]'),
('8e6cfca2-6ad3-4c9e-a844-f247b5f138ae','偈','釋了璨','宋','宋诗','song-poetry','','[]','重陽九是菊華新，一句明明亘古今。',32,'全唐诗/poet.song.94000.json','["重陽九是菊華新，一句明明亘古今。", "楊廣橐駝無覓處，夜來足跡在松陰。"]'),
('4f7f13e3-9459-46b9-a4c0-c71953c16f92','偈八首  其一','釋明辯','宋','宋诗','song-poetry','','[]','猛虎口邊拾得，毒虵頭上安排。',44,'全唐诗/poet.song.94000.json','["猛虎口邊拾得，毒虵頭上安排。", "更不釘摏搖櫓，回頭別有生涯。", "婆子被我勘破了，大悲院裏有村齋。"]'),
('94f7e35d-31d1-4500-b2ca-be0cc5f3b3fd','偈八首  其二','釋明辯','宋','宋诗','song-poetry','','[]','諍五眼，湧金春色晚。',28,'全唐诗/poet.song.94000.json','["諍五眼，湧金春色晚。", "得五力，吹落碧桃華。", "唯證乃知難可測。"]'),
('83dc0f51-f08d-4f77-8f7d-1a23339d0b55','偈八首  其三','釋明辯','宋','宋诗','song-poetry','','[]','十五日已前不得去，少林雙履無藏處。',34,'全唐诗/poet.song.94000.json','["十五日已前不得去，少林雙履無藏處。", "十五日已後不得住，桂子天香和雨露。"]'),
('0b24c1b8-187a-4001-a7d1-a14c5b1d01bc','偈八首  其四','釋明辯','宋','宋诗','song-poetry','','[]','黄龍頭角從來異，不與今時歲月爭。',32,'全唐诗/poet.song.94000.json','["黄龍頭角從來異，不與今時歲月爭。", "復妙回途何處去，月明終夜照虛堂。"]'),
('8ae512cf-5182-4fa3-82ff-1bc9a57b2628','偈八首  其五','釋明辯','宋','宋诗','song-poetry','','[]','我疑千年蒼玉精，化爲一片秋水骨。',32,'全唐诗/poet.song.94000.json','["我疑千年蒼玉精，化爲一片秋水骨。", "海神欲護護不得，一旦鰲頭忽擎出。"]'),
('f61aa180-2c2b-4ee4-8e4b-23522710de2e','偈八首  其六','釋明辯','宋','宋诗','song-poetry','','[]','吹盡風流大石調，唱出富貴黄鍾宮。',32,'全唐诗/poet.song.94000.json','["吹盡風流大石調，唱出富貴黄鍾宮。", "舞腰催拍月當曉，更進蒲萄酒一鍾。"]'),
('a5ec23c1-7b27-46df-afab-b4229b56db41','偈八首  其七','釋明辯','宋','宋诗','song-poetry','','[]','狗子佛性有，毗盧愛飲彌勒酒。',44,'全唐诗/poet.song.94000.json','["狗子佛性有，毗盧愛飲彌勒酒。", "狗子佛性無，文殊醉倒普賢扶。", "扶到家中全酩酊，胡言漢語罵妻孥。"]'),
('ef869fcb-d81c-411a-a765-b6fd5cc5e75a','偈八首  其八','釋明辯','宋','宋诗','song-poetry','','[]','龍門和尚，闡提潦倒。',36,'全唐诗/poet.song.94000.json','["龍門和尚，闡提潦倒。", "不信佛法，滅除禪道。", "拶破毗盧向上關，貓兒洗面自道好。"]'),
('24b2aebf-24a0-4917-a454-077c9ccad141','頌古十六首  其一','釋明辯','宋','宋诗','song-poetry','','[]','黄金鑿，白玉椎。',20,'全唐诗/poet.song.94000.json','["黄金鑿，白玉椎。", "開開混沌竅，透出玄元機。"]'),
('87247c2b-1abb-4148-bcd7-1f4576d0a316','頌古十六首  其二','釋明辯','宋','宋诗','song-poetry','','[]','社舞村歌笑殺人，騎牛挑鴨走成群。',32,'全唐诗/poet.song.94000.json','["社舞村歌笑殺人，騎牛挑鴨走成群。", "三盃酒罷歸家去，留得豬頭礙塞人。"]'),
('9c63ad5c-6a01-47f6-9777-21659f6f29d9','頌古十六首  其三','釋明辯','宋','宋诗','song-poetry','','[]','要得他家活計強，竿頭須解倒拈槍。',32,'全唐诗/poet.song.94000.json','["要得他家活計強，竿頭須解倒拈槍。", "這邊打鼓那邊拍，引得瞿曇笑一場。"]'),
('760c7004-d291-4df6-b8ee-7ca42d4c1347','頌古十六首  其四','釋明辯','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','張果老踏破葫蘆，呂洞賓失卻寶劍。',46,'全唐诗/poet.song.94000.json','["張果老踏破葫蘆，呂洞賓失卻寶劍。", "兩箇撒手相逢，囊篋更無一綫。", "何仙姑鐵笛橫吹，解道長江靜如練。"]'),
('1e8b4f88-6dfc-4729-b329-d531a48bd654','頌古十六首  其五','釋明辯','宋','宋诗','song-poetry','','[]','弓強難結鴛鴦紐，御道那栽栗棘蓬。',32,'全唐诗/poet.song.94000.json','["弓強難結鴛鴦紐，御道那栽栗棘蓬。", "堪笑香嚴饒舌老，今年猶勝去年窮。"]'),
('c8398c2f-0872-451a-b677-6c86adbf7d0c','頌古十六首  其六','釋明辯','宋','宋诗','song-poetry','','[]','不向東山久，薔薇幾度華。',24,'全唐诗/poet.song.94000.json','["不向東山久，薔薇幾度華。", "白雲他自散，明月落誰家。"]'),
('ce318ff1-e480-4abe-b48d-333ebd160a51','頌古十六首  其七','釋明辯','宋','宋诗','song-poetry','','[]','行主無人能賽，姐姐更是好手。',28,'全唐诗/poet.song.94000.json','["行主無人能賽，姐姐更是好手。", "騰身百尺竿頭，打箇背翻筋斗。"]'),
('f33fcf63-fadf-4da0-9f54-20a8f712061d','頌古十六首  其八','釋明辯','宋','宋诗','song-poetry','','[]','老鼠齩生鐵，十分滋味別。',24,'全唐诗/poet.song.94000.json','["老鼠齩生鐵，十分滋味別。", "貓兒左右看，嚥唾也不徹。"]'),
('263e78d0-f61e-4376-8107-0a7c49e3fb20','頌古十六首  其九','釋明辯','宋','宋诗','song-poetry','','[]','百寶光攢無兒頂，是大神咒最靈奇。',32,'全唐诗/poet.song.94000.json','["百寶光攢無兒頂，是大神咒最靈奇。", "揭諦波羅僧揭諦，石人半夜失烏雞。"]'),
('6583e222-e0fe-4a79-8618-d8992142c5f9','頌古十六首  其一○','釋明辯','宋','宋诗','song-poetry','','[]','畫得真如活，華間試展開。',24,'全唐诗/poet.song.94000.json','["畫得真如活，華間試展開。", "黄鶯偷眼覷，不敢下枝來。"]'),
('71fc0ca5-8368-40f9-9e6d-cad062d35152','頌古十六首  其一一','釋明辯','宋','宋诗','song-poetry','','[]','我手何似佛手，黄龍鼻下無口。',28,'全唐诗/poet.song.94000.json','["我手何似佛手，黄龍鼻下無口。", "當時所見顢頇，至今百拙千醜。"]'),
('7772953f-ec45-439a-b8e7-adfb9c463c11','頌古十六首  其一二','釋明辯','宋','宋诗','song-poetry','','[]','我腳何似驢腳，文殊親見無著。',28,'全唐诗/poet.song.94000.json','["我腳何似驢腳，文殊親見無著。", "好箇玻璃盞子，不要當面諱卻。"]'),
('2575a762-6c18-428a-9f5a-14c0b0d8b645','頌古十六首  其一三','釋明辯','宋','宋诗','song-poetry','','[]','人人有箇生緣，從來罪大彌天。',28,'全唐诗/poet.song.94000.json','["人人有箇生緣，從來罪大彌天。", "不是牽犁拽把，便須鼎鑊油煎。"]'),
('2ec201d1-a4d9-433d-be31-faf1863d3a84','頌古十六首  其一四','釋明辯','宋','宋诗','song-poetry','','[]','春水滿幽澗，江風吹斷雲。',24,'全唐诗/poet.song.94000.json','["春水滿幽澗，江風吹斷雲。", "年年那時節，憶著別離人。"]'),
('9f7be36c-7587-4b5a-8778-062a353cf829','頌古十六首  其一五','釋明辯','宋','宋诗','song-poetry','','[]','住山身已老，世事任乖張。',24,'全唐诗/poet.song.94000.json','["住山身已老，世事任乖張。", "年來無侍者，客到自燒香。"]'),
('634a071a-ef3b-4ad5-ab8f-12f5cd82d0ba','頌古十六首  其一六','釋明辯','宋','宋诗','song-poetry','','[]','兩女合爲一媳婦，古寺基前幢子豎。',32,'全唐诗/poet.song.94000.json','["兩女合爲一媳婦，古寺基前幢子豎。", "彷彿上有陀羅尼，多少行人盡驚怖。"]'),
('2f86e560-35a9-47f6-8738-a216bb1558c9','送街坊','釋明辯','宋','宋诗','song-poetry','','[]','貞女不著娘家服，丈夫豈假分時財。',32,'全唐诗/poet.song.94000.json','["貞女不著娘家服，丈夫豈假分時財。", "十盃五盞從何有，空奮雙拳趁得來。"]'),
('13a47411-6a62-42dc-b7a9-cad65a9db334','送及禪人','釋明辯','宋','宋诗','song-poetry','','[]','馬面夜叉纔稽首，牛頭獄卒便擎拳。',32,'全唐诗/poet.song.94000.json','["馬面夜叉纔稽首，牛頭獄卒便擎拳。", "洞賓唱箇陶甄理，脫殻烏龜飛上天。"]'),
('8a443de8-e0d3-445f-9929-5c4c732638c8','自贊三首  其一','釋明辯','宋','宋诗','song-poetry','','[]','土豹長老，悟處敲誵。',38,'全唐诗/poet.song.94000.json','["土豹長老，悟處敲誵。", "滑頭勝似蓴菜，軟頑何啻黐膠。", "曾被三腳驢子，踏得鼻孔成四。"]'),
('6b917427-a8da-41df-9eca-8ee7d1a0000c','自贊三首  其二','釋明辯','宋','宋诗','song-poetry','','[]','瞎老婆半夜吹火，張聾子日午聞歌。',46,'全唐诗/poet.song.94000.json','["瞎老婆半夜吹火，張聾子日午聞歌。", "畫得這般毫相，出生入死降魔。", "有時鼓起龍門浪，娑竭龍王不奈何。"]');
